        this.map_var.put(AppMeasurementSdk.ConditionalUserProperty.NAME, "তবু, পারি নে সঁপিতে প্রাণ");
        this.map_var.put("content", "রাগ: পিলু\nতাল: একতাল\n\n\nতবু পারি নে সঁপিতে প্রাণ।\nপলে পলে মরি সেও ভালো, সহি পদে পদে অপমান।\nকথার বাঁধুনি, কাঁদুনির পালা- চোখে নাহি কারো নীর।\nআবেদন আর নিবেদনের থালা ব'হে ব'হে নত শির।\nকাঁদিয়ে সোহাগ, ছি ছি একি লাজ! জগতের মাঝে ভিখারির সাজ-\nআপনি করি নে আপনার কাজ, পরের ' পরে অভিমান।\nআপনি নামাও কলঙ্কপশরা, যেয়ো না পরের দ্বার-\nপরের পায়ে ধ'রে মান ভিক্ষা করা সকল ভিক্ষার ছার।\n'দাও দাও' ব'লে পরের পিছু পিছু কাঁদিয়া বেড়ালে মেলে না তো কিছু-\nমান পেতে চাও, প্রাণ পেতে চাও, প্রাণ আগে করো দান।");
