        this.String_7 = "রাগ: খাম্বাজ\nতাল: একতাল\n\n\nনাচ্\u200c শ্যামা, তালে তালে।\nরুনু রুনু ঝুনু বাজিছে নূপুর,\tমৃদু মৃদু মধু উঠে গীতসুর,\nবলয়ে বলয়ে বাজে ঝিনি ঝিনি,\tতালে তালে উঠে করতালিধ্বনি-\nনাচ্\u200c শ্যামা, নাচ্\u200c তবে।\nনিরালয় তোর বনের মাঝে\tসেথা কি এমন নূপুর বাজে!\nএমন মধুর গান? এমন মধুর তান?\nকমলকরের করতালি হেন\tদেখিতে পেতিস কবে? -\nনাচ্\u200c শ্যামা, নাচ্\u200c তবে।";
        this.String_8 = "রাগ: খট\nতাল: অজ্ঞাত\n\n\nবিপাশার তীরে ভ্রমিবারে যাই, প্রতিদিন প্রাতে দেখিবারে পাই\nলতা- পাতা- ঘেরা জানালা- মাঝারে একটি মধুর মুখ।\nচারি দিকে তার ফুটে আছে ফুল- কেহ বা হেলিয়া পরশিছে চুল,\nদুয়েকটি শাখা কপাল ছুঁইয়া, দুয়েকটি আছে কপোলে নুইয়া,\nকেহ বা এলায়ে চেতনা হারায়ে চুমিয়া আছে চিবুক।\nবসন্তপ্রভাতে লতার মাঝারে মুখানি মধুর অতি-\nঅধর- দুটির শাসন টুটিয়া রাশি রাশি হাসি পড়িছে ফুটিয়া,\nদুটি আঁখি-'পরে মেলিছে মিশিছে তরল চপল জ্যোতি।";
        this.String_9 = "রাগ: কালাংড়া\nতাল: অজ্ঞাত\n\n\nখেলা কর্ খেলা কর্ তোরা\tকামিনীকুসুমগুলি।\nদেখ্\u200c সমীরণ লতাকুঞ্জে গিয়া কুসুমগুলির চিবুক ধরিয়া\nফিরায়ে এ ধার, ফিরায়ে ও ধার, দুইটি কপোল চুমে বারবার\nমুখানি উঠায়ে তুলি।\nতোরা খেলা কর্ তোরা খেলা কর্ কামিনীকুসুমগুলি।\nকভু পাতা- মাঝে লুকায়ে মুখ, কভু বায়ু- কাছে খুলে দে বুক,\nমাথা নাড়ি নাড়ি নাচ্\u200c কভু নাচ্\u200c বায়ু- কোলে দুলি দুলি।\nদু দণ্ড বাঁচিবি, খেলা তবে খেলা- প্রতি নিমিষেই ফুরাইছে বেলা,\nবসন্তের কোলে খেলাশ্রান্ত প্রাণ\tত্যজিবি ভাবনা ভুলি।";
        this.String_10 = "রাগ: গৌড়সারং\nতাল: ঝাঁপতাল\nস্বরলিপিকার: জ্যোতিরিন্দ্রনাথ ঠাকুর\n\n\nআঁধার শাখা উজল করি\tহরিত- পাতা- ঘোমটা পরি\nবিজন বনে, মালতীবালা, আছিস কেন ফুটিয়া।\nশোনাতে তোরে মনের ব্যথা শুনিতে তোর মনের কথা\nপাগল হয়ে মধুপ কভু আসে না হেথা ছুটিয়া।\nমলয় তব প্রণয়- আশে ভ্রমে না হেথা আকুল শ্বাসে,\nপায় না চাঁদ দেখিতে তোর শরমে- মাখা মুখানি।\nশিয়রে তোর বসিয়া থাকি মধুর স্বরে বনের পাখি\nলভিয়া তোর সুরভিশ্বাস যায় না তোরে বাখানি।";
        this.String_11 = "রাগ: বেহাগ- খাম্বাজ- বাউল\nতাল: একতাল\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nসখী,\tভাবনা কাহারে বলে। সখী,\tযাতনা কাহারে বলে।\nতোমরা যে বলো দিবস- রজনী\t'ভালোবাসা' 'ভালোবাসা'-\nসখী,\tভালোবাসা কারে কয়! সে কি কেবলই যাতনাময়।\nসে কি কেবলই চোখের জল? সে কি কেবলই দুখের শ্বাস?\nলোকে তবে করে কী সুখেরই তরে এমন দুখের আশ।\nআমার চোখে তো সকলই শোভন,\nসকলই নবীন, সকলই বিমল,\tসুনীল আকাশ, শ্যামল কানন,\nবিশদ জোছনা, কুসুম কোমল- সকলই আমার মতো।\nতারা কেবলই হাসে, কেবলই গায়, হাসিয়া খেলিয়া মরিতে চায়-\nনা জানে বেদন, না জানে রোদন, না জানে সাধের যাতনা যত।\nফুল সে হাসিতে হাসিতে ঝরে, জোছনা হাসিয়া মিলায়ে যায়,\nহাসিতে হাসিতে আলোকসাগরে আকাশের তারা তেয়াগে কায়।\nআমার মতন সুখী কে আছে। আয় সখী, আয় আমার কাছে-\nসুখী হৃদয়ের সুখের গান শুনিয়া তোদের জুড়াবে প্রাণ।\nপ্রতিদিন যদি কাঁদিবি কেবল\tএকদিন নয় হাসিবি তোরা-\nএকদিন নয় বিষাদ ভুলিয়া\tসকলে মিলিয়া গাহিব মোরা।";
        this.String_12 = "রাগ: মিশ্র দেশ\nতাল: কাহারবা\n\n\nকাছে তার যাই যদি\tকত যেন পায় নিধি,\nতবু হরষের হাসি ফুটে- ফুটে ফুটে না।\nকখনো বা মৃদু হেসে\tআদর করিতে এসে\nসহসা শরমে বাধে, মন উঠে উঠে না।\nরোষের ছলনা করি\tদূরে যাই, চাই ফিরি-\nচরণ- বারণ- তরে উঠে- উঠে উঠে না।\nকাতর নিশ্বাস ফেলি\tআকুল নয়ন মেলি\nচাহি থাকে, লাজবাঁধ তবু টুটে টুটে না।\nযখন ঘুমায়ে থাকি\tমুখপানে মেলি আঁখি\nচাহি থাকে, দেখি দেখি সাধ যন মিটে না।\nসহসা উঠিলে জাগি\tতখন কিসের লাগি\nশরমেতে ম'রে গিয়ে কথা যেন ফুটে না।\nলাজময়ী, তোর চেয়ে\tদেখি নি লাজুক মেয়ে,\nপ্রেমবরিষার স্রোতে লাজ তবু টুটে না।";
        this.String_13 = "রাগ: মিশ্র সুর\nতাল: অজ্ঞাত\n\n\nযে ভালোবাসুক সে ভালোবাসুক\tসজনি লো, আমরা কে!\nদীনহীন এই হৃদয় মোদের\tকাছেও কি কেহ ডাকে।\nতবে কেন বলো ভেবে মরি মোরা কে কাহারে ভালোবাসে!\nআমাদের কিবা আসে যায় বলো\tকেবা কাঁদে কেবা হাসে!\nআমাদের মন কেহই চাহে না,\tতবে মনখানি লুকানো থাক্\u200c-\nপ্রাণের ভিতরে ঢাকিয়া রাখ্\u200c।\nযদি, সখী, কেহ ভুলে\tমনখানি লয় তুলে,\nউলটি- পালটি ক্ষণেক ধরিয়া\tপরখ করিয়া দেখিতে চায়,\nতখনি ধূলিতে ছুঁড়িয়া ফেলিবে\tনিদারুণ উপেখায়।\nকাজ কী লো, মন লুকানো থাক্\u200c, প্রাণের ভিতরে ঢাকিয়া রাখ্\u200c-\nহাসিয়া খেলিয়া ভাবনা ভুলিয়া হরষে প্রমোদে মাতিয়া থাক্\u200c।";
        this.String_14 = "রাগ: মূলতান\nতাল: অজ্ঞাত\n\n\nকে তুমি গো খুলিয়াছ স্বর্গের দুয়ার\nঢালিতেছ এত সুখ, ভেঙে গেল- গেল বুক-\nযেন এত সুখ হৃদে ধরে না গো আর।\nতোমার চরণে দিনু প্রেম- উপহার-\nনা যদি চাও গো দিতে প্রতিদান তার\nনাই বা দিলে তা মোরে, থাকো হৃদি আলো করে,\nহৃদয়ে থাকুক জেগে সৌন্দর্য তোমার।";
        this.String_15 = "রাগ: মিশ্র ঝিঁঝিট\nতাল: আড়াঠেকা\n\n\nকিছুই তো হল না।\nসেই সব- সেই সব- সেই হাহাকাররব,\nসেই অশ্রুবারিধারা, হৃদয়বেদনা।\nকিছুতে মনের মাঝে শান্তি নাহি পাই,\nকিছুই না পাইলাম যাহা কিছু চাই।\nভালো তো গো বাসিলাম, ভালোবাসা পাইলাম,\nএখনো তো ভালোবাসি- তবুও কী নাই।";
        this.String_16 = "রাগ: মিশ্র ইমনকল্যাণ\nতাল: অজ্ঞাত\n\n\nকী করিব বলো, সখা, তোমার লাগিয়া।\nকী করিলে জুড়াইতে পারিব ও হিয়া।\nএই পেতে দিনু বুক, রাখো, সখা, রাখো মুখ-\nঘুমাও তুমি গো, আমি রহিনু জাগিয়া।\nখুলে বলো, বলো সখা, কী দুঃখ তোমার-\nঅশ্রুজলে মিলাইব অশ্রুজলধার!\nএকদিন বলেছিলে মোর ভালোবাসা\nপাইলে পুরিবে তব হৃদয়ের আশা।\nকই সখা, প্রাণ মন করেছি তো সমর্পণ-\nদিয়েছি তো যাহা- কিছু আছিল আমার।\nতবু কেন শুকালো না অশ্রুজলধার।";
        this.String_17 = "রাগ: ইমনকল্যাণ\nতাল: অজ্ঞাত\n\n\nনা সখা, মনের ব্যথা কোরো না গোপন।\nযবে অশ্রুজল হায় উচ্ছ্বসি উঠিতে চায়\nরুধিয়া রেখো না তাহা আমারি কারণ।\nচিনি, সখা, চিনি তব ও দারুণ হাসি-\nওর চেয়ে কত ভালো অশ্রুজলরাশি।\nমাথা খাও- অভাগীরে কোরো না বঞ্চনা,\nছদ্মবেশে আবরিয়া রেখো না যন্ত্রণা।\nমমতার অশ্রুজলে\tনিভাইব সে অনলে,\nভালো যদি বাস তবে রাখো এ প্রার্থনা।";
        this.String_18 = "রাগ: মিশ্র পিলু\nতাল: দাদরা\n\n\nবুঝেছি বুঝেছি সখা, ভেঙেছে প্রণয়!\nও মিছে আদর তবে না করিলে নয়? ।\nও শুধু বাড়ায় ব্যথা-\tসে- সব পুরানো কথা\nমনে ক'রে দেয় শুধু, ভাঙে এ হৃদয়।\nপ্রতি হাসি প্রতি কথা প্রতি ব্যবহার\nআমি যত বুঝি তত কে বুঝিবে আর।\nপ্রেম যদি ভুলে থাক\tসত্য ক'রে বলো- নাকো-\nকরিব না মুহূর্তের তরে তিরস্কার।\nআমি তো ব'লেই ছিনু, ক্ষুদ্র আমি নারী\nতোমার ও প্রণয়ের নহি অধিকারী।\nআর- কারে ভালোবেসে\tসুখী যদি হও শেষে\nতাই ভালোবেসো নাথ, না করি বারণ।\nমনে ক'রে মোর কথা\tমিছে পেয়ো নাকো ব্যথা,\nপুরানো প্রেমের কথা কোরো না স্মরণ।";
        this.String_19 = "রাগ: কাফি\nতাল: ঝাঁপতাল\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nতুই রে বসন্তসমীরণ।\nতোর নহে সুখের জীবন।\nকিবা দিবা কিবা রাতি\tপরিমলমদে মাতি\nকাননে করিস বিচরণ।\nনদীরে জাগায়ে দিস\tলতারে রাগায়ে দিস\nচুপিচুপি করিয়া চুম্বন\nতোর নহে সুখের জীবন।\nশোন্\u200c বলি বসন্তের বায়,\nহৃদয়ের লতাকুঞ্জে আয়।\nনিভৃত নিকুঞ্জ ছায়\tহেলিয়া ফুলের গায়\nশুনিয়া পাখির মৃদু গান\nলতার- হৃদয়ে- হারা\tসুখে- অচেতন- পারা\nঘুমায়ে কাটায়ে দিবি প্রাণ।\nতাই বলি বসন্তের বায়,\nহৃদয়ের লতাকুঞ্জে আয়।";
        this.String_20 = "রাগ: মিশ্র সারং\nতাল: ঝাঁপতাল\n\n\nবসন্তপ্রভাতে এক মালতীর ফুল\nপ্রথম মেলিল আঁখি তার, চাহিয়া দেখিল চারি ধার।\nউষারানী দাঁড়াইয়া শিয়রে তাহার\nদেখিছে ফুলের ঘুম- ভাঙা। হরষে কপোল তার রাঙা।\nমধুকর গান গেয়ে বলে, 'মধু কই। মধু দাও দাও।'\nহরষে হৃদয় ফেটে গিয়ে ফুল বলে, 'এই লও লও।'\nবায়ু আসি কহে কানে কানে, 'ফুলবালা, পরিমল দাও।'\nআনন্দে কাঁদিয়া কহে ফুল, 'যাহা আছে সব লয়ে যাও।'\nহরষ ধরে না তার চিতে, আপনারে চাহে বিলাইতে,\nবালিকা আনন্দে কুটি- কুটি পাতায় পাতায় পড়ে লুটি।";
        this.String_21 = "রাগ: গৌড়সারং\nতাল: ঝাঁপতাল\n\n\nতরুতলে ছিন্নবৃন্ত মালতীর ফুল-\nমুদিয়া আসিছে আঁখি তার, চাহিয়া দেখিল চারি ধার।\nশুষ্ক তৃণরাশি- মাঝে একেলা পড়িয়া,\nচারি দিকে কেহ নাই আর- নিরদয় অসীম সংসার।\nকে আছে গো দিবে তার তৃষিত অধরে\nএকবিন্দু শিশিরের কণা- কেহ না, কেহ না।\nমধুকর কাছে এসে বলে, 'মধু কই। মধু চাই, চাই।'\nধীরে ধীরে নিশ্বাস ফেলিয়া ফুল বলে, 'কিছু নাই, নাই।'\n'ফুলবালা, পরিমল দাও' বায়ু আসি কহিতেছে কাছে।\nমলিন বদন ফিরাইয়া ফুল বলে, 'আর কী বা আছে।'\nমধ্যাহ্নকিরণ চারি দিকে খরদৃষ্টে চেয়ে অনিমিখে-\nফুলটির মৃদু প্রাণ হায়,\nধীরে ধীরে শুকাইয়া যায়।";
        this.String_22 = "রাগ: কেদারা\nতাল: একতাল\n\n\nযোগী হে, কে তুমি হৃদি- আসনে!\nবিভূতিভূষিত শুভ্র দেহ, নাচিছ দিক্\u200c- বসনে।\nমহা- আনন্দে পুলক কায়, গঙ্গা উথলি উছলি যায়,\nভালে শিশুশশী হাসিয়া চায়-\nজটাজূট ছায় গগনে।";
        this.String_23 = "রাগ: ছায়ানট\nতাল: অজ্ঞাত\n\n\nভিক্ষে দে গো, ভিক্ষে দে।\nদ্বারে দ্বারে বেড়াই ঘুরে, মুখ তুলে কেউ চাইলি নে।\nলক্ষ্মী তোদের সদয় হোন, ধনের উপর বাড়ুক ধন-\nআমি\tএকটি মুঠো অন্ন চাই গো, তাও কেন পাই নে।\nওই রে সূর্য উঠল মাথায়, যে যার ঘরে চলেছে।\nপিপাসাতে ফাটছে ছাতি, চলতে আর যে পারি নে।\nওরে তোদের অনেক আছে, আরো অনেক হবে-\nএকটি মুঠো দিবি শুধু আর কিছু চাহি নে।";
        this.String_24 = "রাগ: গৌড়সারং\nতাল: একতাল\n\n\nআয় রে আয় রে সাঁঝের বা, লতাটিরে দুলিয়ে যা-\nফুলের গন্ধ দেব তোরে আঁচলটি তোর ভ'রে ভ'রে।\nআয় রে আয় রে মধুকর, ডানা দিয়ে বাতাস কর্-\nভোরের বেলা গুন্\u200cগুনিয়ে ফুলের মধু যাবি নিয়ে।\nআয় রে চাঁদের আলো আয়, হাত বুলিয়ে দে রে গায়-\nপাতার কোলে মাথা থুয়ে ঘুমিয়ে পড়বি শুয়ে শুয়ে।\nপাখি রে, তুই কোস্\u200c নে কথা- ওই যে ঘুমিয়ে প'ল লতা।";
        this.String_25 = "রাগ: রামপ্রসাদী\nতাল: দাদরা\n\n\nপ্রিয়ে, তোমার ঢেঁকি হলে যেতেম বেঁচে\nরাঙা চরণতলে নেচে নেচে।\nঢিপ\u200d্\u200dঢিপিয়ে যেতেম মারা, মাথা খুঁড়ে হতেম সারা-\nকানের কাছে কচ্\u200cকচিয়ে মানটি তোমার নিতেম যেচে।";
        this.String_26 = "রাগ: ভৈরবী\nতাল: দাদরা\n\n\nকথা\tকোস্\u200c নে লো রাই, শ্যামের বড়াই বড়ো বেড়েছে।\nকে জানে ও কেমন ক'রে মন কেড়েছে।\nশুধু ধীরে বাজায় বাঁশি, শুধু হাসে মধুর হাসি-\nগোপিনীদের হৃদয় নিয়ে তবে ছেড়েছে।";
        this.String_27 = "রাগ: মিশ্র খাম্বাজ\nতাল: একতাল\n\n\nওই জানালার কাছে বসে আছে করতলে রাখি মাথা-\nতার কোলে ফুল পড়ে রয়েছে, সে যে\tভুলে গেছে মালা গাঁথা।\nশুধু ঝুরু ঝুরু বায়ু বহে যায় তার কানে কানে কী যে কহে যায়-\nতাই আধো শুয়ে আধো বসিয়ে ভাবিতেছে কত কথা।\nচোখের উপরে মেঘ ভেসে যায়, উড়ে উড়ে যায় পাখি-\nসারা দিন ধ'রে বকুলের ফুল ঝ'রে পড়ে থাকি থাকি।\nমধুর আলস, মধুর আবেশ, মধুর মুখের হাসিটি-\nমধুর স্বপনে প্রাণের মাঝারে বাজিছে মধুর বাঁশিটি।";
        this.String_28 = "রাগ: ঝিঁঝিট\nতাল: দাদরা\n\n\nসাধ ক'রে কেন, সখা, ঘটাবে গেরো।\nএই বেলা মানে- মানে ফেরো ফেরো।\nপলক যে নাই আঁখির পাতায়,\nতোমার\tমনটা কি খরচের খাতায়-\nহাসি ফাঁসি দিয়ে প্রাণে বেঁধেছে গেরো।\nসখা, ফেরো ফেরো।";
        this.String_29 = "রাগ: বেহাগ- খাম্বাজ\nতাল: ঝাঁপতাল\n\n\nধীরে ধীরে প্রাণে আমার এসো হে,\nমধুর হাসিয়ে ভালোবেসো হে।\nহৃদয়কাননে\tফুল ফুটাও।\tআধো নয়নে, সখী, চাও চাও-\nপরান কাঁদিয়ে দিয়ে হাসিখানি হেসো হে।";
        this.String_30 = "রাগ: কাফি- সিন্ধু\nতাল: দাদরা\n\n\nতুমি\tআছ কোন্\u200c পাড়া? তোমার পাই নে যে সাড়া।\nপথের মধ্যে হাঁ ক'রে যে রইলে হে খাড়া।\nরোদে প্রাণ যায় দুপুর বেলা, ধরেছে উদরে জ্বালা-\nএর কাছে কি হৃদয়জ্বালা।\nতোমার সকল সৃষ্টিছাড়া।\nরাঙা অধর, নয়ন কালো ভরা পেটেই লাগে ভালো-\nএখন\tপেটের মধ্যে নাড়ীগুলো দিয়েছে তাড়া।";
        this.String_31 = "রাগ: সিন্ধু- খাম্বাজ\nতাল: খেমটা\n\n\nদেখো ওই কে এসেছে। - চাও সখী, চাও।\nআকুল পরান ওর আঁখিহিল্লোলে নাচাও। - সখী, চাও।\nতৃষিত নয়ানে চাহে মুখ- পানে,\nহাসিসুধা- দানে বাঁচাও। - সখী, চাও।";
        this.String_32 = "রাগ: মিশ্র পিলু\nতাল: ঝাঁপতাল\n\n\nভালো যদি বাস, সখী, কী দিব গো আর-\nকবির হৃদয় এই দিব উপহার।\nএত ভালোবাসা, সখী, কোন্\u200c হৃদে বলো দেখি-\nকোন্\u200c হৃদে ফুটে এত ভাবের কুসুমভার।\nতা হলে এ হৃদিধামে তোমারি তোমারি নামে\nবাজিবে মধুর স্বরে মরমবীণার তার।\nযা- কিছু গাহিব গান ধ্বনিবে তোমারি নাম-\nকী আছে কবির বলো, কী তোমারে দিব আর।";
        this.String_33 = "রাগ: পিলু\nতাল: খেমটা\n\n\nও কেন\tভালোবাসা জানাতে আসে ওলো সজনী।\nহাসি খেলি রে মনের সুখে,\nও কেন সাথে ফেরে আঁধার- মুখে\nদিনরজনী।";
        this.String_34 = "রাগ: কালাংড়া\nতাল: একতাল\n\n\nভালোবাসিলে যদি সে ভালো না বাসে কেন সে দেখা দিল।\nমধু অধরের মধুর হাসি প্রাণে কেন বরষিল।\nদাঁড়িয়ে ছিলেম পথের ধারে, সহসা দেখিলেম তারে-\nনয়ন দুটি তুলে কেন\tমুখের পানে চেয়ে গেল।";
        this.String_35 = "রাগ: পিলু\nতাল: ত্রিতাল\n\n\nহা, কে বলে দেবে সে ভালোবাসে কি মোরে।\nকভু বা সে হেসে চায়,\tকভু মুখ ফিরায়ে লয়,\nকভু বা সে লাজে সারা, কভু বা বিষাদময়ী-\nযাব কি কাছে তার। শুধাব চরণ ধ'রে? ।";
        this.String_36 = "রাগ: ভৈরবী\nতাল: খেমটা\n\n\nকেন রে চাস ফিরে ফিরে,\tচলে আয় রে চলে আয়।\nএরা\tপ্রাণের কথা বোঝে না যে,\tহৃদয়কুসুম দলে যায়।\nহেসে হেসে গেয়ে গান\tদিতে এসেছিলি প্রাণ,\nনয়নের জল সাথে নিয়ে\tচলে আয় রে চলে আয়।";
        this.String_37 = "রাগ: বেহাগ- খাম্বাজ\nতাল: ত্রিতাল\n\n\nপ্রমোদে ঢালিয়া দিনু মন, তবু প্রাণ কেন কাঁদে রে।\nচারি দিকে হাসিরাশি, তবু\tপ্রাণ কেন কাঁদে রে।\nআন্\u200c সখী, বীণা আন্\u200c, প্রাণ খুলে কর্ গান,\nনাচ্\u200c\tসবে মিলে ঘিরি ঘিরি ঘিরিয়ে-\nতবু প্রাণ কেন কাঁদে রে।\nবীণা তবে রেখে দে, গান আর গাস নে-\nকেমনে যাবে বেদনা।\nকাননে কাটাই রাতি,\tতুলি ফুল মালা গাঁথি,\nজোছনা কেমন ফুটেছে-\nতবু প্রাণ কেন কাঁদে রে।";
        this.String_38 = "রাগ: গৌড়সারং\nতাল: দাদরা\n\n\nসখা, সাধিতে সাধাতে কত সুখ\nতাহা বুঝিলে না তুমি- মনে রয়ে গেল দুখ।\nঅভিমান- আঁখিজল,\tনয়ন ছলছল-\nমুছাতে লাগে ভালো কত\nতাহা বুঝিলে না তুমি- মনে রয়ে গেল দুখ।";
        this.String_39 = "রাগ: মিশ্র কালাংড়া\nতাল: দাদরা\n\n\nএত ফুল কে ফোটালে\tকাননে!\nলতাপাতায় এত হাসি- তরঙ্গ মরি কে ওঠালে।\nসজনীর বিয়ে হবে ফুলেরা শুনেছে সবে-\nসে কথা কে রটালে।";
        this.String_40 = "রাগ: দেশ\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nআমাদের সখীরে কে নিয়ে যাবে রে-\nতারে কেড়ে নেব, ছেড়ে দেব না- না- না।\nকে জানে কোথা হতে কে এসেছে।\nকেন সে মোদের সখী নিতে আসে- দেব' না।\nসখীরা পথে গিয়ে দাঁড়াব, হাতে তার ফুলের বাঁধন জড়াব,\nবেঁধে তায় রেখে দেব' কুসুমবনে- সখীরে নিয়ে যেতে দেব' না।";
        this.String_41 = "রাগ: মিশ্র ভৈরবী\nতাল: ত্রিতাল\n\n\nকোথা ছিলি সজনী লো,\nমোরা যে তোরি তরে বসে আছি কাননে।\nএসো সখী, এসো হেথা বসি বিজনে\nআঁখি ভরিয়ে হেরি হাসিমুখানি।\nসাজাব সখীরে সাধ মিটায়ে,\nঢাকিব তনুখানি কুসুমেরই ভূষণে।\nগগনে হাসিবে বিধু, গাহিব মৃদু মৃদু-\nকাটাব প্রমোদে চাঁদিনী যামিনী।";
        this.String_42 = "রাগ: গৌড়মল্লার\nতাল: কাহারবা\nস্বরলিপিকার: জ্যোতিরিন্দ্রনাথ ঠাকুর, ইন্দিরা দেবী\n\n\nও কী কথা বল সখী, ছি ছি, ও কথা মনে এনো না।\nআজি সুখের দিনে জগত হাসিছে,\nহেরো লো দশ দিশি হরষে ভাসিছে-\nআজি ও ম্লান মুখ প্রাণে যে সহে না।\nসুখের দিনে, সখী, কেন ও ভাবনা।";
        this.String_43 = "রাগ: মিশ্র বেহাগ\nতাল: কাহারবা- দাদরা\n\n\nমধুর মিলন।\nহাসিতে মিলেছে হাসি, নয়নে নয়ন।\nমরমর মৃদু বাণী মরমর মরমে,\nকপোলে মিলায় হাসি সুমধুর শরমে- নয়নে স্বপন।\nতারাগুলি চেয়ে আছে, কুসুম গাছে গাছে-\nবাতাস চুপিচুপি ফিরিছে কাছে কাছে।\nমালাগুলি গেঁথে নিয়ে, আড়ালে লুকাইয়ে\nসখীরা নেহারিছে দোঁহার আনন-\nহেসে আকুল হল বকুলকানন, আ মরি মরি।";
        this.String_44 = "রাগ: ভৈরবী\nতাল: মধ্যমান\n\n\nমা, একবার দাঁড়া গো হেরি চদ্রানন।\nআঁধার ক'রে কোথায় যাবি শূন্যভবন।\nমধুর মুখ হাসি- হাসি অমিয়া রাশি- রাশি, মা-\nও হাসি কোথায় নিয়ে যাস রে।\nআমরা\tকী নিয়ে জুড়াব জীবন।";
        this.String_45 = "রাগ: মিশ্র ভূপালী\nতাল: ত্রিতাল\n\n\nমা আমার, কেন তোরে ম্লান নেহারি-\nআঁখি ছলছল, আহা।\nফুলবনে সখী- সনে খেলিতে খেলিতে হাসি হাসি দে রে করতারি।\nআয় রে বাছা, আয় রে কাছে আয়।\nদু দিন রহিবি, দিন ফুরায়ে যায়-\nকেমনে বিদায় দেব' হাসিমুখ না হেরি।";
        this.String_46 = "রাগ: খাম্বাজ\nতাল: ঝাঁপতাল\n\n\nওই আঁখি রে!\nফিরে ফিরে চেয়ো না, চেয়ো না, ফিরে যাও-\nকী আর রেখেছ বাকী রে।\nমরমে কেটেছ সিঁধ, নয়নের কেড়েছ নিদ-\nকী সুখে পরান আর রাখি রে।";
        this.String_47 = "রাগ: সিন্ধু- খাম্বাজ\nতাল: খেমটা\n\n\nআজ আসবে শ্যাম গোকুলে ফিরে।\nআবার বাজবে বাঁশি যমুনাতীরে\nআমরা কী করব। কী বেশ ধরব।\nকী মালা পড়ব। বাঁচব কি মরব সুখে।\nকী তারে বলব!\tকথা কি রবে মুখে।\nশুধু তার মুখপানে চেয়ে চেয়ে\nদাঁড়ায়ে ভাসব নয়ননীরে।";
        this.String_48 = "রাগ: খাম্বাজ\nতাল: ঝাঁপতাল\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nরাজ- অধিরাজ, তব ভালে জয়মালা-\nত্রিপুরপুরলক্ষ্মী বহে তব বরণডালা।\nক্ষীণজনভয়তরণ তব অভয় বাণী,\tদীনজনদুখহরণনিপুণ, তব পাণি,\nতরুণ তব মুখচন্দ্র করুণরস- ঢালা।\nগুণিরসিকসেবিত উদার তব দ্বারে\tমঙ্গল বিরাজিত বিচিত্র উপচারে-\nগুণ- অরুণ- কিরণে তব সব ভুবন আলা।";
        this.String_49 = "রাগ: বিভাস\nতাল: দাদরা\n\n\nঝর ঝর রক্ত ঝরে কাটা মুণ্ড বেয়ে।\nধরণী রাঙা হল রক্তে নেয়ে।\nডাকিনী নৃত্য করে প্রসাদ- রক্ত- তরে-\nতৃষিত\tভক্ত তোমার আছে চেয়ে।";
        this.String_50 = "রাগ: ভৈরব\nতাল: দাদরা\n\n\nউলঙ্গিনী নাচে রণরঙ্গে। আমরা নৃত্য করি সঙ্গে।\nদশ দিক আঁধার ক'রে মাতিল দিক্\u200c- বসনা,\nজ্বলে বহ্নিশিখা রাঙা রসনা-\nদেখে মরিবারে ধাইছে পতঙ্গে।\nকালো কেশ উড়িল আকাশে,\nরবি সোম লুকালো তরাসে।\nরাঙা রক্তধারা ঝরে কালো অঙ্গে-\nত্রিভুবন কাঁপে ভুরুভঙ্গে।";
        this.String_51 = "রাগ: ভৈরবী\nতাল: দাদরা\n\n\nথাকতে আর তো পারলি নে মা, পারলি কই।\nকোলের সন্তানেরে ছাড়লি কই।\nদোষী আছি অনেক দোষে, ছিলি বসে ক্ষণিক রোষে-\nমুখ তো ফিরালি শেষে। অভয় চরণ কাড়লি কই।";
        this.String_52 = "রাগ: কীর্তন\nতাল: তেওরা\nরচনাস্থান: শাহজাদপুর\nস্বরলিপিকার: সরলা দেবী\n\n\nখাঁচার পাখি ছিল\tসোনার খাঁচাটিতে,\tবনের পাখি ছিল বনে।\nএকদা কী করিয়া মিলন হল দোঁহে,\tকী ছিল বিধাতার মনে।\nবনের পাখি বলে, 'খাঁচার পাখি ভাই,\tবনেতে যাই দোঁহে মিলে।'\nখাঁচার পাখি বলে, 'বনের পাখি আয়, খাঁচায় থাকি নিরিবিলে।'\nবনের পাখি বলে, 'না, আমি শিকলে ধরা নাহি দিব।'\nখাঁচার পাখি বলে, 'হায়, আমি কেমনে বনে বাহিরিব।'\nবনের পাখি গাহে বাহিরে বসি বসি\tবনের গান ছিল যত,\nখাঁচার পাখি গাহে শিখানো বুলি তার- দোঁহার ভাষা দুইমত।\nবনের পাখি বলে 'খাঁচার পাখি ভাই, বনের গান গাও দেখি।'\nখাঁচার পাখি বলে, 'বনের পাখি ভাই, খাঁচার গান লহো শিখি।'\nবনের পাখি বলে, 'না, আমি শিখানো গান নাহি চাই।'\nখাঁচার পাখি বলে, 'হায় আমি কেমনে বনগান গাই।'\nবনের পাখি বলে, 'আকাশ ঘন নীল কোথাও বাধা নাহি তার।'\nখাঁচার পাখি বলে, 'খাঁচাটি পরিপাটি কেমন ঢাকা চারিধার।'\nবনের পাখি বলে, 'আপনা ছাড়ি দাও মেঘের মাঝে একেবারে।'\nখাঁচার পাখি বলে, 'নিরালা কোণে বসে বাঁধিয়া রাখো আপনারে।'\nবনের পাখি বলে, 'না, সেথা কোথায় উড়িবারে পাই!'\nখাঁচার পাখি বলে, 'হায়, মেঘে কোথায় বসিবার ঠাঁই।'\nএমনি দুই পাখি দোঁহারে ভালোবাসে,\tতবুও কাছে নাহি পায়।\nখাঁচার ফাঁকে ফাঁকে পরশে মুখে মুখে, নীরবে চোখে চোখে চায়।\nদুজনে কেহ কারে বুঝিতে নাহি পারে, বুঝাতে নারে আপনায়।\nদুজনে একা একা ঝাপটি মরে পাখা- কাতরে কহে, 'কাছে আয়!'\nবনের পাখি বলে, 'না, কবে\tখাঁচায় রুধি দিবে দ্বার!'\nখাঁচার পাখি বলে, 'হায়, মোর শকতি নাহি উড়িবার।'";
        this.String_53 = "রাগ: ভৈরবী\nতাল: ঝাঁপতাল\nরচনাস্থান: কলিকাতা\n\n\nএকদা প্রাতে কুঞ্জতলে\tঅন্ধ বালিকা\nপত্রপুটে আনিয়া দিল পুষ্পমালিকা।\nকণ্ঠে পরি অশ্রুজল\tভরিল নয়নে,\nবক্ষে লয়ে চুমিনু তার স্নিগ্ধ বয়নে।\nকহিনু তারে, 'অন্ধকারে\tদাঁড়ায়ে রমণী,\nকী ধন তুমি করিছ দান\tনা জানো আপনি।\nপুষ্পসম অন্ধ তুমি\tঅন্ধ বালিকা,\nদেখ নি নিজে মোহন কী যে\tতোমার মালিকা।'";
        this.String_54 = "রাগ: গৌড়সারং\nতাল: অজ্ঞাত\nরচনাস্থান: কলিকাতা\n\n\nকেন নিবে গেল বাতি।\nআমি অধিক যতনে ঢেকেছিনু তারে জাগিয়া বাসররাতি,\nতাই নিবে গেল বাতি।\nকেন ঝরে গেল ফুল।\nআমি বক্ষে চাপিয়া ধরেছিনু তারে\tচিন্তিত ভয়াকুল,\nতাই ঝরে গেল ফুল।\nকেন মরে গেল নদী।\nআমি বাঁধ বাঁধি তারে চাহি ধরিবারে পাইবারে নিরবধি,\nতাই মরে গেল নদী।\nকেন ছিঁড়ে গেল তার।\nআমি অধিক আবেগে প্রাণপণ বলে দিয়েছিনু ঝঙ্কার,\nতাই ছিঁড়ে গেল তার।";
        this.String_55 = "রাগ: কাফি\nতাল: অজ্ঞাত\n\n\nতুমি পড়িতেছ হেসে\tতরঙ্গের মতো এসে\nহৃদয়ে আমার।\nযৌবনসমুদ্রমাঝে\tকোন্\u200c পূর্ণিমায় আজি\nএসেছে জোয়ার।\nউচ্ছল পাগল নীরে\tতালে তালে ফিরে ফিরে\nএ মোর নির্জন তীরে কী খেলা তোমার!\nমোর সর্ব বক্ষ জুড়ে\tকত নৃত্যে কত সুরে\nএস কাছে যাও দূরে শতলক্ষবার।\nকুসুমের মতো শ্বসি পড়িতেছ খসি খসি\nমোর বক্ষ-'পরে\nগোপন শিহিরছলে\tবিন্দু বিন্দু অশ্রুজলে\nপ্রাণ সিক্ত ক'রে।\nনিঃশব্দ সৌরভরাশি\tপরানে পশিছে আসি\nসুখস্বপ্ন পরকাশি নিভৃত অন্তরে।\nপরশপুলকে ভোর চোখে আসে ঘুমঘোর,\nতোমার চুম্বন মোর সর্বাঙ্গে সঞ্চরে।";
        this.String_56 = "রাগ: বেহাগ\nতাল: কাওয়ালি\n\n\nআজি উন্মাদ মধুনিশি ওগো\tচৈত্রনিশীথশশী।\nতুমি এ বিপুল ধরণীর পানে কী দেখিছ একা বসি\nচৈত্রনিশীথশশী।\nকত নদীতীরে কত মন্দিরে\tকত বাতায়নতলে\nকত কানাকানি, মন- জানাজানি\tসাধাসাধি কত ছলে।\nশাখা- প্রশাখার দ্বার- জানালার\tআড়ালে আড়ালে পশি\nকত সুখদুখ কত কৌতুক\tদেখিতেছ একা বসি\nচৈত্রনিশীথশশী।\nমোরে দেখো চাহি- কেহ কোথা নাহি, শূন্যভবনছাদে\nনৈশ পবন কাঁদে।\nতোমারি মতন একাকী আপনি\tচাহিয়া রয়েছি বসি\nচৈত্রনিশীথশশী।";
        this.String_57 = "রাগ: কীর্তন\nরচনাস্থান: বোলপুর\n\n\nসে আসি কহিল, 'প্রিয়ে, মুখ তুলে চাও।'\nদুষিয়া তাহারে রুষিয়া কহিনু, 'যাও!'\nসখী ওলো সখী, সত্য করিয়া বলি, তবু সে গেল না চলি।\nদাঁড়ালো সমুখে; কহিনু তাহারে, 'সরো!'\nধরিল দু হাত; কহিনু, 'আহা, কী কর!'\nসখী ওলো সখী, মিছে না কহিব তোরে,\tতবু ছাড়িল না মোরে।\nশ্রুতিমূলে মুখ আনিল সে মিছিমিছি।\nনয়ন বাঁকায়ে কহিনু তাহারে, 'ছি ছি!'\nসখী ওলো সখী, কহি লো শপথ ক'রে\tতবু সে গেল না স'রে।\nঅধরে কপোল পরশ করিল তবু।\nকাঁপিয়া কহিনু, 'এমন দেখি নি কভু।'\nসখী ওলো সখী, একি তার বিবেচনা,\tতবু মুখ ফিরালো না।\nআপন মালাটি আমারে পরায়ে দিল।\nকহিনু তাহারে, 'মালায় কী কাজ ছিল!'\nসখী ওলো সখী, নাহি তার লাজ ভয়,\tমিছে তারে অনুনয়।\nআমার মালাটি চলিল গলায় লয়ে।\nচাহি তার পানে রহিনু অবাক হয়ে।\nসখী ওলো সখী, ভাসিতেছি আঁখিনীরে- কেন সে এল না ফিরে।";
        this.String_58 = "রাগ: মিশ্র ঝিঁঝিট- খাম্বাজ\nতাল: দাদরা\nরচনাস্থান: পতিসর হইতে কলকাতা যাবার পথে রেলগাড়িতে\nস্বরলিপিকার: রবীন্দ্রনাথ ঠাকুর\n\n\nএ কি সত্য সকলই সত্য, হে আমার চিরভক্ত।\nমোর নয়নের বিজুলি- উজল আলো\nযেন ঈশান কোণের ঝটিকার মতো কালো এ কি সত্য।\nমোর মধুর অধর বধূর নবীন অনুরাগ- সম রক্ত\nহে আমার চিরভক্ত, এ কি সত্য।\nঅতুল মাধুরী ফুটেছে আমার মাঝে,\nমোর চরণে চরণে সুধাসঙ্গীত বাজে এ কি সত্য।\nমোরে না হেরিয়া নিশির শিশির ঝরে,\nপ্রভাত- আলোকে পুলক আমারি তরে এ কি সত্য।\nমোর তপ্তকপোল- পরশে- অধীর সমীর মদিরমত্ত\nহে আমার চিরভক্ত, এ কি সত্য।";
        this.String_59 = "রাগ: বিভাস\nরচনাস্থান: ইচ্ছামতী নদীবক্ষে\n\n\nএবার চলিনু তবে।\nসময় হয়েছে নিকট, এখন বাঁধন ছিঁড়িতে হবে।\nউচ্ছল জল করে ছলছল,\nজাগিয়া উঠেছে কলকোলাহল,\nতরণীপতাকা চলচঞ্চল কাঁপিছে অধীর রবে।\nসময় হয়েছে নিকট, এখন বাঁধন ছিঁড়িতে হবে।\nআমি নিষ্ঠুর কঠিন কঠোর, নির্মম আমি আজি।\nআর নাই দেরি, ভৈরবভেরী বাহিরে উঠেছে বাজি।\nতুমি ঘুমাইছ নিমীলনয়নে,\nকাঁপিয়া উঠিছ বিরহস্বপনে,\nপ্রভাতে জাগিয়া শূন্য শয়নে কাঁদিয়া চাহিয়া রবে।\nসময় হয়েছে নিকট, এখন বাঁধন ছিঁড়িতে হবে।\nঅরুণ তোমার তরুণ অধর করুণ তোমার আঁখি-\nঅমিয়রচন সোহাগবচন অনেক রয়েছে বাকি।\nপাখি উড়ে যাবে সাগরের পার,\nসুখময় নীড় পড়ে রবে তার,\nমহাকাশ হতে ওই বারে- বার আমারে ডাকিছে সবে।\nসময় হয়েছে নিকট, এখন বাঁধন ছিঁড়িতে হবে।\nবিশ্বজগৎ আমারে মাগিলে কে মোর আত্মপর।\nআমার বিধাতা আমাতে জাগিলে কোথায় আমার ঘর।\nকিসেরই বা সুখ, ক' দিনের প্রাণ।\nওই উঠিয়াছে সংগ্রামগান,\nঅমর মরণ রক্তচরণ নাচিছে সগৌরবে।\nসময় হয়েছে নিকট, এখন বাঁধন ছিঁড়িতে হবে।";
        this.String_60 = "রাগ: বিভাস\nতাল: অজ্ঞাত\nরচনাস্থান: বড়াল নদী\n\n\nবন্ধু, কিসের তরে অশ্রু ঝরে, কিসের লাগি দীর্ঘশ্বাস।\nহাস্যমুখে অদৃষ্টেরে করব মোরা পরিহাস।\nরিক্ত যারা সর্বহারা\tসর্বজয়ী বিশ্বে তারা,\nগর্বময়ী ভাগ্যদেবীর নয়কো তারা ত্রীতদাস।\nহাস্যমুখে অদৃষ্টেরে করব মোরা পরিহাস।\nআমরা সুখের স্ফীত বুকের ছায়ার তলে নাহি চরি\nআমরা দুখের বক্র মুখের চক্র দেখে ভয় না করি।\nভগ্ন ঢাকে যথাসাধ্য বাজিয়ে যাব জয়বাদ্য,\nছিন্ন আশার ধ্বজা তুলে ভিন্ন করব নীলাকাশ।\nহাস্যমুখে অদৃষ্টেরে করব মোরা পরিহাস।\nহে অলক্ষ্মী, রুক্ষকেশী, তুমি দেবী অচঞ্চলা।\nতোমার রীতি সরল অতি, নাহি জানো ছলাকলা।\nজ্বালাও পেটে অগ্নিকণা নাইকো তাহে প্রতারণা\nটানো যখন মরণ- ফাঁসি বল নাকো মিষ্টভাষ।\nহাস্যমুখে অদৃষ্টেরে করব মোরা পরিহাস।\nধরার যারা সেরা সেরা মানুষ তারা তোমার ঘরে।\nতাদের কঠিন শয্যাখানি তাই পেতেছ মোদের তরে।\nআমরা বরপুত্র তব\tযাহাই দিবে তাহাই লব,\nতোমায় দিব ধন্যধ্বনি মাথায় বহি সর্বনাশ।\nহাস্যমুখে অদৃষ্টেরে করব মোরা পরিহাস।\nযৌবরাজ্যে বসিয়ে দে মা, লক্ষ্মীছাড়ার সিংহাসনে।\nভাঙা কুলোয় করুক পাখা তোমার যত ভৃত্যগণে।\nদগ্ধ ভালে প্রলয়শিখা দিক্\u200c মা, এঁকে তোমার টিকা,\nপরাও সজ্জা লজ্জাহারা- জীর্ণকন্থা ছিন্নবাস।\nহাস্যমুখে অদৃষ্টেরে করব মোরা পরিহাস।\nলুকোক তোমার ডঙ্কা শুনে কপট সখার শূন্য হাসি।\nপালাক ছুটে পুচ্ছ তুলে মিথ্যে চাটু মক্কা- কাশী।\nআত্মপরের- প্রভেদ- ভোলা জীর্ণ দুয়োর নিত্য খোলা,\nথাকবে তুমি থাকব আমি সমানভাবে বারো মাস।\nহাস্যমুখে অদৃষ্টেরে করব মোরা পরিহাস।\nশঙ্কা- তরাস লজ্জা- শরম চুকিয়ে দিলেম স্তুতি- নিন্দে।\nধুলো সে তোর পায়ের ধুলো তাই মেখেছি ভক্তবৃন্দে।\nআশারে কই, 'ঠাকুরানী, তোমার খেলা অনেক জানি,\nযাহার ভাগ্যে সকল ফাঁকি তারেও ফাঁকি দিতে চাস।'\nহাস্যমুখে অদৃষ্টেরে করব মোরা পরিহাস।\nমৃত্যু যেদিন বলবে 'জাগো, প্রভাত হল তোমার রাতি'\nনিবিয়ে যাব আমার ঘরের চন্দ্র সূর্য দুটো বাতি।\nআমরা দোঁহে ঘেঁষাঘেঁষি চিরদিনের প্রতিবেশী,\nবন্ধুভাবে কণ্ঠে সে মোর জড়িয়ে দেবে বাহুপাশ-\nবিদায়কালে অদৃষ্টেরে করে যাব পরিহাস। \ufeff";
        this.String_61 = "রাগ: পূরবী\nতাল: অজ্ঞাত\n\n\nভাঙা দেউলের দেবতা,\nতব বন্দনা রচিতে, ছিন্না বীণার তন্ত্রী বিরতা।\nসন্ধ্যাগগনে ঘোষে না শঙ্খ তোমার আরতিবারতা।\nতব মন্দির স্থিরগম্ভীর, ভাঙা দেউলের দেবতা।\nতব জনহীন ভবনে\nথেকে থেকে আসে ব্যাকুল গন্ধ নববসন্তপবনে।\nযে ফুলে রচে নি পূজার অর্ঘ্য, রাখে নি ও রাঙা চরণে,\nসে ফুল ফোটার আসে সমাচার জনহীন ভাঙা ভবনে।\nপূজাহীন তব পূজারি\nকোথা সারা দিন ফিরে উদাসীন কার প্রসাদের ভিখারি।\nগোধূলিবেলায় বনের ছায়ায় চির- উপবাস- ভুখারি\nভাঙা মন্দিরে আসে ফিরে ফিরে পূজাহীন তব পূজারি।\nভাঙা দেউলের দেবতা,\nকত উৎসব হইল নীরব, কত পূজানিশা বিগতা।\nকত বিজয়ায় নবীন প্রতিমা কত যায় কত কব তা-\nশুধু চিরদিন থাকে সেবাহীন ভাঙা দেউলের দেবতা।";
        this.String_62 = "রাগ: মিশ্র ভৈরব- বাউল\nতাল: একতাল\n\n\nযদি জোটে রোজ\nএমনি\tবিনি পয়সার ভোজ।\nডিশের পরে ডিশ\nশুধু\tমটন কারি ফিশ,\nসঙ্গে তারি হুইস্কি সোডা দু- চার রয়াল ডোজ।\nপরের তহবিল\nচোকায়\tউইল্\u200cসনের বিল-\nথাকি মনের সুখে হাস্যমুখে, কে কার রাখে খোঁজ।";
        this.String_63 = "রাগ: কালাংড়া\nতাল: মুক্তছন্দ\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nঅভয় দাও তো বলি আমার\nwish কী–\nএকটি ছটাক সোডার জলে\nপাকী তিন পোয়া হুইস্কি।";
        this.String_64 = "রাগ: খাম্বাজ\nতাল: ত্রিতাল\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nকত কাল রবে বল' ভারত রে\nশুধু ডাল ভাত জল পথ্য ক'রে।\nদেশে অন্নজলের হল ঘোর অনটন-\nধর' হুইস্কি- সোডা আর মুর্গি- মটন।\nযাও ঠাকুর চৈতন- চুট্\u200cকি নিয়া-\nএস' দাড়ি নাড়ি কলিমদ্দি মিয়া।";
        this.String_65 = "রাগ: খাম্বাজ\nতাল: মুক্তছন্দ\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nকী জানি কী ভেবেছ মনে\nখুলে বলো ললনে।\nকী কথা হায় ভেসে যায়\nওই\tছলোছলো দুটি নয়নে।";
        this.String_66 = "রাগ: কাফি\nতাল: মুক্তছন্দ\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nপাছে চেয়ে বসে আমার মন,\nআমি তাই ভয়ে ভয়ে থাকি।\nপাছে চোখে চোখে পড়ে বাঁধা,\nআমি তাই তো তুলি নে আঁখি।";
        this.String_67 = "রাগ: কালাংড়া\nতাল: মুক্তছন্দ\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nবড়ো থাকি কাছাকাছি,\nতাই ভয়ে ভয়ে আছি।\nনয়ন বচন কোথায় কখন\nবাজিলে বাঁচি না- বাঁচি।";
        this.String_68 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nযারে মরণ- দশায় ধরে\nসে যে শতবার ক'রে মরে।\nপোড়া পতঙ্গ যত পোড়ে\nতত\tআগুনে ঝাঁপিয়ে পড়ে।";
        this.String_69 = "রাগ: রামপ্রসাদী\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nদেখব কে তোর কাছে আসে-\nতুই রবি একেশ্বরী,\nএকলা আমি রইব পাশে।";
        this.String_70 = "রাগ: ভৈরবী\nতাল: অজ্ঞাত\n\n\nতুমি আমায় করবে মস্ত লোক-\nদেবে লিখে রাজার টিকে\nপ্রসন্ন ওই চোখ।";
        this.String_71 = "রাগ: কাফি\nতাল: অজ্ঞাত\n\n\nচির- পুরানো চাঁদ,\nচিরদিবস এমনি থেকো আমার এই সাধ।\nপুরানো হাসি পুরানো সুধা মিটায় মম পুরানো ক্ষুধা-\nনূতন কোনো চকোর যেন পায় না পরসাদ।";
        this.String_72 = "রাগ: মালকোষ\nতাল: মুক্তছন্দ\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nস্বর্গে তোমায় নিয়ে যাব উড়িয়ে-\nপিছে পিছে আমি চলব খুঁড়িয়ে,\nইচ্ছা হবে টিকির ডগা ধ'রে\nবিষ্ণুদূতের মাথাটা দিই গুঁড়িয়ে।";
        this.String_73 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nভুলে ভুলে আজ ভুলময়।\nভুলের লতায় বাতাসের ভুলে\nফুলে ফুলে হোক ফুলময়।\nআনন্দ- ঢেউ ভুলের সাগরে\nউছলিয়া হোক কূলময়।";
        this.String_74 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nসকলই ভুলেছে ভোলা মন।\nভোলে নি, ভোলে নি শুধু\nওই চন্দ্রানন।";
        this.String_75 = "রাগ: ভৈরব\nতাল: অজ্ঞাত\n\n\nপোড়া মনে শুধু পোড়া মুখখানি জাগে রে।\nএত আছে লোক, তবু পোড়া চোখে\nআর কেহ নাহি লাগে রে।";
        this.String_76 = "রাগ: পিলু\nতাল: অজ্ঞাত\n\n\nবিরহে মরিব ব'লে ছিল মনে পণ,\nকে তোরা বাহুতে বাঁধি করিলি বারণ।\nভেবেছিনু অশ্রুজলে ডুবিব অকূলতলে-\nকাহার সোনার তরী করিল তারণ।";
        this.String_77 = "রাগ: কাফি\nতাল: অজ্ঞাত\n\n\nকার হাতে যে ধরা দেব, প্রাণ,\nতাই\tভাবতে বেলা অবসান।\nডান দিকেতে তাকাই যখন\tবাঁয়ের লাগি কাঁদে রে মন-\nবাঁয়ের লাগি ফিরলে তখন দক্ষিণেতে পড়ে টান।";
        this.String_78 = "রাগ: সিন্ধু- ভৈরবী\nতাল: অজ্ঞাত\n\n\nওগো হৃদয়বনের শিকারী,\nমিছে তারে জালে ধরা যে তোমারি ভিখারি।\nসহস্রবার পায়ের কাছে আপনি যে জন ম'রে আছে\nনয়নবাণের খোঁচা খেতে সে যে অনধিকারী।";
        this.String_79 = "রাগ: ভৈরবী\nতাল: অজ্ঞাত\n\n\nওগো দয়াময়ী চোর, এত দয়া মনে তোর!\nবড়ো দয়া ক'রে কণ্ঠে আমার জড়াও মায়ার ডোর।\nবড়ো দয়া ক'রে চুরি ক'রে লও শূন্য হৃদয় মোর।";
        this.String_80 = "রাগ: বাহার\nতাল: মুক্তছন্দ\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nচলেছে ছুটিয়া পলাতকা হিয়া, বেগে বহে শিরাধমনী।\nহায় হায় হায়, ধরিবারে তায় পিছে পিছে ধায় রমণী।\nবায়ুবেগভরে উড়ে অঞ্চল, লটপট বেণী দুলে চঞ্চল-\nএকি রে রঙ্গ! আকুল- অঙ্গ ছুটে কুরঙ্গগমনী।";
        this.String_81 = "রাগ: খাম্বাজ\nতাল: অজ্ঞাত\n\n\nআমি কেবল ফুল জোগাব\nতোমার দুটি রাঙা হাতে।\nবুদ্ধি আমার খেলে নাকো\nপাহারা বা মন্ত্রণাতে।";
        this.String_82 = "রাগ: কাফি\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nমনোমন্দিরসুন্দরী! মণিমঞ্জীর গুঞ্জরি\nস্খলদঞ্চলা চলচঞ্চলা!\tঅয়ি মঞ্জুলা মুঞ্জরী!\nরোষারুণরাগরঞ্জিতা! বঙ্কিম- ভুরু- ভঞ্জিতা!\nগোপনহাস্য- কুটিল- আস্য কপটকলহগঞ্জিতা!\nসঙ্কোচনত- অঙ্গিনী! ভয়ভঙ্গুরভঙ্গিনী!\nচকিত চপল নবকুরঙ্গ যৌবনবনরঙ্গিণী!\nঅয়ি খলছলগুণ্ঠিতা! মধুকরভরকুণ্ঠিতা\nলুব্ধপবন- ক্ষুব্ধ- লোভন মল্লিকা অবলুণ্ঠিতা!\nচুম্বনধনবঞ্চিনী দুরূহগর্বমঞ্চিনী!\nরুদ্ধকোরক- সঞ্চিত- মধু কঠিনকনককঞ্জিনী।";
        this.String_83 = "রাগ: কাফি\nতাল: ঝম্পক\nরচনাস্থান: আলমোড়া\n\n\nতোমার কটি- তটের ধটি কে দিল রাঙিয়া-\nকোমল গায়ে দিল পরায়ে রঙিন আঙিয়া।\nবিহানবেলা আঙিনাতলে এসেছ তুমি কী খেলাছলে-\nচরণ দুটি চলিতে ছুটি পড়িছে ভাঙিয়া।\nতোমার কটি- তটের ধটি কে দিল রাঙিয়া।\nকিসের সুখে সহাস মুখে নাচিছ বাছনি-\nদুয়ার- পাশে জননী হাসে হেরিয়া নাচনি।\nতাথেই- থেই তালির সাথে কাঁকন বাজে মায়ের হাতে-\nরাখাল- বেশে ধরেছ হেসে বেণুর পাঁচনি।\nকিসের সুখে সহাস মুখে নাচিছ বাছনি।\nনিখিল শোনে আকুল- মনে নূপুর- বাজনা,\nতপন- শশী হেরিছে বসি তোমার সাজনা।\nঘুমাও যবে মায়ের বুকে\tআকাশ চেয়ে রহে ও মুখে,\nজাগিলে পরে প্রভাত করে নয়ন- মাজনা।\nনিখিল শোনে আকুল- মনে নূপুর- বাজনা।";
        this.String_84 = "রাগ: সাহানা\nতাল: ঝাঁপতাল\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nরাজরাজেন্দ্র জয় জয়তু জয় হে।\nব্যাপ্ত পরতাপ তব বিশ্বময় হে।\nদুষ্টদলন তব দণ্ড ভয়কারী, শত্রুজনদর্পহর দীপ্ত তরবারি-\nসঙ্কটশরণ্য তুমি দৈন্যদুখহারী\nমুক্ত- অবরোধ তব অভ্যুদয় হে।";
        this.String_85 = "রাগ: বাউল\nতাল: দাদরা\n\n\nআমরা বসব তোমার সনে। –\nতোমার শরিক হব রাজার রাজা,\nতোমার আধেক সিংহাসনে।\nতোমার দ্বারী মোদের করেছে শির নত –\nতারা\tজানে না যে মোদের গরব কত।\nতাই\tবাহির হতে তোমায় ডাকি,\nতুমি ডেকে লও গো আপন জনে।";
        this.String_86 = "রাগ: ইমন\nতাল: ঝাঁপতাল\n\n\nবঁধুয়া, অসময়ে কেন হে প্রকাশ।\nসকলই যে স্বপ্ন ব'লে হতেছে বিশ্বাস।\nতুমি গগনেরই তারা মর্তে এলে পথহারা–\nএলে ভুলে অশ্রুজলে আনন্দেরই হাস।";
        this.String_87 = "রাগ: ললিত\nতাল: অজ্ঞাত\n\n\nকবরীতে ফুল শুকালো\nকাননের ফুল ফুটল বনে।\nদিনের আলো প্রকাশিল,\nমনের সাধ রহিল মনে।";
        this.String_88 = "রাগ: কাফি- কানাড়া\nতাল: তেওরা\n\n\nমলিন মুখে ফুটুক হাসি, জুড়াক দু নয়ন।\nমলিন বসন ছাড়ো সখী, পরো আভরণ।\nঅশ্রু- ধোওয়া কাজল- রেখা আবার চোখে দিক- না দেখা,\nশিথিল বেণী তুলুক বেঁধে কুসুমবন্ধন।";
        this.String_89 = "রাগ: বাউল\nতাল: খেমটা\n\n\nওর মানের এ বাঁধ টুটবে না কি টুটবে না।\nওর মনের বেদন থাকবে মনে, প্রাণের কথা ফুটবে না? ।\nকঠিন পাষাণ বুকে লয়ে নাই রহিল অটল হয়ে\nপ্রেমেতে ওই পাথর ক্ষ'য়ে চোখের জল কি ছুটবে না? ।";
        this.String_90 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nআজ আমার আনন্দ দেখে কে!\nকে জানে\tবিদেশ হতে কে এসেছে–\nঘরে আমার কে এসেছে!\tআকাশে উঠেছে চাঁদা,\nসাগর কি থাকে বাঁধা–\tবসন্তরায়ের প্রাণে ঢেউ উঠেছে।";
        this.String_91 = "রাগ: তোড়ি\nতাল: অজ্ঞাত\n\n\nআর কি আমি ছাড়ব তোরে।\nমন দিয়ে মন নাই বা পেলেম,\nজোর ক'রে রাখিব ধ'রে।\nশূন্য করে হৃদয়পুরী মন যদি করিলে চুরি\nতুমিই তবে থাকো সেথায় শূন্য হৃদয় পূর্ণ ক'রে।";
        this.String_92 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nযেখানে রূপের প্রভা নয়ন- লোভা\nসেখানে তোমার মতন ভোলা কে ঠাকুরদাদা।\nযেখানে রসিকসভা পরম- শোভা\nসেখানে এমন রসের ঝোলা কে ঠাকুরদাদা।\nযেখানে গলাগলি কোলাকুলি\nতোমারি বেচা- কেনা সেই হাটে,\nপড়ে না পদধূলি পথ ভুলি\nযেখানে ঝগড়া করে ঝগ্\u200cড়াটে।\nযেখানে ভোলাভুলি খোলাখুলি\nসেখানে তোমার মতন খোলা কে ঠাকুরদাদা।";
        this.String_93 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nএই একলা মোদের হাজার মানুষ দাদাঠাকুর,\nএই আমাদের মজার মানুষ দাদাঠাকুর।\nএই তো নানা কাজে, এই তো নানা সাজে,\nএই আমাদের খেলার মানুষ দাদাঠাকুর।\nসব মিলনে মেলার মানুষ দাদাঠাকুর।\nএই তো হাসির দলে, এই তো চোখের জলে,\nএই তো সকল ক্ষণের মানুষ দাদাঠকুর।\nএই তো ঘরে ঘরে, এই তো বাহির করে\nএই আমাদের কোণের মানুষ দাদাঠাকুর।\nএই আমাদের মনের মানুষ দাদাঠকুর।";
        this.String_94 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nবাজে রে বাজে রে\nওই রুদ্রতালে বজ্রভেরী–\nদলে দলে চলে প্রলয়রঙ্গে বীরসাজে রে!\nদ্বিধা ত্রাস আলস নিদ্রা\tভাঙে লাজে রে!\nউড়ে দীপ্ত বিজয়কেতু\tশূন্য মাঝে রে!\nআছে কে পড়িয়া পিছে মিছে কাজে রে।";
        this.String_95 = "রাগ: ইমন\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nমোরা\tচলব না।\nমুকুল ঝরে ঝরুক, মোরা ফলব না।\nসূর্যতারা আগুন ভুগে জ্ব'লে মরুক যুগে যুগে–\nআমরা যতই পাই- না জ্বালা জ্বলব না।\nবনের শাখা কথা বলে, কথা জাগে সাগরজলে–\nএই ভুবনে আমরা কিছুই বলব না।\nকোথা হতে লাগে রে টান, জীবন- জলে ডাকে রে বান–\nআমরা তো এই প্রাণের টলায় টলব না।";
        this.String_96 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nপথে যেতে তোমার সাথে মিলন হল দিনের শেষে।\nদেখতে গিয়ে, সাঁঝের আলো মিলিয়ে গেল এক নিমেষে।\nদেখা তোমায় হোক বা না- হোক\nতাহার লাগি করব না শোক–\nক্ষণেক তুমি দাঁড়াও, তোমার চরণ ঢাকি এলো কেশে।";
        this.String_97 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nআমার নিকড়িয়া- রসের রসিক কানন ঘুরে ঘুরে\nনিকড়িয়া বাঁশের বাঁশি বাজায় মোহন সুরে।\nআমার ঘর বলে, 'তুই কোথায় যাবি, বাইরে গিয়ে সব খোয়াবি!'\nআমার প্রাণ বলে, 'তোর যা আছে সব যাক্\u200c- না উড়ে পুড়ে।'\nওগো, যায় যদি তো যাক্\u200c- না চুকে, সব হারাব হাসিমুখে–\nআমি এই চলেছি মরণসুধা নিতে পরান পূরে।\nওগো, আপন যারা কাছে টানে এ রস তারা কেই বা জানে–\nআমার বাঁকা পথের বাঁকা সে যে ডাক দিয়েছে দূরে।\nএবার বাঁকার টানে সোজার বোঝা পড়ুক ভেঙে- চুরে।";
        this.String_98 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nযখন দেখা দাও নি, রাধা, তখন বেজেছিল বাঁশি!\nএখন চোখে চোখে চেয়ে সুর যে আমার গেল ভাসি!\nতখন নানা তানের ছলে\nডাক ফিরেছে জলে স্থলে,\nএখন আমার সকল কাঁদা রাধার রূপে উঠল হাসি।";
        this.String_99 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nবঁধুর লাগি কেশে আমি পরব এমন ফুল\nস্বর্গে মর্তে তিন ভুবনে নাইকো যাহার মূল।\nবাঁশির ধ্বনি হাওয়ায় ভাসে, সবার কানে বাজবে না সে–\nদেখ্\u200c লো চেয়ে যমুনা ওই ভাসিয়ে গেল কূল।";
        this.String_100 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nমধুঋতু নিত্য হয়ে রইল তোমার মধুর দেশে–\nযাওয়া- আসার কান্নাহাসি হাওয়ায় সেথা বেড়ায় ভেসে।\nযায় যে জনা সেই শুধু যায়, ফুল ফোটা তো ফুরোয় না হায়–\nঝরবে যে ফুল সেই কেবলই ঝরে পড়ে বেলাশেষে।\nযখন আমি ছিলেম কাছে তখন কত দিয়েছি গান–\nএখন আমার দূরে যাওয়া, এরও কি গো নাই কোনো দান।\nপুষ্পবনের ছায়ায় ঢেকে\tএই আশা তাই গেলেম রেখে–\nআগুন- ভরা ফাগুনকে তোর কাঁদায় যেন আষাঢ় এসে।";
        this.String_101 = "রাগ: খাম্বাজ- বাউল\nতাল: দাদরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nও তো আর ফিরবে না রে, ফিরবে না আর, ফিরবে না রে।\nঝড়ের মুখে ভাসল তরী–\nকূলে ভিড়বে না রে।\nকোন্\u200c পাগলে নিল ডেকে,\nকাঁদন গেল পিছে রেখে–\nওকে তোর বাহুর বাঁধন ঘিরবে না রে।";
        this.String_102 = "রাগ: ইমনকল্যাণ\nতাল: তেওরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nবাজে রে বাজে ডমরু বাজে হৃদয়মাঝে, হৃদয়মাঝে।\nনাচে রে নাচে চরণ নাচে প্রাণের কাছে, প্রাণের কাছে।\nপ্রহর জাগে, প্রহরী জাগে– তারায় তারায় কাঁপন লাগে।\nমরমে মরমে বেদনা ফুটে– বাঁধন টুটে, বাঁধন টুটে।";
        this.String_103 = "রাগ: কাফি\nতাল: অজ্ঞাত\n\n\nআমার মনের বাঁধন ঘুচে যাবে যদি\tও ভাই রে,\nথাক্\u200c\tবাইরে বাঁধন তবে নিরবধি।\nযদি\tসাগর যাবার হুকুম থাকে\nথাক্\u200c\tতটের বাঁধন বাঁকে বাঁকে,\nতবে\tবাঁধে বাঁধে গান গাবে নদী\tভাই রে।";
        this.String_104 = "রাগ: ভৈরবী\n\n\nএতদিন পরে মোরে\nআপন হাতে বেঁধে দিলে মুক্তিডোরে।\nসাবধানীদের পিছে পিছে\nদিন কেটেছে কেবল মিছে,\nওদের\tবাঁধা পথের বাঁধন হতে টেনে নিলে আপন ক'রে।";
        this.String_105 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nনূতন পথের পথিক হয়ে আসে, পুরাতন সাথি,\nমিলন- উষায় ঘোমটা খসায়\tচিরবিরহের রাতি।\nযারে\tবারে বারে হারিয়ে মেলে\nআজ প্রাতে তার দেখা পেলে\nনূতন করে পায়ের তলে দেব হৃদয় পাতি।";
        this.String_106 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nকাজ ভোলাবার কে গো তোরা!\nরঙিন সাজে কে যে পাঠায়\nকোন্\u200c সে ভুবন- মনো- চোরা!\nকঠিন পাথর সারে সারে\nদেয় পাহারা গুহার দ্বারে,\nহাসির ধারায় ডুবিয়ে তারে\nঝরাও রসের সুধা- ঝোরা!\nস্বপন- তরীর তোরা নেয়ে\nলাগল প্রাণে নেশার হাওয়া,\nপাগ্\u200cলা পরান চলে গেয়ে।\nকোন্\u200c উদাসীর উপবনে\nবাজল বাঁশি ক্ষণে ক্ষণে,\nভুলিয়ে দিল ঈশান কোণে\nঝঞ্ঝা ঘনায় ঘনঘোরা।";
        this.String_107 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nশেষ ফলনের ফসল এবার\nকেটে লও, বাঁধো আঁটি।\nবাকি যা নয় গো নেবার\nমাটিতে হোক তা মাটি।";
        this.String_108 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nবাঁধন কেন ভূষণ- বেশে\nতোরে ভোলায়, হায় অভাগী।\nমরণ কেন মোহন হেসে\nতোরে দোলায়, হায় অভাগী।";
        this.String_109 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nদয়া করো, দয়া করো প্রভু, ফিরে ফিরে\nশত শত অপরাধে অপরাধিনীরে।\nঅন্তরে রয়েছ জাগি, তোমার প্রসাদ- লাগি\nদুর্বল পরান বাধা ঘটায় বাহিরে।\nশঙ্কা আসে, লজ্জা আসে, মরি অবসাদে।\nদৈন্যরাশি ফেলে গ্রাসি, ঘেরে পরমাদে।\nক্লান্ত দেহে তন্দ্রা লাগে, ধুলায় শয়ন মাগে–\nঅপথে জাগিয়া উঠি ভাসি আঁখিনীরে।";
        this.String_110 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nজয় জয় জয় হে জয় জ্যোতির্ময়–\nমোহকলুষঘন কর' ক্ষয়, কর' ক্ষয়।\nঅগ্নিপরশ তব কর' কর' দান,\nকর' নির্মল মম তনুমন প্রাণ–\nবন্ধনশৃঙ্খল নাহি সয়, নাহি সয়।\nগূঢ় বিঘ্ন যত কর' উৎপাটিত।\nঅমৃতদ্বার তব কর' উদ্\u200cঘাটিত।\nযাচি যাত্রিদল, হে কর্ণধার,\nসুপ্তিসাগর কর' কর' পার–\nস্বপ্নের সঞ্চয় হোক লয়, হোক লয়।";
        this.String_111 = "রাগ: ইমনকল্যাণ\nতাল: কাহারবা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nবাজো রে বাঁশরি, বাজো।\nসুন্দরী, চন্দনমাল্যে মঙ্গলসন্ধ্যায় সাজো।\nবুঝি মধুফাল্গুনমাসে চঞ্চল পান্থ সে আসে–\nমধুকরপদভরকম্পিত চম্পক অঙ্গনে ফোটে নি কি আজও।\nরক্তিম অংশুক মাথে, কিংশুককঙ্কণ হাতে,\nমঞ্জীরঝঙ্কৃত পায়ে সৌরভমন্থর বায়ে\nবন্দনসঙ্গীতগুঞ্জনমুখরিত নন্দনকুঞ্জে বিরাজো।";
        this.String_112 = "রাগ: কালাংড়া\nতাল: কাহারবা\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\n\nতোমায় সাজাব যতনে কুসুমে রতনে\nকেয়ূরে কঙ্কণে কুঙ্কুমে চন্দনে।\nকুন্তলে বেষ্টিব স্বর্ণজালিকা, কণ্ঠে দোলাইব মুক্তামালিকা,\nসীমন্তে সিন্দুর অরুণ বিন্দুর– চরণ রঞ্জিব অলক্ত- অঙ্কনে।\nসখীরে সাজাব সখার প্রেমে অলক্ষ্য প্রাণের অমূল্য হেমে।\nসাজাব সকরুণ বিরহবেদনায়, সাজাব অক্ষয় মিলনসাধনায়–\nমধুর লজ্জা রচিব সজ্জা যুগল প্রাণের বাণীর বন্ধনে।";
        this.String_113 = "রাগ: ইমন- ভূপালী\nতাল: কাহারবা\nরচনাস্থান: পানাদুরা (শ্রীলঙ্কা)\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\n\nনমো নমো শচীচিতরঞ্জন, সন্তাপভঞ্জন-\nনবজলধরকান্তি, ঘননীল- অঞ্জন– নমো হে, নমো নমো।\nনন্দনবীথির ছায়ে\tতব পদপাতে নব পারিজাতে\nউড়ে পরিমল মধুরাতে– নমো হে, নমো নমো।\nতোমার কটাক্ষের ছন্দে মেনকার মঞ্জীরবন্ধে\nজেগে উঠে গুঞ্জন মধুকরগঞ্জন– নমো হে, নমো নমো।";
        this.String_114 = "রাগ: মিশ্র কানাড়া\nতাল: কাহারবা\nরচনাস্থান: জলপথে, শিলাইদহের অভিমুখে\nস্বরলিপিকার: প্রফুল্লকুমার দাস\n\n\nনহ মাতা, নহ কন্যা, নহ বধূ, সুন্দরী রূপসী হে নন্দনবাসিনী উর্বশী।\nগোষ্ঠে যবে নামে সন্ধ্যা শ্রান্ত দেহে স্বর্ণাঞ্চল টানি\nতুমি কোনো গৃহপ্রান্তে নাহি জ্বালো সন্ধ্যাদীপখানি।\nদ্বিধায় জড়িত পদে কম্প্রবক্ষে নম্রনেত্রপাতে\nস্মিতহাস্যে নাহি চল লজ্জিত বাসরশয্যাতে অর্ধরাতে।\nউষার উদয়- সম অনবগুণ্ঠিতা তুমি অকুণ্ঠিতা।\nসুরসভাতলে যবে নৃত্য করো পুলকে উল্লসি\nহে বিলোল হিল্লোল উর্বশী,\nছন্দে নাচি উঠে সিন্ধুমাঝে তরঙ্গের দল,\nশস্যশীর্ষে শিহরিয়া কাঁপি উঠে ধরার অঞ্চল,\nতোমার মদির গন্ধ অন্ধ বায়ু বহে চারি ভিতে,\nমধুমত্ত ভৃঙ্গ- সম মুগ্ধ কবি ফিরে লুব্ধ চিতে উদ্দাম গীতে।\nনূপুর গুঞ্জরি চলো আকুল- অঞ্চলা বিদ্যুতচঞ্চলা।";
        this.String_115 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nপ্রহরশেষের আলোয় রাঙা সেদিন চৈত্রমাস–\nতোমার চোখে দেখেছিলাম আমার সর্বনাশ।\nএ সংসারের নিত্য খেলায় প্রতিদিনের প্রাণের মেলায়\nবাটে ঘাটে হাজার লোকের হাস্য- পরিহাস–\nমাঝখানে তার তোমার চোখে আমার সর্বনাশ।\nআমের বনে দোলা লাগে, মুকুল প'ড়ে ঝ'রে–\nচিরকালের চেনা গন্ধ হাওয়ায় ওঠে ভ'রে।\nমঞ্জরিত শাখায় শাখায়, মউমাছিদের পাখায় পাখায়,\nক্ষণে ক্ষণে বসন্তদিন ফেলেছে নিশ্বাস–\nমাঝখানে তার তোমার চোখে আমার সর্বনাশ।";
        this.String_116 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nবলেছিল 'ধরা দেব না', শুনেছিল সেই বড়াই।\nবীরপুরুষের সয় নি গুমোর, বাধিয়ে দিয়েছে লড়াই।\nতার পরে শেষে কী যে হল কার,\nকোন্\u200c দশা হল জয়পতাকার। –\nকেউ বলে জিৎ, কেউ বলে হার, আমরা গুজব ছড়াই।";
        this.String_117 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nগুরুপদে মন করো অর্পণ, ঢালো ধন তাঁর ঝুলিতে।\nলঘু হবে ভার, রবে নাকো আর ভবের দোলায় দুলিতে।\nহিসাবের খাতা নাড়ো ব'সে ব'সে, মহাজনে নেয় সুদ ক'ষে ক'ষে –\nখাঁটি যেই জন সেই মহাজনে কেন থাকো হায় ভুলিতে।\nদিন চলে যায় ট্যাঁকে টাকা হায় কেবলই খুলিতে তুলিতে।";
        this.String_118 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nশোন্\u200c রে শোন্\u200c অবোধ মন, –\nশোন্\u200c সাধুর উক্তি, কিসে মুক্তি সেই সুযুক্তি কর্ গ্রহণ।\nভবের শুক্তি ভেঙে মুক্তিমুক্তা কর্ অন্বেষণ,\nওরে ও ভোলা মন।";
        this.String_119 = "রাগ: কেদারা\nতাল: কাহারবা\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nজয় জয় তাসবংশ- অবতংস!\nত্রীড়াসরসীনীরে রাজহংস।\nতাম্রকূটঘনধূমবিলাসী! তন্দ্রাতীরনিবাসী!\nসব- অবকাশ- ধ্বংস! যমরাজেরই অংশ।";
        this.String_120 = "রাগ: ইমন\nতাল: কাহারবা\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nতোলন- নামন পিছন- সামন।\nবাঁয়ে ডাইনে চাই নে, চাই নে।\nবোসন- ওঠন ছড়ান- গুটন।\nউল্টা- পাল্টা ঘূর্ণি চালটা– বাস্\u200c! বাস্\u200c! বাস্\u200c!";
        this.String_121 = "রাগ: ভূপালী\nতাল: কাহারবা\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nআমরা চিত্র অতি বিচিত্র,\nঅতি বিশুদ্ধ, অতি পবিত্র।\nআমাদের যুদ্ধ নহে কেহ ক্রুদ্ধ।\nওই দেখো গোলাম অতিশয় মোলাম।\nনাহি কোনো অস্ত্র খাকি- রাঙা বস্ত্র।\nনাহি লোভ, নাহি ক্ষোভ।\nনাহি লাফ, নাহি ঝাঁপ।\nযথারীতি জানি, সেই মতো মানি।\nকে তোমার শত্রু, কে তোমার মিত্র।\nকে তোমার টক্কা, কে তোমার ফক্কা।";
        this.String_122 = "রাগ: ইমন\nতাল: কাহারবা\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nচিঁড়েতন হর্তন ইস্কাবন\nঅতি সনাতন ছন্দে কর্\u200cতেছে নর্তন।\nকেউ বা ওঠে কেউ পড়ে,\nকেউ বা একটু নাহি নড়ে,\nকেউ শুয়ে শুয়ে ভুঁয়ে করে কালকর্তন।\nনাহি কহে কথা কিছু–\nএকটু না হাসে, সামনে যে আসে\nচলে তারি পিছু পিছু।\nবাঁধা তার পুরাতন চালটা,\nনাই কোনো উল্টা- পাল্টা– নাই পরিবর্তন।";
        this.String_123 = "রাগ: কীর্তন\nতাল: দাদরা\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nচলো নিয়ম- মতে।\nদূরে তাকিয়ো নাকো, ঘাড় বাঁকিয়ো নাকো!\nচলো সমান পথে।\n'হেরো অরণ্য ওই, হোথা শৃঙ্খলা কই–\nপাগল ঝর্নাগুলো দক্ষিণপর্বতে।'\nও দিক চেয়ো না, চেয়ো না– যেয়ো না, যেয়ো না।\nচলো সমান পথে।";
        this.String_124 = "রাগ: পূরবী\nতাল: কাহারবা\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nহা- আ- আ- আই।\nনাই কাজ নাই।\nদিন যায়, দিন যায়।\nআয় আয়, আয় আয়।\nহাতে কাজ নাই।";
        this.String_125 = "রাগ: হাম্বীর\nতাল: কাহারবা\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nহাঁচ্ছোঃ! –ভয় কী দেখাচ্ছ।\nধরি টিপে টুঁটি, মুখে মারি মুঠি–\nবলো দেখি কী আরাম পাচ্ছ।\nহাঁচ্ছো। হাঁচ্ছো।";
        this.String_126 = "রাগ: আড়ানা\nতাল: কাহারবা\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nইচ্ছে! –ইচ্ছে!\nসেই তো ভাঙছে, সেই তো গড়ছে,\nসেই তো দিচ্ছে নিচ্ছে।\nসেই তো আঘাত করছে তলায়, সেই তো বাঁধন ছিঁড়ে পালায়–\nবাঁধন পরতে সেই তো আবার ফিরছে।";
        this.String_127 = "রাগ: রামকেলী- ভৈরবী\nতাল: দাদরা\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\n\nআমরা দূর আকাশের নেশায় মাতাল ঘরভোলা সব যত–\nবকুলবনের গন্ধে আকুল মউমাছিদের মতো।\nসূর্য ওঠার আগে মন আমাদের জাগে–\nবাতাস থেকে ভোর- বেলাকার সুর ধরি সব কত।\nকে দেয় রে হাতছানি\nনীল পাহাড়ের মেঘে মেঘে, আভাস বুঝি জানি।\nপথ যে চলে বেঁকে বেঁকে\tঅলখ- পানে ডেকে ডেকে\nধরা যারে যায় না তারি ব্যাকুল খোঁজেই রত।";
        this.String_128 = "রাগ: খাম্বাজ\nতাল: ষষ্ঠী\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\n\nবাহির হলেম আমি আপন ভিতর হতে,\nনীল আকাশে পাড়ি দেব খ্যাপা হাওয়ার স্রোতে।\nআমের মুকুল ফুটে ফুটে যখন পড়ে ঝ'রে ঝ'রে\nমাটির আঁচল ভ'রে ভ'রে–\nঝরাই আমার মনের কথা ভরা ফাগুন- চোতে।\nকোথা তুই\tপ্রাণের দোসর বেড়াস ঘুরি ঘুরি–\nবনবীথির আলোছায়ায় করিস লুকোচুরি।\nআমার একলা বাঁশি পাগলামি তার পাঠায় দিগন্তরে\nতোমার গানের তরে–\nকবে বসন্তেরে জাগিয়ে দেব আমাতে আর তোতে।";
        this.String_129 = "রাগ: মল্লার\nতাল: কাহারবা\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\n\nশুনি ওই রুনুঝুনু পায়ে পায়ে নূপুরধ্বনি\nচকিত পথে বনে বনে।\nনির্ঝর ঝরো ঝরো ঝরিছে দূরে,\nজলতলে বাজে শিলা ঠুনু- ঠুনু ঠুনু- ঠুনু।\nঝিল্লিঝঙ্কৃত বেণুবনছায়া পল্লবমর্মরে কাঁপে,\nপাপিয়া ডাকে, পুলকিত শিরীষশাখে\nদোল দিয়ে যায় দক্ষিণবায় পুন পুন।";
        this.String_130 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nএই তো ভরা হল ফুলে ফুলে ফুলের ডালা।\nভরা হল– কে নিবি কে নিবি গো, গাঁথিবি বরণমালা।\nচম্পা চামেলি সেঁউতি বেলি\nদেখে যা সাজি আজি রেখেছি মেলি–\nনবমালতীগন্ধ- ঢালা।\nবনের মাধুরী হরণ করো তরুণ আপন দেহে।\nনববধূ, মিলনশুভলগন- রাত্রে\tলও গো বাসরগেহে–\nউপবনের সৌরভভাষা,\nরসতৃষিত মধুপের আশা।\nরাত্রিজাগর রজনীগন্ধা–\nকরবী রূপসীর অলকানন্দা–\nগোলাপে গোলাপে মিলিয়া মিলিয়া\tরচিবে মিলনের পালা।";
        this.String_131 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nসুরের জালে কে জড়ালে আমার মন,\nআমি ছাড়াতে পারি নে সে বন্ধন।\nআমায়\tঅজানা গহনে টানিয়া নিয়ে যে যায়,\nবরন- বরন স্বপনছায়ায় করিল মগন।\nজানি না কোথায় চরণ ফেলি, মরীচিকায় নয়ন মেলি–\nকী ভুলে ভুলালো দূরের বাঁশি!\tমন উদাসী\nআপনারে\tহারালো, ধ্বনিতে আবৃত চেতন।";
        this.String_132 = "রাগ: কীর্তন\nতাল: দাদরা\nস্বরলিপিকার: শান্তিদেব ঘোষ, শৈলজারঞ্জন মজুমদার\n\n\nকোথাও আমার হারিয়ে যাওয়ার নেই মানা\tমনে মনে!\nমেলে দিলেম গানের সুরের এই ডানা\tমনে মনে।\nতেপান্তরের পাথার পেরোই রূপ- কথার,\nপথ ভুলে যাই দূর পারে সেই চুপ্\u200c- কথার–\nপারুলবনের চম্পারে মোর হয় জানা\tমনে মনে।\nসূর্য যখন অস্তে পড়ে ঢুলি মেঘে মেঘে আকাশ- কুসুম তুলি।\nসাত সাগরের ফেনায় ফেনায় মিশে\nআমি\tযাই ভেসে দূর দিশে–\nপরীর দেশের বন্ধ দুয়ার দিই হানা মনে মনে।";
        this.String_133 = "রাগ: ?\nতাল: ?\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\n\nঅসুন্দরের পরম বেদনায় সুন্দরের আহ্বান।\nসূর্যরশ্মি কালো মেঘের ললাটে পরায় ইন্দ্রধনু, তার লজ্জাকে সান্ত্বনা দেবার তরে।\nমর্তের অভিশাপে স্বর্গের করুণা যখন নামে তখনি তো সুন্দরের আবির্ভাব।\nপ্রিয়তমে, সেই করুণাই কি তোমার হৃদয়কে কাল মধুর করে নি।";
