        this.String_9 = "রাগ: দেশ- মল্লার\nতাল: কাহারবা\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nওই মেঘ করে বুঝি গগনে।\nআঁধার ছাইল, রজনী আইল,\nঘরে ফিরে যাব কেমনে!\nচরণ অবশ হায়, শ্রান্ত ক্লান্ত কায়\nসারা দিবস বন ভ্রমণে।\nঘরে ফিরে যব কেমনে!";
        this.String_10 = "রাগ: দেশ- মল্লার\nতাল: ত্রিতাল\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nএ কী এ ঘোর বন! - এনু কোথায়!\nপথ যে জানি না, মোরে দেখায়ে দে না।\nকী করি এ আঁধার রাতে।\nকী হবে মোর হায়।\nঘন ঘোর মেঘ ছেয়েছে গগনে,\nচকিত চপলা চমকে সঘনে,\nএকেলা বালিকা\nতরাসে কাঁপে কায়।";
        this.String_11 = "রাগ: যোগিয়া\nতাল: খেমটা\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nপথ ভুলেছিস সত্যি বটে? সিধে রাস্তা দেখতে চাস?\nএমন জায়গায় পাঠিয়ে দেব, সুখে থাকবি বারো মাস।\nহাঃ হাঃ হাঃ, হাঃ হাঃ হাঃ!\nকেমন হে ভাই!\nকেমন সে ঠাঁই?\nমন্দ নহে বড়ো,\nএক দিন না এক দিন সবাই সেথায় হব জড়ো।\nহাঃ হাঃ হাঃ!\nআয় সাথে আয়, রাস্তা তোরে দেখিয়ে দিই গে তবে,\nআর তা হলে রাস্তা ভুলে ঘুরতে নাহি হবে।\nহাঃ হাঃ হাঃ!";
        this.String_12 = "রাগ: বিলাতি ভাঙা\nতাল: ত্রিতাল\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nমরি ও কাহার বাছা, ওকে কোথায় নিয়ে যায়।\nআহা ঐ করুণ চোখে ও কাহার পানে চায়।\nবাঁধা কঠিন পাশে, অঙ্গ কাঁপে ত্রাসে,\nআঁখি জলে ভাসে, এ কী দশা হায়।\nএ বনে কে আছে, যাব কার কাছে,\nকে ওরে বাঁচায়।";
        this.String_13 = "রাগ: বাগেশ্রী\nতাল: ত্রিতাল\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nরাঙাপদপদ্মযুগে প্রণমি গো ভবদারা!\nআজি এ ঘোর নিশীথে পূজিব তোমারে তারা।\nসুরনর থরহর– ব্রহ্মাণ্ডবিপ্লব করো,\nরণরঙ্গে মাতো, মা গো, ঘোরা উন্মাদিনী- পারা।\nঝলসিয়ে দিশি দিশি ঘুরাও তরিত- অসি,\nছুটাও শোণিতস্রোত, ভাসাও বিপুল ধরা।\nউরো কালী কপালিনী, মহাকালসীমন্তিনী,\nলহো জবাপুষ্পাঞ্জলি মহাদেবী পরাৎপরা।";
        this.String_14 = "রাগ: কাফি\nতাল: খেমটা\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nদেখো হে ঠাকুর, বলি এনেছি মোরা।\nবড়ো সরেস পেয়েছি বলি সরেস–\nএমন সরেস মছলি, রাজা, জালে না পড়ে ধরা।\nদেরি কেন ঠাকুর, সেরে ফেলো ত্বরা।";
