        this.String_20 = "রাগ: খাম্বাজ\nতাল: ত্রিতাল\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nব্যাকুল হয়ে বনে বনে,\nভ্রমি একেলা শূন্যমনে।\nকে পুরাবে মোর কাতর প্রাণ,\nজুড়াবে হিয়া সুধাবরিষণে।";
        this.String_21 = "রাগ: কাফি\nতাল: খেমটা\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nছাড়ব না ভাই, ছাড়ব না ভাই,\nএমন শিকার ছাড়ব না।\nহাতের কাছে অম্\u200cনি এল, অম্\u200cনি যাবে!\nঅম্\u200cনি যেতে দেবে কে রে।\nরাজাটা খেপেছে রে, তার কথা আর মানব না।\nআজ রাতে ধুম হবে ভারি,\nনিয়ে আয় কারণ বারি,\nজ্বেলে দে মশালগুলো, মনের মতন পুজো দেব-\nনেচে নেচে ঘুরে ঘুরে- রাজাটা খেপেছে রে,\nতার কথা আার মানব না।";
        this.String_22 = "রাগ: আড়ানা\nতাল: একতাল\nস্বরলিপিকার: প্রতিভা দেবী, ইন্দিরা দেবী\n\n\nরাজা মহারাজা কে জানে, আমিই রাজাধিরাজ।\nতুমি উজীর, কোতোয়াল তুমি,\nওই ছোঁড়াগুলো বরকন্দাজ।\nযত সব কুঁড়ে আছে ঠাঁই জুড়ে\nকাজের বেলায় বুদ্ধি যায় উড়ে।\nপা ধোবার জল নিয়ে আয় ঝট্\u200c,\nকর্\u200c তোরা সব যে যার কাজ।";
        this.String_23 = "রাগ: দেশ\nতাল: কাহারবা\nস্বরলিপিকার: প্রতিভা দেবী\n\n\nআছে তোমার বিদ্যে- সাধ্যি জানা।\nরাজত্ব করা এ কি তামাশা পেয়েছ।\nজানিস না কেটা আমি।\nঢের ঢের জানি- ঢের ঢের জানি-\nহাসিস নে হাসিস নে মিছে, যা যা-\nসব আপন কাজে যা যা,\nযা আপন কাজে।\nখুব তোমার লম্বাচওড়া কথা!\nনিতান্ত দেখি তোমায় কৃতান্ত ডেকেছে!";
        this.String_24 = "রাগ: কাফি\nতাল: দাদরা\nস্বরলিপিকার: প্রতিভা দেবী\n\n\nআঃ কাজ কী গোলমালে,\nনা হয় রাজাই সাজালে।\nমরবার বেলায় মরবে ওটাই, থাকব ফাঁকতালে।\nরাম রাম হরি হরি, ওরা থাকতে আমি মরি!\nতেমন তেমন দেখলে বাবা ঢুকব আড়ালে।\nওরে চল্\u200c তবে শিগ্\u200cগিরি,\nআনি পূজোর সামিগ্\u200cগিরি।\nকথায় কথায় রাত পোহাল, এমনি কাজের ছিরি।";
        this.String_25 = "রাগ: ভৈরবী\nতাল: ত্রিতাল\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nহা কী দশা হল আমার!\nকোথা গো মা করুণাময়ী, অরণ্যে প্রাণ যায় গো!\nমুহূর্তের তরে মা গো, দেখা দাও আমারে,\nজনমের মত বিদায়!";
        this.String_26 = "রাগ: পিলু- ভৈরব\nতাল: খেমটা\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nএত রঙ্গ শিখেছ কোথা মুণ্ডমালিনী!\nতোমার নৃত্য দেখে চিত্ত কাঁপে চমকে ধরণী।\nক্ষান্ত দে মা, শান্ত হ মা, সন্তানের মিনতি।\nরাঙা নয়ন দেখে নয়ন মুদি, ও মা ত্রিনয়নী।";
        this.String_27 = "রাগ: বেহাগ\nতাল: ত্রিতাল\nস্বরলিপিকার: প্রতিভা দেবী\n\n\nঅহো আস্পর্ধা এ কী তোদের নরাধম!\nতোদের কারেও চাহি নে আর আর না রে-\nদূর দূর দূর, আমারে আর ছুঁস নে।\nএ- সব কাজ আর না, এ পাপ আর না,\nআর না আর না, ত্রাহি, সব ছাড়িনু!";
        this.String_28 = "রাগ: ভৈরবী\nতাল: ঝাঁপতাল\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nআয় মা আমার সাথে কোনো ভয় নাহি আর।\nকত দুঃখ পেলি বনে আহা মা আমার!\nনয়নে ঝরিছে বারি, এ কি মা সহিতে পারি।\nকোমল কাতর তনু কাঁপিতেছে বার বার।";
        this.String_29 = "রাগ: মল্লার\nতাল: ত্রিতাল\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর, ইন্দিরা দেবী\n\n\nরিম্\u200c ঝিম্\u200c ঘন ঘন রে বরষে।\nগগনে ঘনঘটা, শিহরে তরুলতা,\nময়ূর ময়ূরী নাচিছে হরষে।\nদিশি দিশি সচকিত, দামিনী চমকিত,\nচমকি উঠিছে হরিণী তরাসে!";
        this.String_30 = "রাগ: বেহাগ\nতাল: ত্রিতাল\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nকোথায় জুড়াতে আছে ঠাঁই-\nকেন প্রাণ কেন কাঁদে রে।\nযাই দেখি শিকারেতে, রহিব আমোদে মেতে,\nভুলি সব জ্বালা, বনে বনে ছুটিয়ে-\nকেন প্রাণ কেন কাঁদে রে।\nআপনা ভুলিতে চাই, ভুলিব কেমনে,\nকেমনে যাবে বেদনা।\nদলবল লয়ে মাতিব।\nকেন প্রাণ কেন কাঁদে রে।";
        this.String_31 = "রাগ: দেশ\nতাল: খেমটা\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nকেন রাজা ডাকিস কেন, এসেছি সবে।\nবুঝি আবার শ্যামা মায়ের পুজো হবে।\nশিকারে হবে যেতে, আয় রে সাথে।\nওরে, রাজা কী বলছে শোন্\u200c।\nশিকারে চল তবে।\nসবারে আন্\u200c ডেকে যত দলবল সবে।";
        this.String_32 = "রাগ: ইমন- ভূপালী\nতাল: কাহারবা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর, ইন্দিরা দেবী\n\n\nএই বেলা সবে মিলে চল হো, চল হো\nছুটে আয়, শিকারে কে রে যাবি আয়,\nএমন রজনী বহে যায় যে!\nধনুর্বাণ লয়ে হাতে, আয় আয় আয় আয়।\nবাজা শিঙ্গা ঘন ঘন, শব্দে কাঁপিবে বন,\nআকাশ ফেটে যাবে, চমকিবে পশু পাখি সবে,\nছুটে যাবে কাননে কাননে, চারি দিকে ঘিরে\nযাব পিছে পিছে, হো হো হো হো!";
        this.String_33 = "রাগ: বাহার\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর, ইন্দিরা দেবী\n\n\nগহনে গহনে যা রে তোরা, নিশি বহে যায় যে।\nতন্ন তন্ন করি অরণ্য, করী বরাহ খোঁজ গে,\nএই বেলা যা রে।\nনিশাচর পশু সবে, এখনি বাহির হবে,\nধনুর্বাণ নে রে হাতে, চল্\u200c ত্বরা চল্\u200c।\nজ্বালায়ে মশাল- আলো, এই বেলা আয় রে।";
        this.String_34 = "রাগ: ভূপালী\nতাল: কাহারবা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর, ইন্দিরা দেবী\n\n\nচল্\u200c চল্\u200c ভাই, ত্বরা করে মোরা আগে যাই।\nপ্রাণপণ খোঁজ্\u200c এ বন সে বন,\nচল্\u200c মোরা ক- জন ওদিকে যাই।\nনা না ভাই, কাজ নাই\nহোথা কিছু নাই, কিছু নাই,\nওই ঝোপে যদি কিছু পাই।\nবরা বরা-\nআরে দাঁড়া দাঁড়া, অত ব্যস্ত হলে ফসকাবে শিকার,\nচুপি চুপি আয়, চুপি চুপি আয় অশথতলায়,\nএবার ঠিকঠাক হয়ে সব থাক্\u200c,\nসাবধান ধর্\u200c বাণ, সাবধান ছাড়্\u200c বাণ,\nগেল গেল, ঐ ঐ, পালায় পালায়, চল্\u200c চল্\u200c।\nছোট্\u200c রে পিছে আয় রে ত্বরা যাই।";
        this.String_35 = "রাগ: দেশ- মল্লার\nতাল: তেওরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর, ইন্দিরা দেবী\n\n\nকে এল আজি এ ঘোর নিশীথে,\nসাধের কাননে শান্তি নাশিতে।\nমত্ত করী যত পদ্মবন দলে\nবিমল সরোবর মন্থিয়া,\nঘুমন্ত বিহগে কেন বধে রে\nসঘনে খর শর সন্ধিয়া।\nতরাসে চমকিয়ে হরিণ- হরিণী\nস্খলিত চরণে ছুটিছে।\nস্খলিত চরণে ছুটিছে কাননে,\nকরুণ নয়নে চাহিছে-\nআকুল সরসী, সারস- সারসী\nশর- বনে পশি কাঁদিছে।\nতিমির দিগ্\u200c ভরি ঘোর যামিনী\nবিপদ ঘন ছায়া ছাইয়া-\nতরাসে প্রাণ ওঠে কাঁপিয়া।";
        this.String_36 = "রাগ: দেশ- মল্লার\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর, ইন্দিরা দেবী\n\n\nপ্রাণ নিয়ে ত সট্\u200cকেছি রে করবি এখন কী।\nওরে বরা করবি এখন কী।\nবাবা রে, আমি চুপ করে এই কচুবনে লুকিয়ে থাকি।\nএই মরদের মুরদখানা, দেখেও কি রে ভড়কালি না,\nবাহবা শাবাশ তোরে, শাবাশ রে তোর ভরসা দেখি।";
        this.String_37 = "রাগ: যোগিয়া\nতাল: ত্রিতাল\nস্বরলিপিকার: প্রতিভা দেবী\n\n\nবলব কী আর বলব খুড়ো- উঁ উঁ।\nআমার যা হয়েছে বলি কার কাছে-\nএকটা বুড়ো ছাগল তেড়ে এসে মেরেছে ঢুঁ।\nতখন যে ভারি ছিল জারিজুরি,\nএখন কেন করছ বাপু উঁ উঁ উঁ-\nকোন্\u200cখানে লেগেছে বাবা, দিই একটু ফুঁ।";
        this.String_38 = "রাগ: শঙ্করা\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর, ইন্দিরা দেবী\n\n\nসর্দার মহাশয় দেরি না সয়,\nতোমার আশায় সবাই বসে।\nশিকারেতে হবে যেতে,\nমিহি কোমর বাঁধো কষে।\nবনবাদাড় সব ঘেঁটে ঘুঁটে,\nআমরা মরব খেটে খুটে,\nতুমি কেবল লুটে পুটে\nপেট পোরাবে ঠেসে ঠুসে।";
        this.String_39 = "রাগ: বাহার\nতাল: কাহারবা\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nরাখ্\u200c রাখ্\u200c ফেল্\u200c ধনু ছাড়িস নে বাণ।\nহরিণ- শাবক দুটি প্রাণভয়ে ধায় ছুটি,\nচাহিতেছে ফিরে ফিরে করুণ নয়ান।\nকোনো দোষ করে নি তো সুকুমার কলেবর,\nকেমনে কোমল দেহে বিঁধিবি কঠিন শর।\nথাক্\u200c থাক্\u200c ওরে থাক্\u200c, এ দারুণ খেলা রাখ্\u200c,\nআজ হতে বিসর্জিনু এ ছার ধনুক বাণ।";
        this.String_40 = "রাগ: ঝিঁঝিট- বেহাগ\nতাল: দাদরা\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nআর না আর না, এখানে আর না,\nআয় রে সকলে চলিয়া যাই।\nধনুক বাণ ফেলেছে রাজা,\nএখানে কেমনে থাকব ভাই!\nচল্\u200c চল্\u200c চল্\u200c এখনি যাই।\nতোর দশা, রাজা, ভালো তো নয়,\nরক্তপাতে পাস রে ভয়,\nলাজে মোরা মরে যাই।\nপাখিটি মারিলে কাঁদিয়া খুন,\nনা জানি কে তোরে করিল গুণ,\nহেন কভু দেখি নাই।";
        this.String_41 = "রাগ: মিশ্র হাম্বীর- কীর্তন\nতাল: ত্রিতাল\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nজীবনের কিছু হল না হায়-\nহল না গো হল না হায় হায়।\nগহনে গহনে কত আর ভ্রমিব, নিরাশার এ আঁধারে।\nশূন্য হৃদয় আর বহিতে যে পারি না,\nপারি না গো পারি না আর।\nকী লয়ে এখন ধরিব জীবন, দিবস- রজনী চলিয়া যায়-\nদিবস- রজনী চলিয়া যায়-\nকত কী করিব বলি উঠে বাসনা,\nকী করিব জানি না গো।\nসহচর ছিল যারা, ত্যেজিয়া গেল তারা; ধনুর্বাণ ত্যেজেছি,\nকোনো আর নাহি কাজ-\nকী করি কী করি বলি, হাহা করি ভ্রমি গো-\nকী করিব জানি না যে!";
        this.String_42 = "রাগ: ভূপালী\nতাল: কাহারবা\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nদেখ্\u200c দেখ্\u200c, দুটো পাখি বসেছে গাছে।\nআয় দেখি চুপি চুপি আয় রে কাছে।\nআরে ঝট্\u200c করে এই বারে ছেড়ে দে রে বাণ।\nরোস রোস আগে আমি করি রে সন্ধান।";
        this.String_43 = "রাগ: ভৈরবী\nতাল: ঝাঁপতাল\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nথাম্\u200c থাম্\u200c, কী করিবি বধি পাখিটির প্রাণ।\nদুটিতে রয়েছে সুখে, মনের উল্লাসে গাহিতেছে গান।\nরাখো মিছে ও- সব কথা,\nকাছে মোদের এস নাকো হেথা,\nচাই নে ও- সব শাস্তর কথা, সময় বহে যায় যে।\nশোনো শোনো মিছে রোষ ক'রো না।\nথামো থামো ঠাকুর, এই ছাড়ি বাণ।";
        this.String_44 = "রাগ: বাহার\nতাল: ২ + ২ ছন্দ\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nকী বলিনু আমি! এ কী সুললিত বাণী রে!\nকিছু না জানি কেমনে যে আমি প্রকাশিনু দেবভাষা,\nএমন কথা কেমনে শিখিনু রে!\nপুলকে পুরিল মনপ্রাণ, মধু বরষিল শ্রবণে,\nএ কী! হৃদয়ে এ কী এ দেখি! -\nঘোর অন্ধকার মাঝে, এ কী জ্যোতি ভায়,\nঅবাক্\u200c! - করুণা এ কার!";
        this.String_45 = "রাগ: ভূপালী\nতাল: কাহারবা\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nএ কী এ, এ কী এ, স্থির চপলা!\nকিরণে কিরণে হল সব দিক উজলা!\nকী প্রতিমা দেখি এ,\nজোছনা মাখিয়ে,\nকে রেখেছে আঁকিয়ে,\nআ মরি কমল- পুতলা!";
        this.String_46 = "রাগ: প্রভাতী- গুজরাটি\nতাল: ঝাঁপতাল\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nনমি নমি ভারতী, তব কমল চরণে\nপুণ্য হল বনভূমি, ধন্য হল প্রাণ।\nপূর্ণ হল বাসনা, দেবী কমলাসনা,\nধন্য হল দস্যুপতি, গলিল পাষাণ।\nকঠিন ধরাভূমি এ, কমলালয়া তুমি যে,\nহৃদয়- কমলে চরণ- কমল করো দান।\nতব কমল- পরিমলে রাখো হৃদি ভরিয়ে,\nচিরদিবস করিব তব চরণ- সুধা পান।";
        this.String_47 = "রাগ: রামপ্রসাদী\nতাল: একতাল\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nশ্যামা, এবার ছেড়ে চলেছি মা!\nপাষাণের মেয়ে পাষাণী তুই, না বুঝে মা বলেছি মা!\nএত দিন কী ছল করে তুই পাষাণ করে রেখেছিলি-\nআজ আপন মায়ের দেখা পেয়ে নয়ন- জলে গলেছি মা!\nকালো দেখে ভুলি নে আর, আলো দেখে ভুলেছে মন-\nআমায় তুমি ছলেছিলে, এবার আমি তোমায় ছলেছি মা!\nমায়ার মায়া কাটিয়ে এবার মায়ের কোলে চলেছি মা।";
        this.String_48 = "রাগ: ভৈরব\nতাল: ত্রিতাল\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nকোথা লুকাইলে?\nসব আশা নিবিল, দশদিশি অন্ধকার,\nসবে গেছে চলে ত্যেজিয়ে আমারে,\nতুমিও কি তেয়াগিলে।";
        this.String_49 = "রাগ: ভৈরবী\nতাল: ঝাঁপতাল\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nকেন গো আপন মনে ভ্রমিছ বনে বনে, সলিল দু- নয়নে\nকিসের দুখে?\nকমলা দিতেছি আসি, রতন রাশি রাশি, ফুটুক তবে হাসি\nমলিন মুখে।\nকমলা যারে চায়, বলো সে কী না পায়, দুখের এ ধরায়\nথাকে সে সুখে।\nত্যেজিয়া কমলাসনে, এসেছি ঘোর বনে, আমারে শুভক্ষণে\nহেরো গো চোখে।";
        this.String_50 = "রাগ: ভৈরবী\nতাল: কাহারবা\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nকোথায় সে উষাময়ী প্রতিমা।\nতুমি তো নহ সে দেবী, কমলাসনা,\nক'রো না আমারে ছলনা।\nকী এনেছ ধন মান, তাহা যে চাহে না প্রাণ।\nদেবী গো, চাহি না চাহি না, মণিময় ধূলিরাশি চাহি না,\nতাহা লয়ে সুখী যারা হয় হোক, হয় হোক-\nআমি, দেবী, সে সুখ চাহি না।\nযাও লক্ষ্মী অলকায়, যাও লক্ষ্মী অমরায়,\nএ বনে এসো না এসো না,\nএসো না এ দীনজন- কুটিরে।\nযে বীণা শুনেছি কানে, মন প্রাণ আছে ভোর,\nআর কিছু চাহি না চাহি না।";
        this.String_51 = "রাগ: খট\nতাল: ঝাঁপতাল\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nবাণী বীণাপাণি, করুণাময়ী!\nঅন্ধজনে নয়ন দিয়ে অন্ধকারে ফেলিলে,\nদরশ দিয়ে লুকালে কোথা দেবী অয়ি।\nস্বপন সম মিলাবে যদি কেন গো দিলে চেতনা,\nচকিতে শুধু দেখা দিয়ে চির মরম- বেদনা,\nতোমারে চাহি ফিরিছে, হেরো কাননে কাননে ওই।";
        this.String_52 = "রাগ: বাহার\nতাল: ত্রিতাল- দাদরা\nস্বরলিপিকার: প্রতিভা দেবী, দিনেন্দ্রনাথ ঠাকুর\n\n\nএই যে হেরি গো দেবী আমারি!\nসব কবিতাময় জগত- চরাচর,\nসব শোভাময় নেহারি।\nছন্দে উঠিছে চন্দ্রমা, ছন্দে কনক- রবি উদিছে,\nছন্দে জগ- মণ্ডল চলিছে,\nজ্বলন্ত কবিতা তারকা সবে;\nএ কবিতার মাঝারে তুমি কে গো দেবী,\nআলোকে আলো আঁধারি।\nআজি মলয় আকুল, বনে বনে এ কী গীত গাহিছে,\nফুল কহিছে প্রাণের কাহিনী,\nনব রাগ- রাগিণী উছাসিছে,\nএ আনন্দে আজ গীত গাহে মোর হৃদয় সব অবারি।\nতুমিই কি দেবী ভারতী, কৃপাগুণে অন্ধ আঁখি ফুটালে,\nউষা আনিলে প্রাণের আঁধারে,\nপ্রকৃতির রাগিণী শিখাইলে!\nতুমি ধন্য গো,\nরব চিরকাল চরণ ধরি তোমারি।";
