        this.String_3 = "রাগ: ইমনকল্যাণ\nতাল: কাহারবা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nনাই ভয়, নাই ভয়, নাই রে।\nথাক্\u200c পড়ে থাক্\u200c ভয় বাইরে॥\nজাগো, মৃত্যুঞ্জয়, চিত্তে থৈ থৈ নর্তননৃত্যে।\nওরে মন, বন্ধনছিন্ন\nদাও তালি তাই তাই তাই রে॥";
        this.String_4 = "রাগ: ভৈরবী\nতাল: দাদরা\nরচনাস্থান: কলকাতা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nপ্রলয়- নাচন নাচলে যখন আপন ভুলে\nহে নটরাজ, জটার বাঁধন পড়ল খুলে॥\nজাহ্নবী তাই মুক্তধারায়\tউন্মাদিনী দিশা হারায়,\nসঙ্গীতে তার তরঙ্গদল উঠল দুলে॥\nরবির আলো সাড়া দিল আকাশ- পারে।\nশুনিয়ে দিল অভয়বাণী ঘর- ছাড়ারে।\nআপন স্রোতে আপনি মাতে,\tসাথি হল আপন- সাথে,\nসব- হারা সে সব পেল তার কূলে কূলে॥";
        this.String_5 = "রাগ: ইমন- কীর্তন\nতাল: কাহারবা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nদুই হাতে-\nকালের মন্দিরা যে সদাই বাজে ডাইনে বাঁয়ে দুই হাতে,\nসুপ্তি ছুটে নৃত্য উঠে নিত্য নূতন সংঘাতে॥\nবাজে ফুলে, বাজে কাঁটায়, আলোছায়ার জোয়ার- ভাঁটায়,\nপ্রাণের মাঝে ওই- যে বাজে দুঃখে সুখে শঙ্কাতে॥\nতালে তালে সাঁঝ- সকালে রূপ- সাগরে ঢেউ লাগে।\nসাদা- কালোর দ্বন্দ্বে যে ওই ছন্দে নানান রঙ জাগে।\nএই তালে তোর গান বেঁধে নে- কান্নাহাসির তান সেধে নে,\nডাক দিল শোন্\u200c মরণ বাঁচন নাচন- সভার ডঙ্কাতে॥";
        this.String_6 = "রাগ: কাফি\nতাল: খেমটা- ষষ্ঠী\nস্বরলিপিকার: সুরেন্দ্রনাথ বন্দ্যোপাধ্যায়\n\n\nমম চিত্তে নিতি নৃত্যে কে যে নাচে\nতাতা থৈথৈ, তাতা থৈথৈ, তাতা থৈথৈ।\nতারি সঙ্গে কী মৃদঙ্গে সদা বাজে\nতাতা থৈথৈ তাতা থৈথৈ তাতা থৈথৈ॥\nহাসিকান্না হীরাপান্না দোলে ভালে,\nকাঁপে ছন্দে ভালোমন্দ তালে তালে,\nনাচে জন্ম নাচে মৃত্যু পাছে পাছে,\nতাতা থৈথৈ, তাতা থৈথৈ, তাতা থৈথৈ।\nকী আনন্দ, কী আনন্দ, কী আনন্দ\nদিবারাত্রি নাচে মুক্তি নাচে বন্ধ-\nসে তরঙ্গে ছুটি রঙ্গে পাছে পাছে\nতাতা থৈথৈ, তাতা থৈথৈ, তাতা থৈথৈ॥";
        this.String_7 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nআমার ঘুর লেগেছে- তাধিন্\u200c তাধিন্\u200c।\nতোমার পিছন পিছন নেচে নেচে ঘুর লেগেছে তাধিন্\u200c তাধিন্\u200c।\nতোমার তালে আমার চরণ চলে, শুনতে না পাই কে কী বলে-\nতাধিন্\u200c তাধিন্\u200c।\nতোমার গানে আমার প্রাণে যে কোন্\u200c পাগল ছিল সেই জেগেছে-\nতাধিন্\u200c তাধিন্\u200c।\nআমার লাজের বাঁধন সাজের বাঁধন খ'সে গেল ভজন সাধন-\nতাধিন্\u200c তাধিন্\u200c।\nবিষম\tনাচের বেগে দোলা লেগে ভাবনা যত সব ভেগেছে-\nতাধিন্\u200c তাধিন্\u200c॥";
        this.String_8 = "রাগ: সাহানা\nতাল: একতাল\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nকমলবনের মধুপরাজি, এসো হে কমলভবনে।\nকী সুধাগন্ধ এসেছে আজি নববসন্তপবনে॥\nঅমল চরণ ঘেরিয়া পুলকে শত শতদল ফুটিল,\nবারতা তাহারি দ্যুলোকে ভূলোকে ছুটিল ভুবনে ভুবনে॥\nগ্রহে তারকায় কিরণে কিরণে বাজিয়া উঠিছে রাগিণী\nগীতগুঞ্জন কূজনকাকলি আকুলি উঠিছে শ্রবণে।\nসাগর গাহিছে কল্লোলগাথা, বায়ু বাজাইছে শঙ্খ-\nসামগান উঠে বনপল্লবে, মঙ্গলগীত জীবনে॥";
        this.String_9 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\nরচনাস্থান: শিলাইদহ\n\n\nএসো গো নূতন জীবন।\nএসো গো কঠোর নিঠুর নীরব, এসো গো ভীষণ শোভন॥\nএসো অপ্রিয় বিরস তিক্ত, এসো গো অশ্রুসলিলসিক্ত,\nএসো গো ভূষণবিহীন রিক্ত, এসো গো চিত্তপাবন॥\nথাক্\u200c বীণাবেণু, মালতীমালিকা পূর্ণিমানিশি, মায়াকুহেলিকা-\nএসো গো প্রখর হোমানলশিখা হৃদয়শোণিতপ্রাশন।\nএসো গো পরমদুঃখনিলয়, আশা- অঙ্কুর করহ বিলয়-\nএসো সংগ্রাম, এসো মহাজয়, এসো গো মরণসাধন॥";
        this.String_10 = "রাগ: ইমন\nতাল: কাহারবা\nরচনাস্থান: নৌকায়, শিলাইদহ\nস্বরলিপিকার: জ্যোতিরিন্দ্রনাথ ঠাকুর\n\n\nমধুর মধুর ধ্বনি বাজে\nহৃদয়কমলবনমাঝে॥\nনিভৃতবাসিনী বীণাপাণি অমৃতমুরতিমতী বাণী\nহিরণকিরণ ছবিখানি- পরানের কোথা সে বিরাজে॥\nমধুঋতু জাগে দিবানিশি পিককুহরিত দিশি দিশি।\nমানসমধুপ পদতলে মুরছি পড়িছে পরিমলে।\nএসো দেবী, এসো এ আলোকে, একবার তোরে হেরি চোখে-\nগোপনে থেকো না মনোলোকে ছায়াময় মায়াময় সাজে॥";
        this.String_11 = "রাগ: মূলতান\nতাল: অজ্ঞাত\nরচনাস্থান: জোড়াসাঁকো\n\n\nওঠো রে মলিনমুখ, চলো এইবার।\nএসো রে তৃষিত- বুক, রাখো হাহাকার॥\nহেরো ওই গেল বেলা, ভাঙিল ভাঙিল মেলা-\nগেল সবে ছাড়ি খেলা ঘরে যে যাহার॥\nহে ভিখারি, কারে তুমি শুনাইছ সুর-\nরজনী আঁধার হল, পথ অতি দূর।\nক্ষুধিত তৃষিত প্রাণে আর কাজ নাহি গানে-\nএখন বেসুর তানে বাজিছে সেতার॥";
        this.String_12 = "রাগ: বাউল\nতাল: দাদরা\nরচনাস্থান: গিরিডি\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nআমার নাইবা হল পারে যাওয়া।\nযে হাওয়াতে চলত তরী অঙ্গেতে সেই লাগাই হাওয়া॥\nনেই যদি বা জমল পাড়ি ঘাট আছে তো বসতে পারি।\nআমার আশার তরী ডুবল যদি দেখব তোদের তরী- বাওয়া॥\nহাতের কাছে কোলের কাছে যা আছে সেই অনেক আছে।\nআমার সারা দিনের এই কি রে কাজ- ওপার- পানে কেঁদে চাওয়া।\nকম কিছু মোর থাকে হেথা পুরিয়ে নেব প্রাণ দিয়ে তা।\nআমার সেইখানেতেই কল্পলতা যেখানে মোর দাবি- দাওয়া॥";
        this.String_13 = "রাগ: বাউল\nতাল: দাদরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nযখন\tপড়বে না মোর পায়ের চিহ্ন এই বাটে,\nআমি\tবাইব না মোর খেয়াতরী এই ঘাটে,\nচুকিয়ে দেব বেচা কেনা,\nমিটিয়ে দেব গো, মিটিয়ে দেব লেনা দেনা,\nবন্ধ হবে আনাগোনা এই হাটে-\nতখন আমায় নাইবা মনে রাখলে,\nতারার পানে চেয়ে চেয়ে নাইবা আমায় ডাকলে।\n\nযখন\tজমবে ধুলা তানপুরাটার তারগুলায়,\nকাঁটালতা উঠবে ঘরের দ্বারগুলায়, আহা,\nফুলের বাগান ঘন ঘাসের পরবে সজ্জা বনবাসের,\nশ্যাওলা এসে ঘিরবে দিঘির ধারগুলায়-\nতখন আমায় নাইবা মনে রাখলে,\nতারার পানে চেয়ে চেয়ে নাইবা আমায় ডাকলে।\n\nতখন এমনি করেই বাজবে বাঁশি এই নাটে,\nকাটবে দিন কাটবে,\nকাটবে গো দিন আজও যেমন দিন কাটে,\tআহা,\nঘাটে ঘাটে খেয়ার তরী এমনি সে দিন উঠবে ভরি-\nচরবে গোরু খেলবে রাখাল ওই মাঠে।\nতখন আমায় নাইবা মনে রাখলে,\nতারার পানে চেয়ে চেয়ে নাইবা আমায় ডাকলে।\n\nতখন কে বলে গো সেই প্রভাতে নেই আমি।\nসকল খেলায় করবে খেলা এই আমি- আহা,\nনতুন নামে ডাকবে মোরে, বাঁধবে নতুন বাহু- ডোরে,\nআসব যাব চিরদিনের সেই আমি।\nতখন আমায় নাইবা মনে রাখলে,\nতারার পানে চেয়ে চেয়ে নাইবা আমায় ডাকলে॥";
        this.String_14 = "রাগ: বাউল\nতাল: কাহারবা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর, সুরেন্দ্রনাথ বন্দ্যোপাধ্যায়\n\n\nগ্রামছাড়া ওই রাঙা মাটির পথ\tআমার মন ভুলায় রে।\nওরে\tকার পানে মন হাত বাড়িয়ে\tলুটিয়ে যায় ধুলায় রে॥\nও যে\tআমায় ঘরের বাহির করে,\tপায়ে- পায়ে পায়ে ধরে-\nও যে\tকেড়ে আমায় নিয়ে যায় রে\tযায় রে কোন্\u200c চুলায় রে।\nও যে\tকোন্\u200c বাঁকে কী ধন দেখাবে,\tকোন্\u200cখানে কী দায় ঠেকাবে-\nকোথায় গিয়ে শেষ মেলে যে\tভেবেই না কুলায় রে॥";
        this.String_15 = "রাগ: বাউল\nতাল: কাহারবা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nএই তো ভালো লেগেছিল আলোর নাচন পাতায় পাতায়।\nশালের বনে খ্যাপা হাওয়া, এই তো আমার মনকে মাতায়।\nরাঙা মাটির রাস্তা বেয়ে হাটের পথিক চলে ধেয়ে,\nছোটো মেয়ে ধুলায় বসে খেলার ডালি একলা সাজায়-\nসামনে চেয়ে এই যা দেখি চোখে আমার বীণা বাজায়॥\n\nআমার এ যে বাঁশের বাঁশি, মাঠের সুরে আমার সাধন।\nআমার মনকে বেঁধেছে রে এই ধরণীর মাটির বাঁধন।\nনীল আকাশের আলোর ধারা পান করেছে নতুন যারা\nসেই ছেলেদের চোখের চাওয়া নিয়েছি মোর দু চোখ পুরে-\nআমার বীণায় সুর বেঁধেছি ওদের কচি গলার সুরে॥\n\nদূরে যাবার খেয়াল হলে সবাই মোরে ঘিরে থামায়-\nগাঁয়ের আকাশ সজনে ফুলের হাতছানিতে ডাকে আমায়।\nফুরায় নি, ভাই, কাছের সুধা, নাই যে রে তাই দূরের ক্ষুধা-\nএই- যে এ- সব ছোটোখাটো পাই নি এদের কূলকিনারা।\nতুচ্ছ দিনের গানের পালা আজও আমার হয় নি সারা॥\n\nলাগল ভালো, মন ভোলালো, এই কথাটাই গেয়ে বেড়াই-\nদিনে রাতে সময় কোথা, কাজের কথা তাই তো এড়াই।\nমজেছে মন, মজল আঁখি- মিথ্যে আমায় ডাকাডাকি-\nওদের আছে অনেক আশা, ওরা করুক অনেক জড়ো-\nআমি কেবল গেয়ে বেড়াই, চাই নে হতে আরো বড়ো॥";
        this.String_16 = "রাগ: পিলু- বাউল\nতাল: দাদরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nরাঙিয়ে দিয়ে যাও যাও যাও গো এবার যাবার আগে-\nতোমার আপন রাগে, তোমার গোপন রাগে,\nতোমার তরুণ হাসির অরুণ রাগে\nঅশ্রুজলের করুণ রাগে॥\nরঙ যেন মোর মর্মে লাগে, আমার সকল কর্মে লাগে,\nসন্ধ্যাদীপের আগায় লাগে, গভীর রাতের জাগায় লাগে॥\nযাবার আগে যাও গো আমায় জাগিয়ে দিয়ে,\nরক্তে তোমার চরণ- দোলা লাগিয়ে দিয়ে।\nআঁধার নিশার বক্ষে যেমন তারা জাগে,\nপাষাণগুহার কক্ষে নিঝর- ধারা জাগে,\nমেঘের বুকে যেমন মেঘের মন্দ্র জাগে,\nবিশ্ব- নাচের কেন্দ্রে যেমন ছন্দ জাগে,\nতেমনি আমায় দোল দিয়ে যাও যাবার পথে আগিয়ে দিয়ে,\nকাঁদন- বাঁধন ভাগিয়ে দিয়ে॥";
        this.String_17 = "রাগ: খাম্বাজ\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nআমার অন্ধপ্রদীপ শূন্য- পানে চেয়ে আছে,\nসে যে লজ্জা জানায় ব্যর্থ রাতের তারার কাছে॥\nললাটে তার পড়ুক লিখা\nতোমার লিখন ওগো শিখা-\nবিজয়টিকা দাও গো এঁকে এই সে যাচে॥\nহায়\tকাহার পথে বাহির হলে বিরহিণী!\nতোমার\tআলোক- ঋণে করো তুমি আমায় ঋণী।\nতোমার রাতে আমার রাতে\nএক আলোকের সূত্রে গাঁথে\nএমন ভাগ্য হায় গো আমার হারায় পাছে॥";
        this.String_18 = "রাগ: ইমন\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nকেন যে মন ভোলে আমার মন জানে না।\nতারে মানা করে কে, আমার মন মানে না॥\nকেউ বোঝে না তারে, সে যে বোঝে না আপ্\u200cনারে।\nসবাই লজ্জা দিয়ে যায়, সে তো কানে আনে না॥\nতার খেয়া গেল পারে, সে যে রইল নদীর ধারে।\nকাজ ক'রে সব সারা ওই এগিয়ে গেল কারা,\nআন্\u200cমনা মন সে দিক- পানে দৃষ্টি হানে না॥";
        this.String_19 = "রাগ: কালাংড়া\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nআমারে ডাক দিল কে ভিতর পানে-\nওরা যে ডাকতে জানে॥\nআশ্বিনে ওই শিউলিশাখে\nমৌমাছিরে যেমন ডাকে\nপ্রভাতে সৌরভের গানে॥\nঘরছাড়া আজ ঘর পেল যে, আপন মনে রইল ম'জে।\nহাওয়ায় হাওয়ায় কেমন ক'রে খবর যে তার পৌঁছল রে\nঘর- ছাড়া ওই মেঘের কানে॥";
        this.String_20 = "রাগ: ভৈরবী\nতাল: দাদরা\nরচনাস্থান: আহমেদাবাদ\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nহাটের ধুলা সয় না যে আর, কাতর করে প্রাণ।\nতোমার\tসুরসুরধুনীর ধারায় করাও আমায় ম্লান॥\nজাগাক তারি মৃদঙ্গরোল, রক্তে তুলুক তরঙ্গদোল,\nঅঙ্গ হতে ফেলুক ধুয়ে সকল অসম্মান-\nসব কোলাহল দিক্\u200c ডুবায়ে তাহার কলতান॥\nসুন্দর হে, তোমার ফুলে গেঁথেছিলেম মালা-\nসেই কথা আজ মনে করাও, ভুলাও সকল জ্বালা।\nতোমার গানের পদ্মবনে আবার ডাকো নিমন্ত্রণে-\nতারি গোপন সুধাকণা আবার করাও পান,\nতারি রেণুর তিলকলেখা আমায় করো দান॥";
        this.String_21 = "রাগ: মিশ্র দেশ\nতাল: দাদরা\n\n\nআমি\tএকলা চলেছি এ ভবে,\nআমায়\tপথের সন্ধান কে কবে।\nভয় নেই, ভয় নেই-\nযাও আপন মনেই\nযেমন\tএকলা মধুপ ধেয়ে যায়\nকেবল\tফুলের সৌরভে॥";
        this.String_22 = "রাগ: কীর্তন\nতাল: দাদরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nস্বপন- পারের ডাক শুনেছি, জেগে তাই তো ভাবি-\nকেউ কখনো খুঁজে কি পায় স্বপ্নলোকের চাবি॥\nনয় তো সেথায় যাবার তরে, নয় কিছু তো পাবার তরে,\nনাই কিছু তার দাবি-\nবিশ্ব হতে হারিয়ে গেছে স্বপ্নলোকের চাবি॥\nচাওয়া- পাওয়ার বুকের ভিতর না- পাওয়া ফুল ফোটে,\nদিশাহারা গন্ধে তারি আকাশ ভরে ওঠে।\nখুঁজে যারে বেড়াই গানে, প্রাণের গভীর অতল- পানে\nযে জন গেছে নাবি,\nসেই নিয়েছে চুরি করে স্বপ্নলোকের চাবি॥";
        this.String_23 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\nরচনাস্থান: শান্তিনিকেতন\n\n\nআপন- মনে গোপন কোণে লেখাজোখার কারখানাতে\nদুয়ার রুধে বচন কুঁদে খেলনা আমার হয় বানাতে॥\nএই জগতের সকাল সাঁজে ছুটি আমার সকল কাজে,\nমিলে মিলে মিলিয়ে কথা রঙে রঙে হয় মানাতে॥\nকে গো আছে ভুবন- মাঝে নিত্যশিশু আনন্দেতে,\nডাকে আমায় বিশ্বখেলায় খেলাঘরের জোগান দিতে।\nবনের হাওয়ায় সকাল- বেলা ভাসায় সে যে গানের ভেলা,\nসেই তো কাঁপায় সুরের কাঁপন মৌমাছিদের নীল ডানাতে॥";
        this.String_24 = "রাগ: মূলতান\nতাল: ষষ্ঠী\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nসকাল- বেলার কুঁড়ি আমার বিকালে যায় টুটে,\nমাঝখানে হায় হয় নি দেখা উঠল যখন ফুটে॥\nঝরা ফুলের পাপড়িগুলি ধুলো থেকে আনিস তুলি,\nযখন\tসময় ছিল দিল ফাঁকি-\nএখন\tআন্\u200c কুড়ায়ে দিনের শেষে অসময়ের ছিন্ন বাকি।\nকৃষ্ণরাতের চাঁদের কণা আঁধারকে দেয় যে সান্ত্বনা\nতাই নিয়ে মোর মিটুক আশা- স্বপন গেছে ছুটে॥";
        this.String_25 = "রাগ: পিলু\nতাল: কাহারবা\n\n\nপাগল যে তুই, কণ্ঠ ভরে\nজানিয়ে দে তাই সাহস করে॥\nদেয় যদি তোর দুয়ার নাড়া\nথাকিস কোণে, দিস নে সাড়া-\nবলুক সবাই 'সৃষ্টিছাড়া', বলুক সবাই 'কী কাজ তোরে'॥\nবল্\u200c রে 'আমি কেহই না গো,\nকিছুই নহি, যে হই- না'।\nশুনে বনে উঠবে হাসি,\nদিকে দিকে বাজবে বাঁশি-\nবলবে বাতাস 'ভালোবাসি', বাঁধবে আকাশ অলখ ডোরে॥";
        this.String_26 = "রাগ: মিশ্র কেদারা- খাম্বাজ\nতাল: দাদরা\nরচনাস্থান: শান্তিনিকেতন\n\n\nখেলাঘর\tবাঁধতে লেগেছি আমার মনের ভিতরে।\nকত রাত তাই তো জেগেছি বলব কী তোরে॥\nপ্রভাতে\tপথিক ডেকে যায়, অবসর পাই নে আমি হায়-\nবাহিরের খেলায় ডাকে সে, যাব কী ক'রে॥\nযা আমার সবার হেলাফেলা যাচ্ছে ছড়াছড়ি\nপুরোনো\tভাঙা দিনের ঢেলা, তাই দিয়ে ঘর গড়ি।\nযে আমার নতুন খেলার জন তারি এই খেলার সিংহাসন,\nভাঙারে জোড়া দেবে সে কিসের মন্তরে॥";
        this.String_27 = "রাগ: ভৈরবী\nতাল: ষষ্ঠী\nরচনাস্থান: শান্তিনিকেতন\n\n\nগোপন প্রাণে একলা মানুষ যে\nতারে কাজের পাকে জড়িয়ে রাখিস নে॥\nতার\tএকলা ঘরের ধেয়ান হতে উঠুক- না গান নানা স্রোতে,\nতার\tআপন সুরের ভুবন- মাঝে তারে থাকতে দে॥\nতোর প্রাণের মাঝে একলা মানুষ যে\nতারে দশের ভিড়ে ভিড়িয়ে রাখিস নে।\nকোন্\u200c আরেক একা ওরে খোঁজে, সেই তো ওরই দরদ বোঝে-\nযেন\tপথ খুঁজে পায়, কাজের ফাঁকে ফিরে না যায় সে॥";
        this.String_28 = "রাগ: ইমন\nতাল: তেওরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nআমার জীর্ণ পাতা যাবার বেলায় বারে বারে\nডাক দিয়ে যায় নতুন পাতার দ্বারে দ্বারে।\nতাই তো আমার এই জীবনের বনচ্ছায়ে\nফাগুন আসে ফিরে ফিরে দখিন বায়ে,\nনতুন সুরে গান উড়ে যায় আকাশ পারে,\nনতুন রঙে ফুল ফোটে তাই ভারে ভারে॥\nওগো আমার নিত্য নূতন দাঁড়াও হেসে\nচলব তোমার নিমন্ত্রণে নবীন বেশে।\nদিনের শেষে নিবল যখন পথের আলো,\nসাগরতীরে যাত্রা আমার যেই ফুরাল,\nতোমার বাঁশি বাজে সাঁঝের অন্ধকারে-\nশূন্যে আমার উঠল তারা সারে সারে॥";
        this.String_29 = "রাগ: ইমন\nতাল: ত্রিতাল\n\n\nএ শুধু অলস মায়া, এ শুধু মেঘের খেলা,\nএ শুধু মনের সাধ বাতাসেতে বিসর্জন।\nএ শুধু আপনমনে মালা গেঁথে ছিঁড়ে ফেলা,\nনিমেষের হাসিকান্না গান গেয়ে সমাপন।\nশ্যামল পল্লবপাতে রবিকরে সারা বেলা\nআপনারই ছায়া লয়ে খেলা করে ফুলগুলি-\nএও সেই ছায়াখেলা বসন্তের সমীরণে।\nকুহকের দেশে যেন সাধ ক'রে পথ ভুলি\nহেথা হোথা ঘুরি ফিরি সারা দিন আনমনে।\nকারে যেন দেব' ব'লে কোথা যেন ফুল তুলি-\nসন্ধ্যায় মলিন ফুল উড়ে যায় বনে বনে।\nএ খেলা খেলিবে, হায়, খেলার সাথি কে আছে।\nভুলে ভুলে গান গাই- কে শোনে, কে নাই শোনে-\nযদি কিছু মনে পড়ে, যদি কেহ আসে কাছে॥";
        this.String_30 = "রাগ: বাউল\nতাল: দাদরা\n\n\nযে আমি ওই ভেসে চলে\tকালের ঢেউয়ে আকাশতলে\nওরই পানে দেখছি আমি চেয়ে।\nধুলার সাথে, জলের সাথে,\tফুলের সাথে, ফলের সাথে,\nসবার সাথে চলছে ও যে ধেয়ে॥\nও যে সদাই বাইরে আছে,\tদুঃখে সুখে নিত্য নাচে-\nঢেউ দিয়ে যায়, দোলে যে ঢেউ খেয়ে।\nএকটু ক্ষয়ে ক্ষতি লাগে,\tএকটু ঘায়ে ক্ষত জাগে-\nওরই পানে দেখছি আমি চেয়ে॥\nযে আমি যায় কেঁদে হেসে\tতাল দিতেছে মৃদঙ্গে সে,\nঅন্য আমি উঠতেছি গান গেয়ে।\nও যে সচল ছবির মতো,\tআমি নীরব কবির মতো-\nওরই পানে দেখছি আমি চেয়ে।\nএই- যে আমি ঐ আমি নই,\tআপন- মাঝে আপনি যে রই,\nযাই নে ভেসে মরণধারা বেয়ে-\nমুক্ত আমি তৃপ্ত আমি,\tশান্ত আমি, দীপ্ত আমি,\nওরই পানে দেখছি আমি চেয়ে॥";
        this.String_31 = "রাগ: ইমন- পূরবী\nতাল: দাদরা\n\n\nদিনগুলি মোর সোনার খাঁচায় রইল না-\nসেই- যে আমার নানা রঙের দিনগুলি।\nকান্নাহাসির বাঁধন তারা সইল না-\nসেই- যে আমার নানা রঙের দিনগুলি॥\nআমার প্রাণের গানের ভাষা\nশিখবে তারা ছিল আশা-\nউড়ে গেল, সকল কথা কইল না-\nসেই- যে আমার নানা রঙের দিনগুলি॥\nস্বপন দেখি, যেন তারা কার আশে\nফেরে আমার ভাঙা খাঁচার চার পাশে-\nসেই- যে আমার নানা রঙের দিনগুলি।\nএত বেদন হয় কি ফাঁকি।\nওরা কি সব ছায়ার পাখি।\nআকাশ- পারে কিছুই কি গো বইল না-\nসেই- যে আমার নানা রঙের দিনগুলি॥";
        this.String_32 = "রাগ: বেহাগ\nতাল: দাদরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nতরীতে পা দিই নি আমি, পারের পানে যাই নি গো।\nঘাটেই বসে কাটাই বেলা, আর কিছু তো চাই নি গো॥\nতোরা যাবি রাজার পুরে অনেক দূরে,\nতোদের রথের চাকার সুরে\nআমার সাড়া পাই নি গো॥\nআমার এ যে গভীর জলে খেয়া বাওয়া,\nহয়তো কখন্\u200c নিসুত রাতে উঠবে হাওয়া।\nআসবে মাঝি ও পার হতে উজান স্রোতে,\nসেই আশাতেই চেয়ে আছি- তরী আমার বাই নি গো॥";
        this.String_33 = "রাগ: খাম্বাজ- বাউল\nতাল: দাদরা\nস্বরলিপিকার: সুরেন্দ্রনাথ বন্দ্যোপাধ্যায়\n\n\nআমি\tফিরব না রে, ফিরব না আর, ফিরব না রে-\nএমন\tহাওয়ার মুখে ভাসল তরী,\nকূলে\tভিড়ব না আর, ভিড়ব না রে॥\nছড়িয়ে গেছে সুতো ছিঁড়ে,\tতাই খুঁটে আজ মরব কি রে-\nএখন\tভাঙা ঘরের কুড়িয়ে খুঁটি\nবেড়া\tঘিরব না আর, ঘিরব না রে॥\nঘাটের রশি গেছে কেটে,\tকাঁদব কি তাই বক্ষ ফেটে-\nএখন\tপালের রশি ধরব কষি,\nএ রশি ছিঁড়ব না আর ছিঁড়ব না রে!";
        this.String_34 = "রাগ: খাম্বাজ\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nআয়\tআয় রে পাগল, ভুলবি রে চল্\u200c আপনাকে,\nতোর\tএকটুখানির আপনাকে॥\nতুই\tফিরিস নে আর এই চাকাটার ঘুরপাকে॥\nকোন্\u200c\tহঠাৎ হাওয়ার ঢেউ উঠে\nতোর\tঘরের আগল যায় টুটে,\nওরে\tসুযোগ ধরিস, বেরিয়ে পড়িস সেই ফাঁকে-\nতোর দুয়ার- ভাঙার সেই ফাঁকে॥\nনানান গোলে তুফান তোলে চার দিকে-\nতুই\tবুঝিস নে, মন, ফিরবি কখন কার দিকে।\nতোর\tআপন বুকের মাঝখানে\nকী যে\tবাজায় কে যে সেই জানে-\nওরে\tপথের খবর মিলবে রে তোর সেই ডাকে-\nতোর\tআপন বুকের সেই ডাকে॥";
        this.String_35 = "রাগ: পিলু- দেশ- মূলতান\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nকোন্\u200c সুদূর হতে আমার মনোমাঝে\nবাণীর ধারা বহে- আমার প্রাণে প্রাণে।\nআমি\tকখন্\u200c শুনি, কখন্\u200c শুনি না যে,\nকখন্\u200c কী যে কহে- আমার কানে কানে॥\nআমার ঘুমে আমার কোলাহলে\nআমার আঁখি- জলে তাহারি সুর,\nতাহারি সুর জীবন- গুহাতলে\nগোপন গানে রহে- আমার কানে কানে॥\nকোন্\u200c ঘন গহন বিজন তীরে তীরে\nতাহার ভাঙা গড়া- ছায়ার তলে তলে।\nআমি জানি না কোন্\u200c দক্ষিণসমীরে\nতাহার ওঠা পড়া- ঢেউয়ের ছলোছলে।\nএই\tধরণীরে গগন- পারের ছাঁদে সে যে তারার সাথে বাঁধে,\nসুখের সাথে দুখ মিলায়ে কাঁদে\n'এ নহে এই নহে- নহে নহে, এ নহে এই নহে'-\nকাঁদে কানে কানে॥";
        this.String_36 = "রাগ: ইমন- বাউল\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nআকাশ হতে আকাশ- পথে হাজার স্রোতে\nঝরছে জগৎ ঝরনাধারার মতো॥\nআমার শরীর মনের অধীর ধারা সাথে সাথে বইছে অবিরত।\nদুই প্রবাহের ঘাতে ঘাতে উঠতেছে গান দিনে রাতে,\nসেই গানে গানে আমার প্রাণে ঢেউ লেগেছে কত।\nআমার হৃদয়তটে চূর্ণ সে গান ছড়ায় শত শত।\nওই\tআকাশ- ডোবা ধারার দোলায় দুলি অবিরত॥\nএই\tনৃত্য- পাগল ব্যাকুলতা বিশ্বপরানে\nনিত্য আমায় জাগিয়ে রাখে, শান্তি না মানে।\nচিরদিনের কান্নাহাসি উঠছে ভেসে রাশি রাশি-\nএ- সব দেখতেছে কোন্\u200c নিদ্রাহারা নয়ন অবনত।\nওগো, সেই নয়নে নয়ন আমার হোক- না নিমেষহত-\nওই\tআকাশ- ভরা দেখার সাথে দেখব অবিরত॥";
        this.String_37 = "রাগ: ভৈরবী\nতাল: ষষ্ঠী\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nআলোক- চোরা লুকিয়ে এল ওই-\nতিমিরজয়ী বীর, তোরা আজ কই।\nএই কুয়াশা- জয়ের দীক্ষা কাহার কাছে লই॥\nমলিন হল শুভ্র বরন, অরুণ- সোনা করল হরণ,\nলজ্জা পেয়ে নীরব হল উষা জ্যোতির্ময়ী॥\nসুপ্তিসাগরতীরে বেয়ে সে এসেছে মুখ ঢেকে,\nঅঙ্গে কালি মেখে।\nরবির রশ্মি কই গো তোরা, কোথায় আঁধার- ছেদন ছোরা,\nউদয়শৈলশৃঙ্গ হতে বল্\u200c \"মাভৈঃ মাভৈঃ'॥";
        this.String_38 = "রাগ: রামকেলী\nতাল: কাহারবা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nজাগ' আলসশয়নবিলগ্ন।\nজাগ' তামসগহননিমগ্ন॥\nধৌত করুক করুণারুণবৃষ্টি সুপ্তিজড়িত যত আবিল দৃষ্টি,\nজাগ' দুঃখভারনত উদ্যমভগ্ন॥\nজ্যোতিসম্পদ তরি দিক চিত্ত\tধনপ্রলোভননাশন বিত্ত,\nজাগ' পুণ্যবসন পর' লজ্জিত নগ্ন॥";
        this.String_39 = "রাগ: সাহানা\nতাল: দাদরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nতোমার আসন শূন্য আজি, হে বীর পূর্ণ করো,\nঐ যে দেখি বসুন্ধরা কাঁপল থরোথরো।\nবাজল তূর্য আকাশপথে- সূর্য আসেন অগ্নিরথে\tআকাশপথে,\nএই প্রভাতে দখিন হাতে বিজয়খড়্গ ধরো।\nধর্ম তোমার সহায়, তোমার সহায় বিশ্ববাণী।\nঅমর বীর্য সহায় তোমার, সহায় বজ্রপাণি।\nদুর্গম পথ সগৌরবে\tতোমার চরণচিহ্ন লবে\tসগৌরবে-\nচিত্তে অভয় বর্ম, তোমার বক্ষে তাহাই পরো॥";
        this.String_40 = "রাগ: ইমনকল্যাণ\nতাল: একতাল\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nমোরা\tসত্যের 'পরে মন আজি করিব সমর্পণ।\nজয় জয় সত্যের জয়।\nমোরা\tবুঝিব সত্য, পূজিব সত্য, খুঁজিব সত্যধন।\nজয় জয় সত্যের জয়।\nযদি\tদুঃখে দহিতে হয় তবু মিথ্যাচিন্তা নয়।\nযদি\tদৈন্য বহিতে হয় তবু মিথ্যাকর্ম নয়।\nযদি\tদণ্ড সহিতে হয় তবু মিথ্যাবাক্য নয়।\nজয় জয় সত্যের জয়॥\n\nমোরা\tমঙ্গলকাজে প্রাণ আজি করিব সকলে দান।\nজয় জয় মঙ্গলময়।\nমোরা\tলভিব পুণ্য, শোভিব পুণ্যে, গাহিব পুণ্যগান।\nজয় জয় মঙ্গলময়।\nযদি\tদুঃখে দহিতে হয় তবু অশুভচিন্তা নয়।\nযদি\tদৈন্য বহিতে হয় তবু অশুভকর্ম নয়।\nযদি\tদণ্ড সহিতে হয়\tতবু অশুভবাক্য নয়।\nজয় জয় মঙ্গলময়॥\n\nসেই\tঅভয় ব্রহ্মনাম আজি মোরা সবে লইলাম-\nযিনি সকল ভয়ের ভয়।\nমোরা\tকরিব না শোক যা হবার হোক, চলিব ব্রহ্মধাম।\nজয় জয় ব্রহ্মের জয়।\nযদি\tদুঃখে দহিতে হয় তবু নাহি ভয়, নাহি ভয়।\nযদি\tদৈন্য বহিতে হয় তবু নাহি ভয়, নাহি ভয়।\nযদি\tমৃত্যু নিকট হয় তবু নাহি ভয়, নাহি ভয়।\nজয় জয় ব্রহ্মের জয়॥\n\nমোরা\tআনন্দ- মাঝে মন আজি করিব বিসর্জন।\nজয় জয় আনন্দময়।\nসকল দৃশ্যে সকল বিশ্বে আনন্দনিকেতন।\nজয় জয় আনন্দময়।\nআনন্দ চিত্ত- মাঝে আনন্দ সর্বকাজে,\nআনন্দ সর্বকালে দুঃখে বিপদজালে,\nআনন্দ সর্বলোকে মৃত্যুবিরহে শোকে-\nজয় জয় আনন্দময়॥";
        this.String_41 = "রাগ: ইমন\nতাল: দাদরা\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\n\nআমাদের\tশান্তিনিকেতন আমাদের সব হতে আপন।\nতার\tআকাশ- ভরা কোলে মোদের দোলে হৃদয় দোলে,\nমোরা\tবারে বারে দেখি তারে নিত্যই নূতন॥\nমোদের\tতরুমূলের মেলা, মোদের খোলা মাঠের খেলা,\nমোদের\tনীল গগনের সোহাগ- মাখা সকাল- সন্ধ্যাবেলা।\nমোদের\tশালের ছায়াবীথি বাজায় বনের কলগীতি,\nসদাই\tপাতার নাচে মেতে আছে আম্\u200cলকী- কানন॥\nআমরা\tযেথায় মরি ঘুরে সে যে যায় না কভু দূরে,\nমোদের\tমনের মাঝে প্রেমের সেতার বাঁধা যে তার সুরে।\nমোদের\tপ্রাণের সঙ্গে প্রাণে সে যে মিলিয়েছে এক তানে,\nমোদের\tভাইয়ের সঙ্গে ভাইকে সে যে করেছে এক- মন॥";
        this.String_42 = "রাগ: ইমনকল্যাণ\nতাল: দাদরা\nরচনাস্থান: সুরুল\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nনা গো,\tএই যে ধুলা আমার না এ।\nতোমার ধুলার ধরার 'পরে উড়িয়ে যাব সন্ধ্যাবায়ে॥\nদিয়ে মাটি আগুন জ্বালি রচলে দেহ পূজার থালি-\nশেষ আরতি সারা ক'রে ভেঙে যাব তোমার পায়ে॥\nফুল যা ছিল পূজার তরে\nযেতে পথে ডালি হতে অনেক যে তার গেছে পড়ে।\nকত প্রদীপ এই থালাতে সাজিয়েছিলে আপন হাতে-\nকত যে তার নিবল হাওয়ায়, পৌঁছল না চরণছায়ে॥";
        this.String_43 = "রাগ: ইমন\nতাল: দাদরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nজীবন আমার চলছে যেমন তেমনি ভাবে\nসহজ কঠিন দ্বন্দ্বে ছন্দে চলে যাবে॥\nচলার পথে দিনে রাতে দেখা হবে সবার সাথে-\nতাদের আমি চাব, তারা আমায় চাবে॥\nজীবন আমার পলে পলে এমনি ভাবে\nদুঃখসুখের রঙে রঙে রঙিয়ে যাবে॥\nরঙের খেলার সেই সভাতে খেলে যে জন সবার সাথে\nতারে আমি চাব, সেও আমায় চাবে॥";
        this.String_44 = "রাগ: ইমন- কীর্তন\nতাল: কাহারবা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: রমা কর\n\n\nকী পাই নি তারি হিসাব মিলাতে মন মোর নহে রাজি।\nআজ হৃদয়ের ছায়াতে আলোতে বাঁশরি উঠেছে বাজি॥\nভালোবেসেছিনু এই ধরণীরে সেই স্মৃতি মনে আসে ফিরে ফিরে,\nকত বসন্তে দখিনসমীরে ভরেছে আমারি সাজি॥\nনয়নের জল গভীর গহনে আছে হৃদয়ের স্তরে,\nবেদনার রসে গোপনে গোপনে সাধনা সফল করে।\nমাঝে মাঝে বটে ছিঁড়েছিল তার, তাই নিয়ে কেবা করে হাহাকার-\nসুর তবু লেগেছিল বারে- বার মনে পড়ে তাই আজি॥";
        this.String_45 = "রচনাস্থান: শিলাইদহ\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nআমি সব নিতে চাই,\tসব নিতে ধাই রে।\nআমি\tআপনাকে, ভাই, মেলব যে বাইরে॥\nপালে আমার লাগল হাওয়া, হবে আমার সাগর- যাওয়া,\nঘাটে তরী নাই বাঁধা নাই রে॥\nসুখে দুখে বুকের মাঝে\tপথের বাঁশি কেবল বাজে,\nসকল কাজে শুনি যে তাই রে।\nপাগ্\u200cলামি আজ লাগল পাখায়, পাখি কি আর থাকবে শাখায়।\nদিকে দিকে সাড়া যে পাই রে॥";
        this.String_46 = "রাগ: ইমন\nতাল: দাদরা\nরচনাস্থান: শিলাইদহ\nস্বরলিপিকার: ভীমরাও শাস্ত্রী\n\n\nআলো আমার, আলো ওগো, আলো ভুবন- ভরা।\nআলো নয়ন- ধোওয়া আমার, আলো হৃদয়- হরা॥\nনাচে আলো নাচে, ও ভাই,\tআমার প্রাণের কাছে-\nবাজে আলো বাজে, ও ভাই\tহৃদয়বীণার মাঝে-\nজাগে আকাশ, ছোটে বাতাস, হাসে সকল ধরা॥\nআলোর স্রোতে পাল তুলেছে হাজার প্রজাপতি।\nআলোর ঢেউয়ে উঠল নেচে মল্লিকা মালতী।\nমেঘে মেঘে সোনা, ও ভাই,\tযায় না মানিক গোনা-\nপাতায় পাতায় হাসি, ও ভাই,\tপুলক রাশি রাশি-\nসুরনদীর কূল ডুবেছে সুধা- নিঝর- ঝরা॥";
        this.String_47 = "রাগ: পিলু\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nওরে ওরে ওরে, আমার মন মেতেছে,\nতারে আজ থামায় কে রে।\nসে যে আকাশ- পানে হাত পেতেছে,\nতারে আজ নামায় কে রে।\nওরে ওরে ওরে, আমার মন মেতেছে, আমারে থামায় কে রে॥\nওরে ভাই, নাচ্\u200c রে ও ভাই, নাচ্\u200c রে-\nআজ ছাড়া পেয়ে বাঁচ্\u200c রে-\nলাজ ভয় ঘুচিয়ে দে রে।\nতোরে আজ থামায় কে রে॥";
        this.String_48 = "রাগ: ইমন- ভূপালী\nতাল: একতাল\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nহারে রে রে রে রে, আমায় ছেড়ে দে রে, দে রে-\nযেমন ছাড়া বনের পাখি মনের আনন্দে রে॥\nঘনশ্রাবণধারা যেমন বাঁধনহারা,\nবাদল- বাতাস যেমন ডাকাত আকাশ লুটে ফেরে॥\nহারে রে রে রে রে, আমায় রাখবে ধ'রে কে রে-\nদাবানলের নাচন যেমন সকল কানন ঘেরে,\nবজ্র যেমন বেগে গর্জে ঝড়ের মেঘে,\nঅট্টহাস্যে সকল বিঘ্ন- বাধার বক্ষ চেরে॥";
        this.String_49 = "রাগ: পিলু\nতাল: তেওরা\nস্বরলিপিকার: ভীমরাও শাস্ত্রী\n\n\nআনন্দেরই সাগর হতে এসেছে আজ বান।\nদাঁড় ধ'রে আজ বোস্\u200c রে সবাই, টান রে সবাই টান॥\nবোঝা যত বোঝাই করি করব রে পার দুখের তরী,\nঢেউয়ের 'পরে ধরব পাড়ি- যায় যদি যাক প্রাণ॥\nকে ডাকে রে পিছন হতে, কে করে রে মানা,\nভয়ের কথা কে বলে আজ- ভয় আছে সব জানা।\nকোন্\u200c শাপে কোন্\u200c গ্রহের দোষে\tসুখের ডাঙায় থাকব বসে।\nপালের রশি ধরব কষি, চলব গেয়ে গান॥";
        this.String_50 = "রাগ: ইমন\nতাল: কাহারবা\nরচনাস্থান: O & E Hotel, পিনাঙ\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nখরবায়ু বয় বেগে, চারি দিক ছায় মেঘে,\nওগো নেয়ে, নাওখানি বাইয়ো।\nতুমি কষে ধরো হাল, আমি তুলে বাঁধি পাল-\nহাঁই মারো, মারো টান হাঁইয়ো॥\nশৃঙ্খলে বারবার ঝন্\u200cঝন্\u200c ঝঙ্কার, নয় এ তো তরণীর ক্রন্দন শঙ্কার-\nবন্ধন দুর্বার সহ্য না হয় আর, টলমল করে আজ তাই ও।\nহাঁই মারো, মারো টান হাঁইয়ো॥\nগণি গণি দিন খন\tচঞ্চল করি মন\nবোলো না, 'যাই কি নাহি যাই রে'।\nসংশয়পারাবার\tঅন্তরে হবে পার,\nউদ্\u200cবেগে তাকায়ো না বাইরে।\nযদি মাতে মহাকাল, উদ্দাম জটাজাল ঝড়ে হয় লুণ্ঠিত, ঢেউ উঠে উত্তাল,\nহোয়ো নাকো কুণ্ঠিত, তালে তার দিয়ো তাল- জয়- জয় জয়গান গাইয়ো।\nহাঁই মারো, মারো টান হাঁইয়ো॥";
        this.String_51 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nযুদ্ধ যখন বাধিল অচলে চঞ্চলে\nঝঙ্কারধ্বনি রণিল কঠিন শৃঙ্খলে,\nবন্ধমোচন ছন্দে তখন নেমে এলে নির্ঝরিণী-\nতোমারে চিনি, তোমারে চিনি॥\nসিন্ধুমিলনসঙ্গীতে\nমাতিয়া উঠেছ পাষাণশাসন লঙ্ঘিতে\nঅধীর ছন্দে ওগো মহাবিদ্রোহিণী-\nতোমারে চিনি, তোমারে চিনি॥\nহে নিঃশঙ্কিতা,\nআত্ম- হারানো রুদ্রতালের নূপুরঝঙ্কৃতা,\nমৃত্যুতোরণতরণ- চরণ- চারিণী\nচিরদিন অভিসারিণী,\nতোমারে চিনি॥";
        this.String_52 = "রাগ: কীর্তন\nতাল: দাদরা\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nগগনে গগনে ধায় হাঁকি\nবিদ্যুতবাণী বজ্রবাহিনী বৈশাখী,\nস্পর্ধাবেগের ছন্দ জাগায় বনস্পতির শাখাতে॥\nশূন্যমদের নেশায় মাতাল ধায় পাখি,\nঅলখ পথের ছন্দ উড়ায় মুক্তবেগের পাখাতে॥\nঅন্তরতল মন্থন করে ছন্দে\nসাদা কালোর দ্বন্দ্বে,\nকভু ভালো কভু মন্দে,\nকভু সোজা কভু বাঁকাতে।\nছন্দ নাচিল হোমবহ্নির তরঙ্গে,\nমুক্তিরণের যোদ্\u200cধৃবীরের ভ্রুভঙ্গে,\nছন্দ ছুটিল প্রলয়পথের রুদ্ররথের চাকাতে॥";
        this.String_53 = "রাগ: ইমন\nতাল: কাহারবা\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nভাঙো বাঁধ ভেঙে দাও, বাঁধ ভেঙে দাও, বাঁধ ভেঙে দাও।\nবন্দী প্রাণ মন হোক উধাও॥\nশুকনো গাঙে আসুক\nজীবনের বন্যার উদ্দাম কৌতুক-\nভাঙনের জয়গান গাও।\nজীর্ণ পুরাতন যাক ভেসে যাক,\nযাক ভেসে যাক, যাক ভেসে যাক।\nআমরা শুনেছি ওই\tমাভৈঃ মাভৈঃ মাভৈঃ\nকোন্\u200c নূতনেরই ডাক।\nভয় করি না অজানারে,\nরুদ্ধ তাহারি দ্বারে\tদুর্দাড় বেগে ধাও॥";
        this.String_54 = "রাগ: ইমন- কীর্তন\nতাল: কাহারবা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nওই সাগরের ঢেউয়ে ঢেউয়ে বাজল ভেরী, বাজল ভেরী।\nকখন্\u200c আমার খুলবে দুয়ার- নাইকো দেরি, নাইকো দেরি॥\nতোমার তো নয় ঘরের মেলা, কোণের খেলা গো-\nতোমার সঙ্গে বিষম রঙ্গে জগৎ জুড়ে ফেরাফেরি॥\nমরণ তোমার পারের তরী, কাঁদন তোমার পালের হাওয়া-\nতোমার বীণা বাজায় প্রাণে বেরিয়ে যাওয়া, হারিয়ে যাওয়া।\nভাঙল যাহা পড়ল ধুলায়\tযাক্\u200c- না চুলায় গো-\nভরল যা তাই দেখ্\u200c- না, রে ভাই, বাতাস ঘেরি, আকাশ ঘেরি॥";
        this.String_55 = "রাগ: কাফি\nতাল: নবতাল\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nদুয়ার মোর পথপাশে, সদাই তারে খুলে রাখি।\nকখন্\u200c তোর রথ আসে ব্যাকুল হয়ে জাগে আঁখি॥\nশ্রাবণে শুনি দূর মেঘে লাগায় গুরু গরো- গরো,\nফাগুনে শুনি বায়ুবেগে জাগায় মৃদু মরো- মরো-\nআমার বুকে উঠে জেগে চমক তারি থাকি থাকি॥\nসবাই দেখি যায় চলে পিছন- পানে নাহি চেয়ে\nউতল রোলে কল্লোলে পথের গান গেয়ে গেয়ে।\nশরৎ- মেঘ যায় ভেসে উধাও হয়ে কত দূরে\nযেথায় সব পথ মেশে গোপন কোন্\u200c সুরপুরে।\nস্বপনে ওড়ে কোন্\u200c দেশে উদাস মোর মনোপাখি॥";
        this.String_56 = "রাগ: পিলু- বাউল\nতাল: দাদরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nনাহয় তোমার যা হয়েছে তাই হল।\nআরো কিছু নাই হল, নাই হল, নাই হল॥\nকেউ যা কভু দেয় না ফাঁকি সেইটুকু তোর থাক্\u200c- না বাকি,\nপথেই না হয় ঠাঁই হল॥\nচল্\u200c রে সোজা বীণার তারে ঘা দিয়ে,\nডাইনে বাঁয়ে দৃষ্টি তোমার না দিয়ে।\nহারিয়ে চলিস পিছনেরে, সামনে যা পাস কুড়িয়ে নে রে-\nখেদ কী রে তোর যাই হল॥";
        this.String_57 = "রাগ: পঞ্চম\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nসে কোন্\u200c\tবনের হরিণ ছিল আমার মনে।\nকে তারে\tবাঁধল অকারণে॥\nগতিরাগের সে ছিল গান, আলোছায়ার সে ছিল প্রাণ,\nআকাশকে সে চমকে দিত বনে\nমেঘলা দিনের আকুলতা বাজিয়ে যেত পায়ে\nতমাল ছায়ে- ছায়ে।\nফাল্গুনে সে পিয়ালতলায়\tকে জানিত কোথায় পলায়\nদখিন- হাওয়ার চঞ্চলতার সনে॥";
        this.String_58 = "রাগ: বিলাতি ভাঙা\nতাল: কাহারবা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nতোমার হল শুরু, আমার হল সারা-\nতোমায় আমায় মিলে এমনি বহে ধারা॥\nতোমার জ্বলে বাতি তোমার ঘরে সাথি-\nআমার তরে রাতি, আমার তরে তারা॥\nতোমার আছে ডাঙা, আমার আছে জল-\nতোমার বসে থাকা, আমার চলাচল।\nতোমার হাতে রয়, আমার হাতে ক্ষয়-\nতোমার মনে ভয়, আমার ভয় হারা॥";
        this.String_59 = "রাগ: ইমন- পূরবী\nতাল: তেওরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nএমনি ক'রেই যায় যদি দিন যাক না।\nমন উড়েছে উড়ুক- না রে মেলে দিয়ে গানের পাখ্\u200cনা॥\nআজকে আমার প্রাণ ফোয়ারার সুর ছুটেছে,\nদেহের\tবাঁধ টুটেছে-\nমাথার 'পরে খুলে গেছে আকাশের ওই সুনীল ঢাক্\u200cনা॥\nধরণী আজ মেলেছে তার হৃদয়খানি,\nসে যেন রে কাহার বাণী।\nকঠিন মাটি মনকে আজি দেয় না বাধা।\nসে কোন্\u200c সুরে সাধা-\nবিশ্ব বলে মনের কথা, কাজ প'ড়ে আজ থাকে থাক্\u200c- না॥";
        this.String_60 = "রাগ: রামকেলী\nতাল: দাদরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nআমারে\tবাঁধবি তোরা সেই বাঁধন কি তোদের আছে।\nআমি যে\tবন্দী হতে সন্ধি করি সবার কাছে॥\nসন্ধ্যা আকাশ বিনা ডোরে বাঁধল মোরে গো,\nনিশিদিন বন্ধহারা নদীর ধারা আমায় যাচে।\nযে কুসুম\tআপনি ফোটে, আপনি ঝরে, রয় না ঘরে গো-\nতারা যে\tসঙ্গী আমার, বন্ধু আমার, চায় না পাছে॥\nআমারে\tধরবি ব'লে মিথ্যে সাধা।\nআমি যে\tনিজের কাছে নিজের গানের সুরে বাঁধা।\nআপনি যাহার প্রাণ দুলিল, মন ভুলিল গো-\nসে মানুষ\tআগুন- ভরা, পড়লে ধরা সে কি বাঁচে।\nসে যে ভাই,\tহাওয়ার সখা, ঢেউয়ের সাথি, দিবারাতি গো\nকেবলই\tএড়িয়ে চলার ছন্দে তাহার রক্ত নাচে॥";
        this.String_61 = "রাগ: কালাংড়া\nতাল: দাদরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\n\nফিরে ফিরে আমায় মিছে ডাকো স্বামী-\nসময় হল বিদায় নেব আমি॥\nঅপমানে যার সাজায় চিতা\nসে যে বাহির হয়ে এল অগ্নিজিতা।\nরাজাসনের কঠিন অসম্মানে\nধরা দিবে না সে যে মুক্তিকামী॥\nআমায় মাটি নেবে আঁচল পেতে\nবিশ্বজনের চোখের আড়ালেতে,\nতুমি থাকো সোনার সীতার অনুগামী॥";
        this.String_62 = "রাগ: কালাংড়া\nতাল: দাদরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\n\nফুরোলো ফুরোলো এবার পরীক্ষার এই পালা-\nপার হয়েছি আমি অগ্নিদহন- জ্বালা॥\nমা গো মা, মা গো মা, এবার তুমি জাগো মা-\nতোমার কোলে উজাড় করে দেব অপমানের ডালা॥\nতোমার শ্যামল আঁচলখানি আমার অঙ্গে দাও, মা, আনি-\nআমার বুকের থেকে লও খসিয়ে নিঠুর কাঁটার মালা॥";
        this.String_63 = "রাগ: মিশ্র ঝিঁঝিট- বাউল\nতাল: ত্রিতাল\nস্বরলিপিকার: সুরেন্দ্রনাথ বন্দ্যোপাধ্যায়\n\n\nওরে\tশিকল, তোমায় কোলে করে দিয়েছি ঝঙ্কার।\nতুমি\tআনন্দে ভাই রেখেছিলে ভেঙে অহঙ্কার।\nতোমায় নিয়ে ক'রে খেলা\tসুখে দুঃখে কাটল বেলা-\nঅঙ্গ বেড়ি দিলে বেড়ী বিনা দামের অলঙ্কার॥\nতোমার 'পরে করি নে রোষ,\tদোষ থাকে তো আমারি দোষ-\nভয় যদি রয় আপন মনে তোমায় দেখি ভয়ঙ্কর।\nঅন্ধকারে সারা রাতি\tছিলে আমার সাথের সাথি,\nসেই দয়াটি স্মরি তোমায় করি নমস্কার॥";
        this.String_64 = "রাগ: শঙ্করা\nতাল: দাদরা\nস্বরলিপিকার: সুরেন্দ্রনাথ বন্দ্যোপাধ্যায়\n\n\nআমাকে যে বাঁধবে ধরে এই হবে যার সাধন,\nসে কি অমনি হবে।\nআপনাকে সে বাঁধা দিয়ে আমায় দেবে বাঁধন,\nসে কি অমনি হবে॥\nআমাকে যে দুঃখ দিয়ে আনবে আপন বশে,\nসে কি অমনি হবে।\nতার আগে তার পাষাণ হিয়া গলবে করুণ রসে,\nসে কি অমনি হবে।\nআমাকে যে কাঁদাবে তার ভাগ্যে আছে কাঁদন,\nসে কি অমনি হবে॥";
        this.String_65 = "রাগ: ভৈরবী\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nআমি চঞ্চল হে,\nআমি সুদূরের পিয়াসি।\nদিন চলে যায়, আমি আনমনে তারি আশা চেয়ে থাকি বাতায়নে-\nওগো, প্রাণে মনে আমি যে তাহার পরশ পাবার প্রয়াসী॥\nওগো সুদূর, বিপুল সুদূর, তুমি যে বাজাও ব্যাকুল বাঁশরি-\nমোর ডানা নাই, আছি এক ঠাঁই সে কথা যে যাই পাশরি॥\nআমি উন্মনা হে,\nহে সুদূর, আমি উদাসী॥\nরৌদ্র- মাখানো অলস বেলায় তরুমর্মরে ছায়ার খেলায়\nকী মুরতি তব নীল আকাশে নয়নে উঠে গো আভাসি।\nহে সুদূর, আমি উদাসী।\nওগো সুদূর, বিপুল সুদূর, তুমি যে বাজাও ব্যাকুল বাঁশরি-\nকক্ষে আমার রুদ্ধ দুয়ার সে কথা যে যাই পাশরি॥";
        this.String_66 = "রাগ: খাম্বাজ\nতাল: একতাল\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nওরে সাবধানী পথিক, বারেক পথ ভুলে মরো ফিরে।\nখোলা আঁখি- দুটো অন্ধ করে দে আকুল আঁখির নীরে॥\nসে ভোলা পথের প্রান্তে রয়েছে হারানো হিয়ার কুঞ্জ,\nঝ'রে প'ড়ে আছে কাঁটা- তরুতলে রক্তকুসুমপুঞ্জ-\nসেথা দুই বেলা ভাঙা- গড়া- খেলা অকূলসিন্ধুতীরে॥\nঅনেক দিনের সঞ্চয় তোর আগুলি আছিস বসে,\nঝড়ের রাতের ফুলের মতন ঝরুক পড়ুক খসে।\nআয় রে এবার সব- হারাবার জয়মালা পরো শিরে।";
        this.String_67 = "রাগ: ভৈরবী- রামকেলী\nতাল: দাদরা\n\n\nতরী আমার হঠাৎ ডুবে যায়\nকোন্\u200cখানে রে কোন্\u200c পাষাণের ঘায়॥\nনবীন তরী নতুন চলে, দিই নি পাড়ি অগাধ জলে-\nবাহি তারে খেলার ছলে কিনার- কিনারায়॥\nভেসেছিলেম স্রোতের ভরে, একা ছিলেম কর্ণ ধ'রে-\nলেগেছিল পালের 'পরে মধুর মৃদু বায়।\nসুখে ছিলেম আপন- মনে, মেঘ ছিল না গগনকোণে-\nলাগবে তরী কুসুমবনে ছিলেম সেই আশায়॥";
        this.String_68 = "রাগ: বেহাগ\nতাল: একতাল\nস্বরলিপিকার: সরলা দেবী\n\n\nআমি\tকেবলই স্বপন করেছি বপন বাতাসে-\nতাই\tআকাশকুসুম করিনু চয়ন হতাশে॥\nছায়ার মতন মিলায় ধরণী,\tকূল নাহি পায় আশায় তরণী,\nমানসপ্রতিমা ভাসিয়া বেড়ায় আকাশে॥\nকিছু\tবাঁধা পড়িল না কেবলই বাসনা- বাঁধনে।\nকেহ\tনাহি দিল ধরা শুধু এ সুদূর- সাধনে।\nআপনার মনে বসিয়া একেলা অনলশিখায় কী করিনু খেলা,\nদিনশেষে দেখি ছাই হল সব হুতাশে॥";
        this.String_69 = "রাগ: বেহাগ\nতাল: কাহারবা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nশুধু\tযাওয়া আসা, শুধু স্রোতে ভাসা,\nশুধু\tআলো- আঁধারে কাঁদা- হাসা॥\nশুধু\tদেখা পাওয়া, শুধু ছুঁয়ে যাওয়া,\nশুধু\tদূরে যেতে যেতে কেঁদে চাওয়া,\nশুধু\tনব দুরাশায় আগে চ'লে যায়-\nপিছে ফেলে যায় মিছে আশা॥\nঅশেষ বাসনা লয়ে ভাঙা বল,\nপ্রাণপণ কাজে পায় ভাঙা ফল,\nভাঙা তরী ধ'রে ভাসে পারাবারে,\nভাব কেঁদে মরে- ভাঙা ভাষা।\nহৃদয়ে হৃদয়ে আধো পরিচয়,\nআধখানি কথা সাঙ্গ নাহি হয়,\nলাজে ভয়ে ত্রাসে আধো- বিশ্বাসে\nশুধু আধখানি ভালোবাসা॥";
        this.String_70 = "রাগ: বেহাগ- খাম্বাজ\nতাল: ত্রিতাল\n\n\nওগো, তোরা কে যাবি পারে।\nআমি তরী নিয়ে বসে আছি নদীকিনারে॥\nও পারেতে উপবনে\nকত খেলা কত জনে,\nএ পারেতে ধু ধু মরু বারি বিনা রে॥\nএই বেলা বেলা আছে, আয় কে যাবি।\nমিছে কেন কাটে কাল কত কী ভাবি।\nসূর্য পাটে যাবে নেমে,\nসুবাতাস যাবে থেমে,\nখেয়া বন্ধ হয়ে যাবে সন্ধ্যা- আঁধারে॥";
        this.String_71 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\nরচনাস্থান: কলকাতা\n\n\nতোমাদের দান যশের ডালায় সব- শেষ সঞ্চয় আমার-\nনিতে মনে লাগে ভয়॥\nএই রূপলোকে কবে এসেছিনু রাতে,\nগেঁথেছিনু মালা ঝ'রে- পড়া পারিজাতে,\nআঁধারে অন্ধ- এ যে গাঁথা তারি হাতে-\nকী দিল এ পরিচয়॥\nএরে পরাবে কি কলালক্ষ্মীর গলে\nসাতনরী হারে যেথায় মানিক জ্বলে।\nএকদা কখন অমরার উৎসবে\nম্লান ফুলদল খসিয়া পড়িবে কবে,\nএ আদর যদি লজ্জার পরাভবে\nসে দিন মলিন হয়॥";
        this.String_72 = "রাগ: মিশ্র খাম্বাজ\nতাল: কাহারবা\nরচনাস্থান: শিলং\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nদূর রজনীর স্বপন লাগে আজ নূতনের হাসিতে,\nদূর ফাগুনের বেদন জাগে আজ ফাগুনের বাঁশিতে॥\nহায় রে সে কাল হায় রে কখন চলে যায় রে\nআজ এ কালের মরীচিকায় নতুন মায়ায় ভাসিতে॥\nযে মহাকাল দিন ফুরালে আমার কুসুম ঝরালো\nসেই তোমারি তরুণ ভালে ফুলের মালা পরালো।\nশুনিয়ে শেষের কথা সে কাঁদিয়ে ছিল হতাশে,\nতোমার মাঝে নতুন সাজে শূন্য আবার ভরালো।\nআমরা খেলা খেলেছিলেম, আমরাও গান গেয়েছি।\nআমরাও পাল মেলেছিলেম, আমরা তরী বেয়েছি।\nহারায় নি তা হারায় নি বৈতরণী পারায় নি-\nনবীন চোখের চপল আলোয় সে কাল ফিরে পেয়েছি।";
        this.String_73 = "রাগ: শ্রী\nতাল: একতাল\nরচনাস্থান: বোলপুর\nস্বরলিপিকার: সুরেন্দ্রনাথ বন্দ্যোপাধ্যায়\n\n\nওরে মাঝি, ওরে আমার মানবজন্মতরীর মাঝি,\nশুনতে কি পাস দূরের থেকে পারের বাঁশি উঠছে বাজি॥\nতরী কি তোর দিনের শেষে ঠেকবে এবার ঘাটে এসে।\nসেথায় সন্ধ্যা- অন্ধকারে দেয় কি দেখা প্রদীপরাজি॥\nযেন আমার লাগে মনে মন্দ- মধুর এই পবনে\nসিন্ধুপারের হাসিটি কার আঁধার বেয়ে আসছে আজি।\nআসার বেলায় কুসুমগুলি কিছু এনেছিলেম তুলি,\nযেগুলি তার নবীন আছে এই বেলা নে সাজিয়ে সাজি॥";
        this.String_74 = "রাগ: খাম্বাজ- বাউল\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nচোখ যে ওদের ছুটে চলে গো-\nধনের বাটে, মানের বাটে, রূপের হাটে,\tদলে দলে গো॥\nদেখবে ব'লে করেছে পণ,\tদেখবে কারে জানে না মন-\nপ্রেমের দেখা দেখে যখন\tচোখ ভেসে যায় চোখের জলে গো॥\nআমায় তোরা ডাকিস না রে-\nআমি যাব খেয়ার ঘাটে অরূপ- রসের পারাবারে।\nউদাস হাওয়া লাগে পালে, পারের পানে যাবার কালে\nচোখদুটোরে ডুবিয়ে যাব অকূল সুধা- সাগর তলে গো॥";
        this.String_75 = "রাগ: কীর্তন\nতাল: অর্ধঝাঁপ\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nকৃষ্ণকলি আমি তারেই বলি, কালো তারে বলে গাঁয়ের লোক।\nমেঘলা দিনে দেখেছিলেম মাঠে কালো মেঘের কালো হরিণ- চোখ।\nঘোমটা মাথায় ছিল না তার মোটে, মুক্তবেণী পিঠের 'পরে লোটে।\nকালো? তা সে যতই কালো হোক, দেখেছি তার কালো হরিণ- চোখ।\n\nঘন মেঘে আঁধার হল দেখে ডাকতেছিল শ্যামল দুটি গাই,\nশ্যামা মেয়ে ব্যস্ত ব্যাকুল পদে কুটির হতে ত্রস্ত এল তাই।\nআকাশ- পানে হানি যুগল ভুরু শুনলে বারেক মেঘের গুরুগুরু।\nকালো? তা সে যতই কালো হোক, দেখেছি তার কালো হরিণ- চোখ।\n\nপূবে বাতাস এল হঠাৎ ধেয়ে, ধানের ক্ষেতে খেলিয়ে গেল ঢেউ।\nআলের ধারে দাঁড়িয়েছিলেম একা, মাঠের মাঝে আর ছিল না কেউ।\nআমার পানে দেখলে কি না চেয়ে আমি জানি আর জানে সেই মেয়ে।\nকালো? তা সে যতই কালো হোক, দেখেছি তার কালো হরিণ- চোখ।\n\nএমনি করে কালো কাজল মেঘ জ্যৈষ্ঠ মাসে আসে ঈশান কোণে।\nএমনি করে কালো কোমল ছায়া আষাঢ় মাসে নামে তমাল- বনে।\nএমনি করে শ্রাবণ- রজনীতে হঠাৎ খুশি ঘনিয়ে আসে চিতে।\nকালো? তা সে যতই কালো হোক, দেখেছি তার কালো হরিণ- চোখ।\n\nকৃষ্ণকলি আমি তারেই বলি, আর যা বলে বলুক অন্য লোক।\nদেখেছিলেম ময়নাপাড়ার মাঠে কালো মেয়ের কালো হরিণ- চোখ।\nমাথার 'পরে দেয় নি তুলে বাস, লজ্জা পাবার পায় নি অবকাশ।\nকালো? তা সে যতই কালো হোক, দেখেছি তার কালো হরিণ- চোখ॥";
        this.String_76 = "রাগ: কানাড়া\nতাল: কাহারবা\nরচনাস্থান: এলাহাবাদ\n\n\nতুমি কি কেবলই ছবি, শুধু পটে লিখা।\nওই- যে সুদূর নীহারিকা\nযারা করে আছে ভিড় আকাশের নীড়,\nওই যারা দিনরাত্রি\nআলো হাতে চলিয়াছে আঁধারের যাত্রী গ্রহ তারা রবি,\nতুমি কি তাদের মতো সত্য নও।\nহায় ছবি, তুমি শুধু ছবি॥\nনয়নসমুখে তুমি নাই,\nনয়নের মাঝখানে নিয়েছ যে ঠাঁই- আজি তাই\nশ্যামলে শ্যামল তুমি, নীলিমায় নীল।\nআমার নিখিল তোমাতে পেয়েছে তার অন্তরের মিল।\nনাহি জানি, কেহ নাহি জানে-\nতব সুর বাজে মোর গানে,\nকবির অন্তরে তুমি কবি-\nনও ছবি, নও ছবি, নও শুধু ছবি॥";
        this.String_77 = "রাগ: পিলু\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nআজ\tতারায় তারায় দীপ্ত শিখার অগ্নি জ্বলে\nনিদ্রাবিহীন গগনতলে॥\nওই\tআলোক- মাতাল স্বর্গসভার মহাঙ্গন\nহোথায় ছিল কোন্\u200c যুগে মোর নিমন্ত্রণ-\nআমার লাগল না মন লাগল না,\nতাই\tকালের সাগর পাড়ি দিয়ে এলেম চ'লে\nনিদ্রাবিহীন গগনতলে॥\nহেথা\tমন্দমধুর কানাকানি জলে স্থলে\nশ্যামল মাটির ধরাতলে।\nহেথা\tঘাসে ঘাসে রঙিন ফুলের আলিম্পন,\nবনের পথে আঁধার- আলোয় আলিঙ্গন-\nআমার লাগল রে মন লাগল রে,\nতাই\tএইখানেতেই দিন কাটে এই খেলার ছলে\nশ্যামল মাটির ধরাতলে॥";
        this.String_78 = "রাগ: কালাংড়া\nতাল: কাহারবা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nওরে\tপ্রজাপতি, মায়া দিয়ে কে যে পরশ করল তোরে\nঅস্তরবির তুলিখানি চুরি ক'রে॥\nহাওয়ার বুকে যে চঞ্চলের গোপন বাসা\nবনে বনে বয়ে বেড়াস তারি ভাষা,\nঅপ্সরীদের দোলের খেলার ফুলের রেণু\nপাঠায় কে তোর পাখায় ভ'রে॥\nযে গুণী তার কীর্তিনাশার বিপুল নেশায়\nচিকন রেখার লিখন মেলে শূন্যে মেশায়,\nসুর বাঁধে আর সুর যে হারায় পলে পলে-\nগান গেয়ে যে চলে তারা দলে দলে-\nতার হারা সুর নাচের নেশায়\nডানাতে তোর পড়ল ঝরে॥";
        this.String_79 = "রাগ: ইমন- ভূপালী\nতাল: দাদরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nনমো\tযন্ত্র, নমো- যন্ত্র, নমো- যন্ত্র, নমো- যন্ত্র!\nতুমি\tচক্রমুখরমন্দ্রিত, তুমি বজ্রবহ্নিবন্দিত,\nতব\tবস্তুবিশ্ববক্ষোদংশ ধ্বংসবিকট দন্ত॥\nতব\tদীপ্ত- অগ্নি- শত- শতঘ্নী- বিঘ্নবিজয় পন্থ।\nতব\tলৌহগলন শৈলদলন অচলচলন মন্ত্র॥\nকভু\tকাষ্ঠলোষ্ট্র- ইষ্টক দৃঢ় ঘনপিনদ্ধ কায়া,\nকভু\tভূতল- জল- অন্তরীক্ষ- লঙ্ঘন লঘু মায়া।\nতব\tখনি- খনিত্র- নখ- বিদীর্ণ ক্ষিতি বিকীর্ণ- অন্ত্র।\nতব\tপঞ্চভূতবন্ধনকর ইন্দ্রজালতন্ত্র॥";
        this.String_80 = "রাগ: পিলু\nতাল: একতাল\nরচনাস্থান: বোলপুর থেকে কলকাতা যাবার পথে ট্রেনে\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nওগো নদী, আপন বেগে পাগল- পারা,\nআমি স্তব্ধ চাঁপার তরু\tগন্ধভরে তন্দ্রাহারা॥\nআমি সদা অচল থাকি,\tগভীর চলা গোপন রাখি,\nআমার চলা নবীন পাতায়, আমার চলা ফুলের ধারা॥\nওগো নদী, চলার বেগে পাগল- পারা,\nপথে পথে বাহির হয়ে আপন- হারা-\nআমার চলা যায় না বলা- আলোর পানে প্রাণের চলা-\nআকাশ বোঝে আনন্দ তার, বোঝে নিশার নীরব তারা॥";
        this.String_81 = "রাগ: ভৈরবী\nতাল: দাদরা\nরচনাস্থান: চৌরঙ্গী, কলকাতা\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nপ্রাঙ্গণে মোর শিরীষশাখায় ফাগুন মাসে\nকী উচ্ছ্বাসে\nক্লান্তিবিহীন ফুল ফোটানোর খেলা।\nক্ষান্তকূজন শান্তবিজন সন্ধ্যাবেলা\nপ্রত্যহ সেই ফুল্ল শিরীষ প্রশ্ন শুধায় আমায় দেখি\n'এসেছে কি- এসেছে কি।'\n\nআর বছরেই এমনি দিনেই ফাগুন মাসে\nকী উচ্ছ্বাসে\nনাচের মাতন লাগল শিরীষ- ডালে\nস্বর্গপুরের কোন্\u200c নূপুরের তালে।\nপ্রত্যহ সেই চঞ্চল প্রাণ শুধিয়েছিল, 'শুনাও দেখি\nআসে নি কি- আসে নি কি।'\nআবার কখন এমনি দিনেই ফাগুন মাসে\nকী আশ্বাসে\nডালগুলি তার রইবে শ্রবণ পেতে\nঅলখ জনের চরণ- শব্দে মেতে।\nপ্রত্যহ তার মর্মরস্বর বলবে আমায় কী বিশ্বাসে,\n'সে কি আসে- সে কি আসে।'\n\nপ্রশ্ন জানাই পুষ্পবিভোর ফাগুন মাসে\nকী আশ্বাসে,\n'হায় গো, আমার ভাগ্য- রাতের তারা,\nনিমেষ- গণন হয় নি কি মোর সারা।'\nপ্রত্যহ বয় প্রাঙ্গণময় বনের বাতাস এলোমেলো-\n'সে কি এল- সে কি এল।'";
        this.String_82 = "রাগ: কীর্তন\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nহে\tআকাশবিহারী- নীরদবাহন জল,\nআছিল শৈলশিখরে- শিখরে তোমার লীলাস্থল॥\nতুমি\tবরনে বরনে কিরণে কিরণে প্রাতে সন্ধ্যায় অরুণে হিরণে\nদিয়েছ ভাসায়ে পবনে পবনে স্বপনতরণীদল॥\nশেষে শ্যামল মাটির প্রেমে তুমি ভুলে এসেছিলে নেমে,\nকবে\tবাঁধা পড়ে গেলে যেখানে ধরার গভীর তিমিরতল।\nআজ\tপাষাণদুয়ার দিয়েছি টুটিয়া, কত যুগ পরে এসেছ ছুটিয়া\nনীল গগনের হারানো স্মরণ\nগানেতে সমুচ্ছল॥";
        this.String_83 = "রাগ: পিলু- খাম্বাজ\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nযে কেবল পালিয়ে বেড়ায়, দৃষ্টি এড়ায়, ডাক দিয়ে যায় ইঙ্গিতে,\nসে কি আজ দিল ধরা গন্ধে- ভরা বসন্তের এই সঙ্গীতে॥\nও কি তার উত্তরীয় অশোকশাখায় উঠল দুলি।\nআজ কি পলাশবনে ওই সে বুলায় রঙের তুলি।\nও কি তার চরণ পড়ে তালে তালে মল্লিকার ওই ভঙ্গীতে॥\nনা গো না, দেয় নি ধরা, হাসির ভরা দীর্ঘশ্বাসে যায় ভেসে।\nমিছে এই\tহেলা- দোলায় মনকে ভোলায়, ঢেউ দিয়ে যায় স্বপ্নে সে।\nসে বুঝি লুকিয়ে আসে বিচ্ছেদেরই রিক্ত রাতে,\nনয়নের আড়ালে তার নিত্য- জাগার আসন পাতে-\nধেয়ানের বর্ণছটায় ব্যথার রঙে মনকে সে রয় রঙ্গিতে॥";
        this.String_84 = "রাগ: ভৈরবী- রামকেলী\nতাল: দাদরা\n\n\nও কি এল, ও কি এল না, বোঝা গেল না-\nও কি মায়া কি স্বপনছায়া, ও কি ছলনা॥\nধরা কি পড়ে ও রূপেরই ডোরে,\nগানেরই তানে কি বাঁধিবে ওরে-\nও যে চিরবিরহেরই সাধনা॥\nওর বাঁশিতে করুণ কী সুর লাগে\nবিরহমিলনমিলিত রাগে।\nসুখে কি দুখে ও পাওয়া না- পাওয়া,\nহৃদয়বনে ও উদাসী হাওয়া,\nবুঝি শুধু ও পরমকামনা॥";
        this.String_85 = "রাগ: বৃন্দাবনী সারং\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nদূরদেশী সেই রাখাল ছেলে\nআমার বাটে বটের ছায়ায় সারা বেলা গেল খেলে॥\nগাইল কী গান সেই তা জানে, সুর বাজে তার আমার প্রাণে-\nবলো দেখি তোমরা কি তার কথার কিছু আভাস পেলে॥\nআমি তারে শুধাই যবে 'কী তোমারে দিব আনি'-\nসে শুধু কয়, 'আর কিছু নয়, তোমার গলার মালাখানি।'\nদিই যদি তো কী দাম দেবে যায় বেলা সেই ভাব্\u200cনা ভেবে-\nফিরে এসে দেখি ধুলায় বাঁশিটি তার গেছে ফেলে॥";
        this.String_86 = "রাগ: মেঘমল্লার\nতাল: কাহারবা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: সুশীলকুমার ভঞ্জচৌধুরী\n\n\nবাজে গুরু গুরু শঙ্কার ডঙ্কা,\nঝঞ্ঝা ঘনায় দূরে ভীষণ নীরবে।\nকত রব সুখস্বপ্নের ঘোরে আপনা ভুলে-\nসহসা জাগিতে হবে রে॥";
        this.String_87 = "রাগ: ছায়ানট\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nও জোনাকী,\tকী সুখে ওই ডানা দুটি মেলেছ।\nআঁধার সাঁঝে বনের মাঝে উল্লাসে প্রাণ ঢেলেছ॥\nতুমি নও তো সূর্য, নও তো চন্দ্র, তোমার তাই ব'লে কি কম আনন্দ।\nতুমি\tআপন জীবন পূর্ণ ক'রে আপন আলো জ্বেলেছ॥\nতোমার যা আছে তা তোমার আছে, তুমি নও গো ঋণী কারো কাছে,\nতোমার অন্তরে যে শক্তি আছে তারি আদেশ পেলেছ।\nতুমি আঁধার- বাঁধন ছাড়িয়ে ওঠ, তুমি ছোটো হয়ে নও গো ছোটো,\nজগতে যেথায় যত আলো সবায় আপন ক'রে ফেলেছ॥";
        this.String_88 = "রাগ: ভৈরবী\nতাল: দাদরা\nরচনাস্থান: কারোয়ার থেকে ফেরার পথে\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nহ্যাদে গো নন্দরানী, আমাদের শ্যামকে ছেড়ে দাও।\nআমরা রাখাল- বালক দাঁড়িয়ে দ্বারে। আমাদের শ্যামকে দিয়ে যাও॥\nহেরো গো প্রভাত হল, সুয্যি ওঠে, ফুল ফুটেছে বনে।\nআমরা শ্যামকে নিয়ে গোষ্ঠে যাব আজ করেছি মনে।\nওগো, পীত ধড়া পরিয়ে তারে কোলে নিয়ে আয়।\nতার হাতে দিয়ো মোহন বেণু, নূপুর দিয়ো পায়॥\nরোদের বেলায় গাছের তলায় নাচব মোরা সবাই মিলে।\nবাজবে নূপুর রুনুঝুনু, বাজবে বাঁশি মধুর বোলে।\nবনফুলে গাঁথব মালা, পরিয়ে দেব' শ্যামের গলে॥";
        this.String_89 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nআঁধারের লীলা আকাশে আলোকলেখায়- লেখায়,\nছন্দের লীলা অচলকঠিনমৃদঙ্গে।\nঅরূপের লীলা অগোনা রূপের রেখায় রেখায়,\nস্তব্ধ অতল খেলায় তরলতরঙ্গে॥\nআপনারে পাওয়া আপনা- ত্যাগের গভীর লীলায়,\nমূর্তির লীলা মূর্তিবিহীন কঠোর শিলায়,\nশান্ত শিবের লীলা যে প্রলয়ভ্রূভঙ্গে।\nশৈলের লীলা নির্ঝরকলকলিত রোলে,\nশুভ্রের লীলা কত- না রঙ্গে বিরঙ্গে।\nমাটির লীলা যে শস্যের বায়ুহেলিত দোলে,\nআকাশের লীলা উধাও ভাষার বিহঙ্গে।\nস্বর্গের খেলা মর্তের ম্লান ধুলায় হেলায়,\nদুঃখেরে লয়ে আনন্দ খেলে দোলন- খেলায়,\nশৌর্যের খেলা ভীরু মাধুরীর আসঙ্গে॥";
        this.String_90 = "রাগ: মেঘমল্লার\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nদেখা না- দেখায় মেশা হে বিদ্যুৎলতা,\nকাঁপাও ঝড়ের বুকে একি ব্যাকুলতা॥\nগগনে সে ঘুরে ঘুরে খোঁজে কাছে, খোঁজে দূরে-\nসহসা কী হাসি হাস';\tনাহি কহ কথা॥\nআঁধার ঘনায় শূন্যে, নাহি জানে নাম,\nকী রুদ্র সন্ধানে সিন্ধু দুলিছে দুর্দাম।\nঅরণ্য হতাশপ্রাণে আকাশে ললাট হানে,\nদিকে দিকে কেঁদে ফেরে কী দুঃসহ ব্যথা॥";
        this.String_91 = "রাগ: কাফি- খাম্বাজ\nতাল: দাদরা\nরচনাস্থান: কল্যন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nতুমি উষার সোনার বিন্দু প্রাণের সিন্ধুকূলে,\nশরৎ- প্রাতের প্রথম শিশির প্রথম শিউলিফুলে॥\nআকাশপারের ইন্দ্রধনু ধরার পারে নোওয়া,\nনন্দনেরই নন্দিনী গো চন্দ্রলেখায় ছোঁওয়া,\nপ্রতিপদে চাঁদের স্বপন শুভ্র মেঘে ছোঁওয়া-\nস্বর্গলোকের গোপন কথা মর্তে এলে ভুলে॥\nতুমি কবির ধেয়ান- ছবি পূর্বজনম- স্মৃতি,\nতুমি আমার কুড়িয়ে পাওয়া হারিয়ে- যাওয়া গীতি।\nযে কথাটি যায় না বলা কইলে চুপে চুপে,\nতুমি আমার মুক্তি হয়ে এলে বাঁধনরূপে-\nঅমল আলোর কমলবনে ডাকলে দুয়ার খুলে।";
        this.String_92 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\nরচনাস্থান: মিউনিক\n\n\nআকাশ, তোমায় কোন্\u200c রূপে মন চিনতে পারে\nতাই ভাবি যে বারে বারে॥\nগহন রাতের চন্দ্র তোমার মোহন ফাঁদে\nস্বপন দিয়ে মনকে বাঁধে,\nপ্রভাতসূর্য শুভ্র জ্যোতির তরবারে\nছিন্ন করি ফেলে তারে॥\nবসন্তবায় পরান ভুলায় চুপে চুপে,\nবৈশাখী ঝড় গর্জি উঠে রূদ্ররূপে।\nশ্রাবণমেঘের নিবিড় সজল কাজল ছায়া\nদিগ্\u200cদিগন্তে ঘনায় মায়া-\nআশ্বিনে এই অমল আলোর কিরণধারে\nযায় নিয়ে কোন্\u200c মুক্তিপারে॥";
        this.String_93 = "রাগ: মিশ্র সোহিনী\nতাল: দাদরা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nআধেক ঘুমে নয়ন চুমে স্বপন দিয়ে যায়।\nশ্রান্ত ভালে যূথীর মালে পরশে মৃদু বায়॥\nবনের ছায়া মনের সাথি, বাসনা নাহি কিছু-\nপথের ধারে আসন পাতি, না চাহি ফিরে পিছু-\nবেণুর পাতা মিশায় গাথা নীরব ভাবনায়॥\nমেঘের খেলা গগনতটে অলস লিপি- লিখা,\nসুদূর কোন্\u200c স্ময়ণপটে জাগিল মরীচিকা।\nচৈত্রদিনে তপ্ত বেলা তৃণ- আঁচল পেতে\nশূন্যতলে গন্ধ- ভেলা ভাসায় বাতাসেতে-\nকপোত ডাকে মধুকশাখে বিজন বেদনায়॥";
        this.String_94 = "রাগ: রামকেলী\nতাল: ঝম্পক\nরচনাস্থান: করাচি\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nপাখি বলে, 'চাঁপা, আমারে কও,\nকেন তুমি হেন নীরবে রও।\nপ্রাণ ভরে আমি গাহি যে গান\nসারা প্রভাতেরই সুরের দান,\nসে কি তুমি তব হৃদয়ে লও।\nকেন তুমি তবে নীরবে রও।'\nচাঁপা শুনে বলে, 'হায় গো হায়,\nযে আমারই পাওয়া শুনিতে পায়\nনহ নহ পাখি, সে তুমি নও।'\nপাখি বলে, 'চাঁপা আমারে কও,\nকেন তুমি হেন গোপনে রও।\nফাগুনের প্রাতে উতলা বায়\nউড়ে যেতে সে যে ডাকিয়া যায়,\nসে কি তুমি তব হৃদয়ে লও।\nকেন তুমি তবে গোপনে রও।'\nচাঁপা শুনে বলে, 'হায় গো হায়,\nযে আমারই ওড়া দেখিতে পায়\nনহ নহ পাখি, সে তুমি নও।'";
        this.String_95 = "রাগ: পিলু\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nমাটির বুকের মাঝে বন্দী যে জল মিলিয়ে থাকে\nমাটি\tপায় না, পায় না, মাটি পায় না তাকে॥\nকবে\tকাটিয়ে বাঁধন পালিয়ে যখন যায় সে দূরে\nআকাশপুরে গো,\nতখন কাজল মেঘের সজল ছায়া শূন্যে আঁকে,\nসুদূর\tশূন্যে আঁকে-\nমাটি\tপায় না, পায় না, মাটি পায় না তাকে॥\nশেষে বজ্র তারে বাজায় ব্যথা বহ্নিজ্বালায়,\nঝঞ্ঝা তারে দিগ্\u200cবিদিকে কাঁদিয়ে চালায়।\nতখন কাছের ধন যে দূরের থেকে কাছে আসে\nবুকের পাশে গো,\nতখন চোখের জলে নামে সে যে চোখের জলের ডাকে,\nআকুল\tচোখের জলের ডাকে-\nমাটি\tপায় রে, পায় রে, মাটি পায় রে তাকে॥";
        this.String_96 = "রাগ: ইমনকল্যাণ\nতাল: দাদরা\nরচনাস্থান: শ্রীনিকেতন\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nআমি সন্ধ্যাদীপের শিখা,\nঅন্ধকারের ললাট- মাঝে পরানু রাজটিকা॥\nতার\tস্বপনে মোর আলোর পরশ জাগিয়ে দিল গোপন হরষ,\nঅন্তরে তার রইল আমার প্রথম প্রেমের লিখা॥\nআমার নির্জন উৎসবে\nঅম্বরতল হয় নি উতল পাখির কলরবে।\nযখন\tতরুণ রবির চরণ লেগে নিখিল ভুবন উঠবে জেগে\nতখন আমি মিলিয়ে যাব ক্ষণিক মরীচিকা॥";
        this.String_97 = "রাগ: বাউল\nতাল: ত্রিতাল\n\n\nমাটির প্রদীপখানি আছে মাটির ঘরের কোলে,\nসন্ধ্যাতারা তাকায় তারি আলো দেখবে ব'লে॥\nসেই আলোটি নিমেষহত\tপ্রিয়ার ব্যাকুল চাওয়ার মতো,\nসেই আলোটি মায়ের প্রাণের ভয়ের মতো দোলে॥\nসেই আলোটি নেবে জ্বলে\tশ্যামল ধরার হৃদয়তলে,\nসেই আলোটি চপল হাওয়ায় ব্যথায় কাঁপে পলে পলে।\nনামল সন্ধ্যাতারার বাণী\tআকাশ হতে আশিস আনি,\nঅমরশিখা আকুল হল মর্তশিখায় উঠতে জ্ব'লে॥";
        this.String_98 = "রাগ: ছায়ানট\nতাল: একতাল\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\n\nআমি\tতোমারি মাটির কন্যা, জননী বসুন্ধরা-\nতবে\tআমার মানবজন্ম\tকেন বঞ্চিত করা॥\nপবিত্র জানি যে তুমি পবিত্র জন্মভূমি,\nমানবকন্যা আমি যে ধন্যা প্রাণের পুণ্যে ভরা॥\nকোন্\u200c স্বর্গের তরে ওরা তোমায় তুচ্ছ করে\nরহি\tতোমার বক্ষোপরে।\nআমি যে তোমারি আছি নিতান্ত কাছাকাছি,\nতোমার মোহিনীশক্তি দাও আমারে হৃদয়প্রাণহরা॥";
        this.String_99 = "রাগ: খাম্বাজ\nতাল: দাদরা\nরচনাস্থান: কালিগ্রাম\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nযাবই আমি যাবই ওগো,\tবাণিজ্যেতে যাবই।\nলক্ষ্ণীরে হারাবই যদি, অলক্ষ্ণীরে পাবই।\nসাজিয়ে নিয়ে জাহাজখানি বসিয়ে হাজার দাঁড়ি\nকোন্\u200c পুরীতে যাব দিয়ে কোন্\u200c সাগরে পাড়ি।\nকোন্\u200c তারকা লক্ষ্য করি\tকূল- কিনারা পরিহরি\nকোন্\u200c দিকে যে বাইব তরী\tবিরাট কালো নীরে-\nমরব না আর ব্যর্থ আশায় সোনার বালুর তীরে॥\nনীলের কোলে শ্যামল সে দ্বীপ প্রবাল দিয়ে ঘেরা।\nশৈলচূড়ায় নীড় বেঁধেছে সাগরবিহঙ্গেরা।\nনারিকেলের শাখে শাখে\tঝোড়ো হাওয়া কেবল ডাকে,\nঘন বনের ফাঁকে ফাঁকে\tবইছে নগনদী।\nসাত রাজার ধন মানিক পাব সেথায় নামি যদি॥\nহেরো\tসাগর উঠে তরঙ্গিয়া, বাতাস বহে বেগে।\nসূর্য যেথায় অস্তে নামে ঝিলিক মারে মেঘে।\nদক্ষিণে চাই, উত্তরে চাই- ফেনায় ফেনা, আর কিছু নাই-\nযদি কোথাও কূল নাহি পাই\tতল পাব তো তবু-\nভিটার কোণে হতাশমনে রবই না আর কভু॥\nঅকূল- মাঝে ভাসিয়ে তরী যাচ্ছি অজানায়\nআমি শুধু একলা নেয়ে আমার শূন্য নায়।\nনব নব পবন- ভরে\tযাব দ্বীপে দ্বীপান্তরে,\nনেব তরী পূর্ণ ক'রে\tঅপূর্ব ধন যত।\nভিখারি মন ফিরবে যখন ফিরবে রাজার মতো॥";
        this.String_100 = "রাগ: খাম্বাজ\nতাল: ষষ্ঠী\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nআমরা নূতন যৌবনেরই দূত।\nআমরা চঞ্চল, আমরা অদ্ভুত।\nআমরা বেড়া ভাঙি,\nআমরা\tঅশোকবনের রাঙা নেশায় রাঙি,\nঝঞ্ঝার বন্ধন ছিন্ন করে দিই- আমরা বিদ্যুৎ॥\nআমরা করি ভুল-\nঅগাধ জলে ঝাঁপ দিয়ে যুঝিয়ে পাই কূল।\nযেখানে ডাক পড়ে\tজীবন- মরণ- ঝড়ে\tআমরা প্রস্তুত॥";
        this.String_101 = "রাগ: মেঘ\nতাল: ঝাঁপতাল\nস্বরলিপিকার: সুরেন্দ্রনাথ বন্দ্যোপাধ্যায়\n\n\nতিমিরময় নিবিড় নিশা নাহি রে নাহি দিশা-\nএকেলা ঘনঘোর পথে, পান্থ, কোথা যাও॥\nবিপদ দুখ নাহি জানো, বাধা কিছু না মানো,\nঅন্ধকার হতেছ পার- কাহার সাড়া পাও॥\nদীপ হৃদয়ে জ্বলে, নিবে না সে বায়ুবলে-\nমহানন্দে নিরন্তর একি গান গাও।\nসমুখে অভয় তব, পশ্চাতে অভয়রব-\nঅন্তরে বাহিরে কাহার মুখে চাও॥";
        this.String_102 = "রাগ: পিলু- ভীমপলশ্রী\nতাল: কাহারবা\nরচনাস্থান: শান্তিনিকেতন\nস্বরলিপিকার: সুশীলকুমার ভঞ্জচৌধুরী\n\n\nহায় হায় রে হায় পরবাসী,\nহায় গৃহছাড়া উদাসী।\nঅন্ধ অদৃষ্টের আহ্বানে\nকোথা অজানা অকূলে চলেছিস ভাসি।\nশুনিতে কি পাস দূর আকাশে\tকোন্\u200c বাতাসে\nসর্বনাশার বাঁশি-\nওরে, নির্মম ব্যাধ যে গাঁথে মরণের ফাঁসি।\nরঙিন মেঘের তলে\tগোপন অশ্রুজলে\nবিধাতার দারুণ বিদ্রূপবজ্রে\nসঞ্চিত নীরব অট্টহাসি॥";
        this.String_103 = "রাগ: মিশ্র কেদারা\nতাল: দাদরা\nস্বরলিপিকার: শান্তিদেব ঘোষ, সুশীলকুমার ভঞ্জচৌধুরী\n\n\nসুন্দরের বন্ধন নিষ্ঠুরের হাতে\tঘুচাবে কে।\nনিঃসহায়ের অশ্রুবারি পীড়িতের চক্ষে\tমুছাবে কে,\nআর্তের ক্রন্দনে হেরো ব্যথিত বসুন্ধরা,\nঅন্যায়ের আক্রমণে বিষবাণে জর্জরা-\nপ্রবলের উৎপীড়নে\nকে বাঁচাব দুর্বলেরে।\nঅপমানিতেরে কার দয়া বক্ষে\tলবে ডেকে॥";
        this.String_104 = "রাগ: মিশ্র রামকেলি\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nআকাশে তোর তেমনি আছে ছুটি,\nঅলস যেন না রয় ডানা দুটি॥\nওরে পাখি, ঘন বনের তলে\nবাসা তোরে ভুলিয়ে রাখে ছলে,\nরাত্রি তোরে মিথ্যে করে বলে-\nশিথিল কভু হবে না তার মুঠি॥\nজানিস নে কি কিসের আশা চেয়ে\nঘুমের ঘোরে উঠিস গেয়ে গেয়ে।\nজানিস নে কি ভোরের আঁধার- মাঝে\nআলোর আশা গভীর সুরে বাজে,\nআলোর আশা গোপন রহে না যে-\nরুদ্ধ কুঁড়ির বাঁধন ফেলে টুটি॥";
        this.String_105 = "রাগ: রামকেলী\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nকোথায় ফিরিস পরম শেষের অন্বেষণে।\nঅশেষ হয়ে সেই তো আছে এই ভুবনে॥\nতারি বাণী দু হাত বাড়ায় শিশুর বেশে,\nআধো ভাষায় ডাকে তোমার বুকে এসে,\nতারি ছোঁওয়া লেগেছে ওই কুসুমবনে॥\nকোথায় ফিরিস ঘরের লোকের অন্বেষণে-\nপর হয়ে সে দেয় যে দেখা ক্ষণে ক্ষণে।\nতার বাসা- যে সকল ঘরের বাহির- দ্বারে,\nতার আলো যে সকল পথের ধারে ধারে,\nতাহারি রূপ গোপন রূপে জনে জনে॥";
        this.String_106 = "রাগ: ভৈরবী\nতাল: কাহারবা\nরচনাস্থান: কল্যন\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nচাহিয়া দেখো রসের স্রোতে রঙের খেলাখানি।\nচেয়ো না চেয়ো না তারে নিকটে নিতে টানি॥\nরাখিতে চাহ, বাঁধিতে চাহ যাঁরে,\nআঁধারে তাহা মিলায় মিলায় বারে বারে-\nবাজিল যাহা প্রাণের বীণা- তারে\nসে তো কেবলই গান কেবলই বাণী॥\nপরশ তার নাহি রে মেলে, নাহি রে পরিমাণ-\nদেবসভায় যে সুধা করে পান।\nনদীর স্রোতে, ফুলের বনে বনে,\nমাধুরী- মাখা হাসিতে আঁখিকোণে,\nসে সুধাটুকু পিয়ো আপন- মনে-\nমুক্তরূপে নিয়ো তাহারে জানি॥";
        this.String_107 = "রাগ: ছায়ানট\nতাল: কাহারবা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nরয় যে কাঙাল শূন্য হাতে, দিনের শেষে\nদেয় সে দেখা নিশীথরাতে স্বপনবেশে॥\nআলোয় যারে মলিনমুখে মৌন দেখি\nআঁধার হলে আঁখিতে তার দীপ্তি একি-\nবরণমালা কে যে দোলায় তাহার কেশে॥\nদিনের বীণায় যে ক্ষীণ তারে ছিল হেলা\nঝঙ্কারিয়া ওঠে যে তাই রাতের বেলা।\nতন্দ্রাহারা অন্ধকারের বিপুল গানে\nমন্দ্রি ওঠে সারা আকাশ কী আহ্বানে-\nতারার আলোয় কে চেয়ে রয় নির্নিমেষে॥";
        this.String_108 = "রাগ: সাহানা\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nসে কোন্\u200c পাগল যায় যায় পথে তোর, যায় চলে ওই- একলা রাতে-\nতারে ডাকিস নে ডাকিস নে তোর আঙিনাতে॥\nসুদূর দেশের বাণী ও যে যায় যায় বলে, হায়, কে তা বোঝে-\nকী সুর বাজায় একতারাতে॥\nকাল সকালে রইবে না রইবে না তো,\nবৃথাই কেন আসন পাতো।\nবাঁধন- ছেঁড়ার মহোৎসবে\nগান যে ওরে গাইতে হবে\nনবীন আলোর বন্দনাতে॥";
        this.String_109 = "রাগ: ইমনকল্যাণ\nতাল: কাহারবা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nপরবাসী, চলে এসো ঘরে\nঅনুকূল সমীরণ- ভরে॥\nওই দেখো কতবার হল খেয়া- পারাবার,\nসারিগান উঠিল অম্বরে॥\nআকাশে আকাশে আয়োজন,\nবাতাসে বাতাসে আমন্ত্রণ।\nমন যে দিল না সাড়া, তাই তুমি গৃহছাড়া\nনির্বাসিত বাহিরে অন্তরে॥";
        this.String_110 = "রাগ: ভৈরবী\nতাল: একতাল\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nছিল যে পরানের অন্ধকারে\nএল সে ভুবনের আলোক- পারে॥\nস্বপনবাধা টুটি বাহিরে এল ছুটি,\nঅবাক্\u200c আঁখি দুটি হেরিল তারে॥\nমালাটি গেঁথেছিনু অশ্রুধারে,\nতারে যে বেঁধেছিনু সে মায়াহারে।\nনীরব বেদনায় পূজিনু যারে হায়\nনিখিল তারি গায় বন্দনা রে॥";
        this.String_111 = "রাগ: মিশ্র পূরবী\nতাল: একতাল\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nযে কাঁদনে হিয়া কাঁদিছে সে কাঁদনে সেও কাঁদিল।\nযে বাঁধনে মোরে বাঁধিছে সে বাঁধনে তারে বাঁধিল॥\nপথে পথে তারে খুঁজিনু, মনে মনে তারে পূজিনু,\nসে পূজার মাঝে লুকায়ে আমারেও সে যে সাধিল॥\nএসেছিল মন হরিতে মহাপারাবার পারায়ে।\nফিরিল না আর তরীতে, আপনারে গেল হারায়ে।\nতারি আপনারই মাধুরী আপনারে করে চাতুরী,\nধরিবে কি ধরা দিবে সে কী ভাবিয়া ফাঁদ ফাঁদিল॥";
        this.String_112 = "রাগ: দেশ- মল্লার\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nআমরা লক্ষ্মীছাড়ার দল\tভবের\tপদ্মপত্রে জল\nসদা করছি টলোমল\nমোদের আসা- যাওয়া শূন্য হাওয়া, নাইকো ফলাফল॥\nনাহি জানি করণ- কারণ, নাহি জানি ধরণ- ধারণ॥\nনাহি মানি শাসন- বারণ গো-\nআমরা আপন রোখে মনের ঝোঁকে ছিঁড়েছি শিকল॥\nলক্ষ্মী, তোমার বাহনগুলি ধনে পুত্রে উঠুন ফুলি,\nলুঠুন তোমার চরণধূলি গো-\nআমরা স্কন্ধে লয়ে কাঁথা ঝুলি ফিরব ধরাতল।\nতোমার বন্দরেতে বাঁধা ঘাটে বোঝাই- করা সোনার পাটে\nঅনেক রত্ন অনেক হাটে গো-\nআমরা নোঙর- ছেঁড়া ভাঙা তরী ভেসেছি কেবল॥\nআমরা এবার খুঁজে দেখি অকূলেতে কূল মেলে কি,\nদ্বীপ আছে কি ভবসাগরে।\nযদি সুখ না জোটে দেখব ডুবে কোথায় রসাতল।\nআমরা জুটে সারা বেলা\tকরব হতভাগার মেলা,\nগাব গান খেলব খেলা গো-\nকণ্ঠে যদি গান না আসে করব কোলাহল॥";
        this.String_113 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nওগো, তোমরা সবাই ভালো-\nযার অদৃষ্টে যেমনি জুটেছে, সেই আমাদের ভালো-\nআমাদের এই আঁধার ঘরে সন্ধ্যাপ্রদীপ জ্বালো॥\nকেউ বা অতি জ্বলো- জ্বলো, কেউ বা ম্লান' ছলো- ছলো,\nকেউ বা কিছু দহন করে, কেউ বা স্নিগ্ধ আলো॥\nনূতন প্রেমে নূতন বধূ আগাগোড়া কেবল মধু,\nপুরাতনে অম্ল- মধুর একটুকু ঝাঁঝালো।\nবাক্য যখন বিদায় করে চক্ষু এসে পায়ে ধরে,\nরাগের সঙ্গে অনুরাগে সমান ভাগে ঢালো॥\nআমরা তৃষ্ঞা, তোমরা সুধা- তোমরা তৃপ্তি, আমরা ক্ষুধা-\nতোমার কথা বলতে কবির কথা ফুরালো।\nযে মূর্তি নয়নে জাগে সবই আমার ভালো লাগে-\nকেউ বা দিব্যি গৌরবরন, কেউ বা দিব্যি কালো॥";
        this.String_114 = "রাগ: খাম্বাজ- বাউল\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nভালোমানুষ নই রে মোরা ভালোমানুষ নই-\nগুণের মধ্যে ওই আমাদের, গুণের মধ্যে ওই॥\nদেশে দেশে নিন্দে রটে, পদে পদে বিপদ ঘটে-\nপুঁথির কথা কই নে মোরা, উল্\u200cটো কথা কই॥\nজন্ম মোদের ত্র্যহস্পর্শে, সকল- অনাসৃষ্টি।\nছুটি নিলেন বৃহস্পতি, রইল শনির দৃষ্টি।\nঅযাত্রাতে নৌকো ভাসা, রাখি নে, ভাই, ফলের আশা-\nআমাদের আর নাই যে গতি ভেসেই চলা বই॥";
        this.String_115 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nআমাদের\tভয় কাহারে।\nবুড়ো বুড়ো চোর ডাকাতে\tকী আমাদের করতে পারে।\nআমাদের\tরাস্তা সোজা, নাইকো গলি- নাইকো ঝুলি, নাইকো থলি-\nওরা\tআর যা কাড়ে কাড়ুক, মোদের পাগলামি কেউ কাড়বে না রে॥\nআমরা চাই নে আরাম, চাই নে বিরাম,\nচাই নে যে ফল, চাই নে রে নাম-\nমোরা\tওঠায় পড়ায় সমান নাচি,\nসমান খেলি জিতে হারে॥";
        this.String_116 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nআমাদের\tপাকবে না চুল গো- মোদের পাকবে না চুল।\nআমাদের\tঝরবে না ফুল গো- মোদের ঝরবে না ফুল।\nআমরা\tঠেকব না তো কোনো শেষে, ফুরোয় না পথ কোনো দেশে রে,\nআমাদের\tঘুচবে না ভুল গো- মোদের ঘুচবে না ভুল।\nআমরা\tনয়ন মুদে করব না ধ্যান\tকরব না ধ্যান।\nনিজের\tমনের কোণে খুঁজব না জ্ঞান\tখুঁজব না জ্ঞান।\nআমরা\tভেসে চলি স্রোতে স্রোতে\tসাগর- পানে শিখর হতে রে,\nআমাদের\tমিলবে না কূল গো- মোদের মিলবে না কূল॥";
        this.String_117 = "রাগ: বাউল\nতাল: খেমটা\nস্বরলিপিকার: সুধীরচন্দ্র কর\n\n\nপায়ে পড়ি শোনো ভাই গাইয়ে,\nমোদের\tপাড়ার থোড়া দূর দিয়ে যাইয়ে॥\nহেথা\tসা রে গা মা- গুলি\tসদাই\tকরে চুলোচুলি,\nকড়ি কোমল কোথা গেছে তলাইয়ে॥\nহেথা আছে তাল- কাটা বাজিয়ে-\nবাধাবে সে কাজিয়ে।\nচৌতালে ধামারে\nকে কোথায় ঘা মারে-\nতেরে- কেটে মেরে- কেটে ধাঁ- ধাঁ- ধাঁইয়ে॥";
        this.String_118 = "রাগ: বাউল\nতাল: দাদরা\n\n\nও ভাই কানাই, কারে জানাই দুঃসহ মোর দুঃখ।\nতিনটে- চারটে পাস করেছি, নই নিতান্ত মুক্\u200cখ॥\nতুচ্ছ সা- রে- গা- মা'য়\tআমায়\tগলদ্\u200cঘর্ম ঘামায়।\nবুদ্ধি আমার যেমনি হোক কান দুটো নয় সূক্ষ্ম-\nএই বড়ো মোর দুঃখ কানাই রে,\nএই বড়ো মোর দুঃখ॥\nবান্ধবীকে গান শোনাতে ডাকতে হয় সতীশকে,\nহৃদয়খানা ঘুরে মরে গ্রামোফোনের ডিস্কে।\nকণ্ঠখানার জোর আছে তাই\tলুকিয়ে গাইতে ভরসা না পাই-\nস্বয়ং প্রিয়া বলেন, 'তোমার গলা বড়োই রুক্ষ'\nএই বড়ো মোর দুঃখ কানাই রে,\nএই বড়ো মোর দুঃখ॥";
        this.String_119 = "রাগ: কীর্তন\nতাল: কাহারবা\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nকাঁটাবনবিহারিণী সুর- কানা দেবী\nতাঁরি পদ সেবি, করি তাঁহারই ভজনা\nবদ্\u200cকণ্ঠলোকবাসী আমরা কজনা॥\nআমাদের বৈঠক বৈরাগীপুরে\tরাগ- রাগিণীর বহু দূরে,\nগত জনমের সাধনেই বিদ্যা এনেছি সাথে এই গো\nনিঃসুর- রসাতল- তলায় মজনা॥\nসতেরো পুরুষ গেছে, ভাঙা তম্বুরা\nরয়েছে মর্চে ধরি বেসুর- বিধুরা।\nবেতার সেতার দুটো, তবলাটা ফাটা- ফুটো,\nসুরদলনীর করি এ নিয়ে যজনা-\nআমরা কল্পনা॥";
        this.String_120 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\n\n\nআমরা না- গান- গাওয়ার দল রে, আমরা না- গলা- সাধার।\nমোদের ভৈঁরোরাগে প্রভাতরবি রাগে মুখ- আঁধার॥\nআমাদের এই অমিল- কণ্ঠ- সমবায়ের চোটে\nপাড়ার কুকুর সমস্বরে, ও ভাই, ভয়ে ফুক্\u200cরে ওঠে-\nআমরা কেবল ভয়ে মরি ধূর্জটিদাদার॥\nমেঘমল্লার ধরি যদি ঘটে অনাবৃষ্টি,\nছাতিওয়ালার দোকান জুড়ে লাগে শনির দৃষ্টি।\nআধখানা সুর যেমনি লাগাই বসন্তবাহারে\nমলয়বায়ুর ধাত ফিরে যায়, তৎক্ষণাৎ আহা রে\nসেই হাওয়াতে বিচ্ছেদতাপ পালায় শ্রীরাধায়॥\nঅমাবস্যার রাত্রে যেমনি বেহাগ গাইতে বসা\nকোকিলগুলোর লাগে দশম- দশা।\nশুক্লকোজাগরী নিশায় জয়জয়ন্তী ধরি,\nঅমনি মরি মরি\nরাহু- লাগার বেদন লাগে পূর্ণিমা- চাঁদার॥";
        this.String_121 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nমোদের কিছু নাই রে নাই,\tআমরা ঘরে বাইরে গাই-\nতাইরে নাইরে নাইরে না। না না না।\nযতই দিবস যায় রে যায় গাই রে সুখে হায় রে হায়-\nতাইরে নাইরে নাইরে না। না না না।\nযারা সোনার চোরাবালির 'পরে পাকা ঘরের- ভিত্তি গড়ে\nতাদের সামনে মোরা গান গেয়ে যাই- তাইরে নাইরে নাইরে না।\nনা না না॥\nযখন\tথেকে থেকে গাঁঠের পানে গাঁঠকাটারা দৃষ্টি হানে\nতখন শূন্যঝুলি দেখায়ে গাই- তাইরে নাইরে নাইরে না। না না না॥\nযখন দ্বারে আসে মরণবুড়ি\tমুখে তাহার বাজাই তুড়ি,\nতখন তান দিয়ে গান জুড়ি রে ভাই- তাইরে নাইরে নাইরে না। না না না।\nএ যে বসন্তরাজ এসেছে আজ, বাইরে তাহার উজ্জ্বল সাজ,\nওরে, অন্তরে তার বৈরাগী গায়- তাইরে নাইরে নাইরে না। না না না।\nসে যে উৎসবদিন চুকিয়ে দিয়ে, ঝরিয়ে দিয়ে, শুকিয়ে দিয়ে,\nদুই\tরিক্ত হাতে তাল দিয়ে গায়- তাইরে নাইরে নাইরে না।\nনা না না॥";
        this.String_122 = "রাগ: ঝিঁঝিট\nতাল: দাদরা\n\n\nএবার\tযমের দুয়োর খোলা পেয়ে ছুটেছে সব ছেলেমেয়ে।\nহরিবোল হরি বোল হরিবোল॥\nরাজ্য জুড়ে মস্ত খেলা, মরণ- বাঁচন- অবহেলা-\nও ভাই,\tসবাই মিলে প্রাণটা দিলে সুখ আছে কি মরার চেয়ে।\nহরিবোল হরি বোল হরিবোল॥\nবেজেছে ঢোল, বেজেছে ঢাক, ঘরে ঘরে পড়েছে ডাক,\nএখন\tকাজকর্ম চুলোতে যাক- কেজো লোক সব আয় রে ধেয়ে।\nহরিবোল হরি বোল হরিবোল॥\nরাজা প্রজা হবে জড়ো\tথাকবে না আর ছোটো বড়ো-\nএকই\tস্রোতের মুখে ভাসবে সুখে বৈতরণীর নদী বেয়ে।\nহরিবোল হরি বোল হরিবোল॥";
        this.String_123 = "রাগ: ভীমপলশ্রী\nতাল: দাদরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nহায় হায় হায় দিন চলি যায়।\nচা- স্পৃহ চঞ্চল চাতকদল চল' চল' চল' হে॥\nটগ'বগ'- উচ্ছল কাথলিতল- জল কল'কল'হে।\nএল\tচীনগগন হতে পূর্বপবনস্রোতে শ্যামলরসধরপুঞ্জ॥\nশ্রাবণবাসরে রস ঝর'ঝর' ঝরে, ভুঞ্জ হে ভুঞ্জ দলবল হে।\nএস'\tপুঁথিপরিচারক তদ্ধিতকারক তারক তুমি কাণ্ডারী।\nএস'\tগণিতধুরন্ধর কাব্যপুরন্দর ভূবিবরণভাণ্ডারী।\nএস'\tবিশ্বভারনত শুষ্করুটিনপথ- মরু- পরিচারণক্লান্ত।\nএস'\tহিসাবপত্তরত্রস্ত তহবিল- মিল- ভুল- গ্রস্ত লোচনপ্রান্ত- ছল'ছল' হে।\nএস'\tগীতিবীথিচর তম্বুরকরধর তানতালতলমগ্ন।\nএস'\tচিত্রী চট'পট' ফেলি তুলিকপট রেখাবর্ণবিলগ্ন।\nএস'\tকন্\u200cস্\u200cটিট্যুশন- নিয়মবিভূষণ তর্কে অপরিশ্রান্ত।\nএস'\tকমিটিপলাতক বিধানঘাতক এস' দিগভ্রান্ত টল'মল' হে॥";
        this.String_124 = "রাগ: বিভাস- বাউল\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nওগো ভাগ্যদেবী পিতামহী, মিটল আমার আশ-\nএখন তবে আজ্ঞা করো, বিদায় হবে দাস।\nজীবনের এই বাসরবাতি পোহায় বুঝি, নেবে বাতি-\nবধূর দেখা নাইকো, শুধু প্রচুর পরিহাস।\nএখন থেমে গেল বাঁশি, শুকিয়ে এল পুষ্পরাশি,\nউঠল তোমার অট্টহাসি কাঁপায়ে আকাশ।\nছিলেন যাঁরা আমায় ঘিরে গেছেন যে যার ঘরে ফিরে,\nআছ বৃদ্ধা ঠাকুরানী মুখে টানি বাস॥";
        this.String_125 = "রাগ: বেহাগ- বাউল\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nওর ভাব দেখে যে পায় হাসি,\tহায় হায় রে।\nমরণ- আয়োজনের মাঝে বসে আছেন কিসের কাজে\nকোন্\u200c প্রবীণ প্রাচীন প্রবাসী।\tহায় হায় রে।\nএবার দেশে যাবার দিনে\tআপনাকে ও নিক- না চিনে,\nসবাই মিলে সাজাও ওকে নবীন রূপের সন্ন্যাসী।\tহায় হায় রে।\nএবার ওকে মজিয়ে দে রে\tহিসাব- ভুলের বিষম ফেরে।\nকেড়ে নে ওর থলি- থালি,\tআয় রে নিয়ে ফুলের ডালি,\nগোপন প্রাণের পাগ্\u200cলাকে ওর বাইরে দে আজ প্রকাশি।\tহায় হায় রে॥";
        this.String_126 = "রাগ: কালাংড়া\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nআমরা খুঁজি খেলার সাথি-\nভোর না হতে জাগাই তাদের ঘুমায় যারা সারা রাতি॥\nআমরা ডাকি পাখির গলায়,\tআমরা নাচি বকুলতলায়,\nমন ভোলাবার মন্ত্র জানি,\tহাওয়াতে ফাঁদ আমরা পাতি।\nমরণকে তো মানি নে রে,\nকালের ফাঁসি ফাঁসিয়ে দিয়ে লুঠ- করা ধন নিই যে কেড়ে।\nআমরা তোমার মনোচোরা, ছাড়ব না গো তোমায় মোরা-\nচলেছ কোন্\u200c আঁধারপানে\tসেথাও জ্বলে মোদের বাতি॥";
        this.String_127 = "রাগ: খাম্বাজ- বাউল\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nমোদের\tযেমন খেলা তেমনি যে কাজ\tজানিস নে কি ভাই।\nতাই\tকাজকে কভু আমরা না ডরাই॥\nখেলা মোদের লড়াই করা,\tখেলা মোদের বাঁচা মরা,\nখেলা ছাড়া কিছুই কোথাও নাই॥\nখেলতে খেলতে ফুটেছে ফুল,\tখেলতে খেলতে ফল যে ফলে,\nখেলারই ঢেউ জলে স্থলে।\nভয়ের ভীষণ রক্তরাগে\tখেলার আগুন যখন লাগে\nভাঙাচোরা জ্ব'লে যে হয় ছাই॥";
        this.String_128 = "রাগ: পিলু- বাউল\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nসব কাজে হাত লাগাই মোরা সব কাজেই।\nবাধা বাঁধন নেই গো নেই॥\nদেখি খুঁজি বুঝি,\tকেবল ভাঙি গড়ি যুঝি,\nমোরা\tসব দেশেতেই বেড়াই ঘুরে সব সাজেই॥\nপারি নাইবা পারি, নাহয় জিতি কিম্বা হারি-\nযদি অমনিতে হাল ছাড়ি মরি সেই লাজেই।\nআপন হাতের জোরে আমরা তুলি সৃজন ক'রে,\nআমরা প্রাণ দিয়ে ঘর বাঁধি, থাকি তার মাঝেই॥";
        this.String_129 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nকঠিন লোহা কঠিন ঘুমে ছিল অচেতন, ও তার ঘুম ভাঙাইনু রে।\nলক্ষ যুগের অন্ধকারে ছিল সঙ্গোপন, ওগো, তায় জাগাইনু রে॥\nপোষ মেনেছে হাতের তলে যা বলাই সে তেমনি বলে-\nদীর্ঘ দিনের মৌন তাহার আজ ভাগাইনু রে॥\nঅচল ছিল, সচল হয়ে\tছুটেছে ওই জগৎ- জয়ে-\nনির্ভয়ে আজ দুই হাতে তার রাশ বাগাইনু রে॥";
        this.String_130 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nআমরা চাষ করি আনন্দে।\nমাঠে মাঠে বেলা কাটে সকাল হতে সন্ধে॥\nরৌদ্র ওঠে, বৃষ্টি পড়ে, বাঁশের বনে পাতা নড়ে,\nবাতাস ওঠে ভরে ভরে চষা মাটির গন্ধে॥\nসবুজ প্রাণের গানের লেখা রেখায় রেখায় দেয় রে দেখা,\nমাতে রে কোন্\u200c তরুণ কবি নৃত্যদোদুল ছন্দে।\nধানের শিষে পুলক ছোটে- সকল ধরা হেসে ওঠে\nঅঘ্রানেরই সোনার রোদে, পূর্ণিমারই চন্দ্রে॥";
        this.String_131 = "রাগ: কানাড়া- কীর্তন\nতাল: একতাল\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nতোমরা হাসিয়া বহিয়া চলিয়া যাও কুলুকুলুকল নদীর স্রোতের মতো।\nআমরা তীরেতে দাঁড়ায়ে চাহিয়া থাকি, মরমে গুমরি মরিছে কামনা কত।\nআপনা- আপনি কানাকানি কর সুখে, কৌতুকছটা উছলিছে চোখে মুখে,\nকমলচরণ পড়িছে ধরণী- মাঝে, কনকপুর রিনিকি ঝিনিকি বাজে॥\n\nঅঙ্গে অঙ্গ বাঁধিছ রঙ্গপাশে, বাহুতে বাহুতে জড়িত ললিত লতা।\nইঙ্গিতরসে ধ্বনিয়া উঠিছে হাসি, নয়নে নয়নে বহিছে গোপন কথা।\nআঁখি নত করি একেলা গাঁথিছ ফুল, মুকুর লইয়া যতনে বাঁধিছ চুল।\nগোপন হৃদয়ে আপনি করিছ খেলা-\nকী কথা ভাবিছ, কেমনে কাটিছে বেলা॥\n\nআমরা বৃহৎ অবোধ ঝড়ের মতো আপন আবেগে ছুটিয়া চলিয়া আসি,\nবিপুল আঁধারে অসীম আকাশ ছেয়ে টুটিবারে চাহি আপন হৃদয়রাশি।\nতোমরা বিজুলি হাসিতে হাসিতে চাও, আঁধার ছেদিয়া মরম বিঁধিয়া দাও-\nগগনের গায়ে আগুনের রেখা আঁকি চকিত চরণে চলে যাও দিয়ে ফাঁকি॥\n\nঅযতনে বিধি গড়েছে মোদের দেহ, নয়ন অধর দেয় নি ভাষায় ভরে-\nমোহনমধুর মন্ত্র জানি নে মোরা, আপনা প্রকাশ করিব কেমন ক'রে।\nতোমরা কোথায় আমরা কোথায় আছি,\nকোনো সুলগনে হব না কি কাছাকাছি-\nতোমরা হাসিয়া বহিয়া চলিয়া যাবে, আমরা দাঁড়ায়ে রহিব এমনি ভাবে॥";
        this.String_132 = "রাগ: মিস খাম্বাজ\nতাল: কাহারবা\n\n\nওগো পুরবাসী,\nআমি দ্বারে দাঁড়ায়ে আছি উপবাসী॥\nহেরিতেছি সুখমেলা,\tঘরে ঘরে কত খেলা,\nশুনিতেছি সারা বেলা সুমধুর বাঁশি॥\nচাহি না অনেক ধন,\tরব না অধিক ক্ষণ,\nযেথা হতে আসিয়াছি সেথা যাব ভাসি-\nতোমরা আনন্দে রবে\tনব নব উৎসবে,\nকিছু ম্লান নাহি হবে গৃহভরা হাসি॥";
        this.String_133 = "রাগ: খট\nতাল: একতাল\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nআমার যাবার সময় হল, আমায় কেন রাখিস ধরে।\nচোখের জলের বাঁধন দিয়ে বাঁধিস নে আর মায়াডোরে॥\nফুরিয়েছে জীবনের ছুটি, ফিরিয়ে নে তোর নয়ন দুটি-\nনাম ধরে আর ডাকিস নে ভাই, যেতে হবে ত্বরা করে॥";
        this.String_134 = "রাগ: যোগিয়া- বাউল\nতাল: আড়াঠেকা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nওরে, যেতে হবে, আর দেরি নাই।\nপিছিয়ে পড়ে রবি কত, সঙ্গীরা যে গেল সবাই॥\nআয় রে ভবের খেলা সেরে, আঁধার করে এসেছে রে,\nপিছন ফিরে বারে বারে কাহার পানে চাহিস রে ভাই॥\nখেলতে এল ভবের নাটে নতুন লোকে নতুন খেলা।\nহেথা হতে আয় রে সরে, নইলে তোরে মারবে ঢেলা।\nনামিয়ে দে রে প্রাণের বোঝা, আরেক দেশে চল্\u200c রে সোজা-\nসেথা নতুন করে বাঁধবি বাসা,\nনতুন খেলা খেলবি সে ঠাঁই॥";
        this.String_135 = "রাগ: রামপ্রসাদী\nতাল: একতাল\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nআমিই শুধু রইনু বাকি।\nযা ছিল তা গেল চলে, রইল যা তা কেবল ফাঁকি॥\nআমার ব'লে ছিল যারা আর তো তারা দেয় না সাড়া-\nকোথায় তারা, কোথায় তারা, কেঁদে কেঁদে কারে ডাকি॥\nবল্\u200c দেখি মা শুধাই তোরে- আমার কিছু রাখলি নে রে,\nআমি কেবল আমায় নিয়ে কোন্\u200c প্রাণেতে বেঁচে থাকি॥";
        this.String_136 = "রাগ: কালাংড়া\nতাল: একতাল\nস্বরলিপিকার: সুরেন্দ্রনাথ বন্দ্যোপাধ্যায়\n\n\nসারা বরষ দেখি নে, মা, মা তুই আমার কেমন ধারা?\nনয়নতারা হারিয়ে আমার অন্ধ হল নয়নতারা॥\nএলি কি পাষাণী ওরে।\tদেখব তোরে আঁখি ভরে-\nকিছুতেই থামে না যে মা,\tপোড়া এ নয়নের ধারা॥";
        this.String_137 = "রাগ: ইমনকল্যাণ\nতাল: তেওরা\n\n\nযাহা পাও তাই লও, হাসিমুখে ফিরে যাও।\nকারে চাও, কেন চাও- তোমার আশা কে পূরাতে পারে॥\nসবে চায়, কেবা পায় সংসার চ'লে যায়-\nযে বা হাসে, যে বা কাঁদে, যে বা প'ড়ে থাকে দ্বারে॥";
        this.String_138 = "রাগ: বেহাগ\nতাল: অজ্ঞাত\n\n\nমেঘেরা চলে চলে যায়, চাঁদেরে ডাকে 'আয়, আয়'।\nঘুমঘোরে বলে চাঁদ 'কোথায় কোথায়'॥\nনা জানি কোথা চলিয়াছে, কী জানি কী যে সেথা আছে,\nআকাশের মাঝে চাঁদ চারি দিকে চায়॥\nসুদূরে, অতি অতিদূরে,\tবুঝি রে কোন্\u200c সুরপুরে\nতারাগুলি ঘিরে ব'সে বাঁশরি বাজায়।\nমেয়েরা তাই হেসে হেসে\tআকাশে চলে ভেসে ভেসে,\nলুকিয়ে চাঁদের হাসি চুরি করে যায়॥";
        this.String_139 = "রাগ: সাহানা\nতাল: কাহারবা\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\n\n(আমি)\tশ্রাবণ- আকাশে ওই দিয়েছি পাতি\nমম\tজল- ছলোছলো আঁখি মেঘে মেঘে॥\n(আমার\tবেদনা ব্যাপিয়া যায় গো বেণুবনমর্মরে মর্মরে॥ )\nবিরহদিগন্ত পারায়ে সারা রাতি\nঅনিমেষে আছে জেগে মেঘে মেঘে॥\n(বিরহের পরপারে খুঁজিছে আকুল আঁখি\nমিলনপ্রতিমাখানি- খুঁজিছে। )\nযে\tগিয়েছে দেখার বাহিরে\nআছে\tতারি উদ্দেশে চাহি রে।\n(সে যে\tচোখে মোর জল রেখে গেছে চোখের সীমানা পারায়ে। )\nস্বপ্নে উড়িছে তারি কেশরাশি\nপুরব- পবন- বেগে মেঘে মেঘে॥\n(কেশের পরশ তার পাই রে\nপুরব- পবন- বেগে মেঘে মেঘে। )\nশ্যামল তমালবনে\nযে পথে সে চলে গিয়েছিল বিদায়গোধূলিখনে\nবেদনা জড়ায়ে আছে তারি ঘাসে-\n(তার\tনা- বলা কথার বেদনা বাজে গো-\nচলার পথে পথে বাজে গো। )\nকাঁপে নিশ্বাসে-\nসেই\tবারে বারে ফিরে ফিরে চাওয়া\nছায়ায় রয়েছে লেগে মেঘে মেঘে॥";
        this.String_140 = "রাগ: ইমন- পরজ\nতাল: তেওরা\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\n\nসন্ন্যাসী যে জাগিল ওই, জাগিল ওই, জাগিল!\nহাস্য- ভরা দখিন- বায়ে অঙ্গ হতে দিল উড়ায়ে\nশ্মশানচিতাভস্মরাশি- ভাগিল কোথা ভাগিল।\nমানসলোকে শুভ্র আলো চূর্ণ হয়ে রঙ জাগালো,\nমদির রাগ লাগিল তারে- হৃদয়ে তার লাগিল॥\nআয় রে তোরা, আয় রে তোরা, আয় রে-\nরঙের ধারা ওই- যে বহে যায় রে॥\nরঙের ঝড় উচ্ছ্বসিল গগনে,\nরঙের ঢেউ রসের স্রোতে মাতিয়া ওঠে সঘনে-\nডাকিল বান আজি সে কোন্\u200c কোটালে।\nনাকাড়া বাজে কানাড়া বাজে বাঁশিতে-\nকান্নাধারা মিলিয়া গেছে হাসিতে-\nপ্রাণের মাঝে ফোয়ারা তার ছোটালে।\nএসেছে হাওয়া বাণীতে দোল- দোলানো, এসেছে পথ- ভোলানো-\nএসেছে ডাক ঘরের দ্বার- খোলানো॥\nআয় রে তোরা, আয় রে তোরা, আয় রে-\nরঙের ধারা ওই- যে বহে যায় রে॥\nউদয়রবি যে রাঙা রঙ রাঙায়ে পূর্বাচলের দিয়েছে ঘুম ভাঙায়ে\nঅস্তরবি সে রাঙা রসে রসিল-\nচিরপ্রাণের বিজয়বাণী ঘোষিল।\nঅরুণবীণা যে সুর দিল রণিয়া সন্ধ্যাকাশে সে সুর উঠে ঘনিয়া\nনীরব নিশীথিনীর বুকে নিখিল ধ্বনি ধ্বনিয়া।\nআয় রে তোরা, আয় রে তোরা, আয় রে-\nবাঁধন- হারা রঙের ধারা ওই- যে বহে যায় রে॥";
        this.map_var = new HashMap<>();
