        this.String_10 = "রাগ: ইমন- ভূপালী\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\nআমরা\tসবাই রাজা আমাদের এই রাজার রাজত্বে-\nনইলে মোদের রাজার সনে মিলব কী স্বত্বে? ।\nআমরা\tযা খুশি তাই করি, তবু তাঁর খুশিতেই চরি,\nআমরা\tনই বাঁধা নই দাসের রাজার ত্রাসের দাসত্বে-\nনইলে মোদের রাজার সনে মিলব কী স্বত্বে? ।\nরাজা\tসবারে দেন মান,\tসে মান\tআপনি ফিরে পান,\nমোদের\tখাটো ক'রে রাখে নি কেউ কোনো অসত্যে-\nনইলে মোদের রাজার সনে মিলব কী স্বত্বে?\nআমরা\tচলব আপন মতে,\tশেষে\tমিলব তাঁরি পথে,\nমোরা\tমরব না কেউ বিফলতার বিষম আবর্তে-\nনইলে মোদের রাজার সনে মিলব কী স্বত্বে?";
        this.String_11 = "রাগ: ইমনকল্যাণ\nতাল: দাদরা\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\nসঙ্কোচের বিহ্বলতা নিজেরে অপমান।\nসঙ্কটের কল্পনাতে হোয়ো না ম্রিয়মাণ।\nমুক্ত করো ভয়,\tআপনা- মাঝে শক্তি ধরো, নিজেরে করো জয়।\nদুর্বলেরে রক্ষা করো, দুর্জনেরে হানো,\nনিজেরে দীন নিঃসহায় যেন কভু না জানো।\nমুক্ত করো ভয়,\tনিজের 'পরে করিতে ভর না রেখো সংশয়।\nধর্ম যবে শঙ্খরবে করিবে আহ্বান\nনীরব হয়ে নম্র হয়ে পণ করিয়ো প্রাণ।\nমুক্ত করো ভয়,\tদুরূহ কাজে নিজেরি দিয়ো কঠিন পরিচয়॥";
        this.String_12 = "রাগ: ভৈরবী\nতাল: কাহারবা\nরচনাস্থান: মিউনিক\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\nনাই নাই ভয়, হবে হবে জয়, খুলে যাবে এই দ্বার-\nজানি জানি তোর বন্ধনডোর ছিঁড়ে যাবে বারে বার॥\nখনে খনে তুই হারায়ে আপনা সুপ্তিনিশীথ করিস যাপনা-\nবারে বারে তোরে ফিরে পেতে হবে বিশ্বের অধিকার॥\nস্থলে জলে তোর আছে আহ্বান, আহ্বান লোকালয়ে-\nচিরদিন তুই গাহিবি যে গান সুখে দুখে লাজে ভয়ে।\nফুলপল্লব নদীনির্ঝর সুরে সুরে তোর মিলাইবে স্বর-\nছন্দে যে তোর স্পন্দিত হবে আলোক অন্ধকার॥";
        this.String_13 = "রাগ: ভৈরবী\nতাল: একতাল\nরচনাস্থান: গিরিডি\nস্বরলিপিকার: সুরেন্দ্রনাথ বন্দ্যোপাধ্যায়\n\nআমাদের যাত্রা হল শুরু এখন, ওগো কর্ণধার।\nতোমারে\tকরি নমস্কার।\nএখন\tবাতাস ছুটুক, তুফান উঠুক, ফিরব না গো আর-\nতোমারে\tকরি নমস্কার॥\nআমরা দিয়ে তোমার জয়ধ্বনি বিপদ বাধা নাহি গণি\nওগো কর্ণধার।\nএখন\tমাভৈঃ বলি ভাসাই তরী, দাও গো করি পার-\nতোমারে\tকরি নমস্কার॥\nএখন\tরইল যাত্রা আপন ঘরে চাব না পথ তাদের তরে\nওগো কর্ণধার।\nযখন\tতোমার সময় এল কাছে তখন কে বা কার-\nতোমারে\tকরি নমস্কার।\nমোদেরকেবা আপন, কে বা অপর, কোথায় বাহির, কোথা বা ঘর\nওগো কর্ণধার।\nচেয়ে\tতোমার মুখে মনের সুখে নেব সকল ভার-\nতোমারে\tকরি নমস্কার॥\nআমরা নিয়েছি দাঁড়, তুলেছি পাল, তুমি এখন ধরো গো হাল\nওগো কর্ণধার।\nমোদের মরণ বাঁচন ঢেউয়ের নাচন, ভাবনা কী বা তার-\nতোমারে\tকরি নমস্কার।\nআমরা সহায় খুঁজে পরের দ্বারে ফিরব না আর বারে বারে\nওগো কর্ণধার।\nকেবল তুমিই আছ আমরা আছি\tএই জেনেছি সার-\nতোমারে\tকরি নমস্কার॥";
        this.String_14 = "রাগ: ইমন\nতাল: কাহারবা\nরচনাস্থান: কলকাতা\nস্বরলিপিকার: ব্রজেন্দ্রলাল চৌধুরী, দিনেন্দ্রনাথ ঠাকুর, এ. এ. বাকে, ভীমরাও শাস্ত্রী\n\nজনগণমন- অধিনায়ক জয় হে ভারতভাগ্যবিধাতা!\nপঞ্জাব সিন্ধু গুজরাট মরাঠা দ্রাবিড় উৎকল বঙ্গ\nবিন্ধ্য হিমাচল যমুনা গঙ্গা উচ্ছলজলধিতরঙ্গ\nতব শুভ নামে জাগে,\tতব শুভ আশিস মাগে,\nগাহে তব জয়গাথা।\nজনগণমঙ্গলদায়ক জয় হে ভারতভাগ্যবিধাতা!\nজয় হে, জয় হে, জয় হে, জয় জয় জয়, জয় হে॥\n\nঅহরহ তব আহ্বান প্রচারিত, শুনি তব উদার বাণী\nহিন্দু বৌদ্ধ শিখ জৈন পারসিক মুসলমান খৃস্টানী\nপূরব পশ্চিম আসে তব সিংহাসন- পাশে\nপ্রেমহার হয় গাঁথা।\nজনগণ- ঐক্য- বিধায়ক জয় হে ভারতভাগ্যবিধাতা!\nজয় হে, জয় হে, জয় হে, জয় জয় জয়, জয় হে॥\n\nপতন- অভ্যুদয়- বন্ধুর পন্থা, যুগ- যুগ ধাবিত যাত্রী।\nহে চিরসারথি, তব রথচক্রে মুখরিত পথ দিনরাত্রি।\nদারুণ বিপ্লব- মাঝে তব শঙ্খধ্বনি বাজে\nসঙ্কটদুঃখত্রাতা।\nজনগণপথপরিচায়ক জয় হে ভারতভাগ্যবিধাতা!\nজয় হে, জয় হে, জয় হে, জয় জয় জয় জয় হে॥\n\nঘোরতিমিরঘন নিবিড় নিশীথে পীড়িত মূর্ছিত দেশে\nজাগ্রত ছিল তব অবিচল মঙ্গল নতনয়নে অনিমেষে।\nদুঃস্বপ্নে আতঙ্কে রক্ষা করিলে অঙ্কে\nস্নেহময়ী তুমি মাতা।\nজনগণদুঃখত্রায়ক জয় হে ভারতভাগ্যবিধাতা!\nজয় হে, জয় হে, জয় হে, জয় জয় জয় জয় হে॥\n\nরাত্রি প্রভাতিল, উদিল রবিচ্ছবি পূর্ব- উদয়গিরিভালে-\nগাহে বিহঙ্গম, পুণ্য সমীরণ নবজীবনরস ঢালে।\nতব করুণারুণরাগে নিদ্রিত ভারত জাগে\nতব চরণে নত মাথা।\nজয় জয় জয় হে, জয় রাজেশ্বর ভারতভাগ্যবিধাতা!\nজয় হে, জয় হে, জয় হে, জয় জয় জয় জয় হে॥";
        this.String_15 = "রাগ: শঙ্করা\nতাল: দাদরা\nরচনাস্থান: বোলপুর\nস্বরলিপিকার: ভীমরাও শাস্ত্রী\n\n\nহে মোর চিত্ত, পুণ্য তীর্থে জাগো রে ধীরে\nএই ভারতের মহামানবের সাগরতীরে।\nহেথায় দাঁড়ায়ে দু বাহু বাড়ায়ে নমি নরদেবতারে-\nউদার ছন্দে, পরমানন্দে বন্দন করি তাঁরে।\nধ্যানগম্ভীর এই- যে ভূধর, নদী- জপমালা- ধৃত প্রান্তর,\nহেথায় নিত্য হেরো পবিত্র ধরিত্রীরে-\nএই ভারতের মহামানবের সাগরতীরে॥\n\nকেহ নাহি জানে কার আহ্বানে কত মানুষের ধারা\nদুর্বার স্রোতে এল কোথা হতে, সমুদ্রে হল হারা।\nহেথায় আর্য, হেথা অনার্য, হেথায় দ্রাবিড় চীন-\nশক- হুন- দল পাঠান- মোগল এক দেহে হল লীন।\nপশ্চিমে আজি খুলিয়াছে দ্বার, সেথা হতে সবে আনে উপহার,\nদিবে আর নিবে, মিলাবে মিলিবে, যাবে না ফিরে-\nএই ভারতের মহামানবের সাগরতীরে॥\n\nএসো হে আর্য, এসো অনার্য, হিন্দু- মুসলমান।\nএসো এসো আজ তুমি ইংরাজ, এসো এসো খৃস্টান।\nএসো ব্রাহ্মণ, শুচি করি মন ধরো হাত সবাকার।\nএসো হে পতিত, হোক অপনীত সব অপমানভার।\nমার অভিষেকে এসো এসো ত্বরা, মঙ্গলঘট হয় নি যে ভরা\nসবার- পরশে- পবিত্র- করা তীর্থনীরে-\nআজি ভারতের মহামানবের সাগরতীরে॥";
        this.String_16 = "রাগ: মিশ্র কেদারা\nতাল: একতাল\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nদেশ দেশ নন্দিত করি মন্দ্রিত তব ভেরী\nআসিল যত বীরবৃন্দ আসন তব ঘেরি।\nদিন আগত ওই, ভারত তবু কই?\nসে কি রহিল লুপ্ত আজি সব- জন পশ্চাতে?\nলউক বিশ্বকর্মভার মিলি সবার সাথে।\nপ্রেরণ কর' ভৈরব তব দুর্জয় আহ্বান হে, জাগ্রত ভগবান হে॥\nবিঘ্নবিপদ দুঃখদহন তুচ্ছ করিল যারা\nমৃত্যুগহন পার হইল, টুটিল মোহকারা।\nদিন আগত ওই, ভারত তবু কই?\nনিশ্চল নিবীর্যবাহু কর্মকীর্তিহীনে\nব্যর্থশক্তি নিরানন্দ জীবনধনদীনে\nপ্রাণ দাও, প্রাণ দাও, দাও দাও প্রাণ হে, জাগ্রত ভগবান হে॥\nনূতনযুগসূর্য উঠিল, ছুটিল তিমিররাত্রি,\nতব মন্দির- অঙ্গন ভরি মিলিল সকল যাত্রী।\nদিন আগত ওই, ভারত তবু কই?\nগতগৌরব, হৃত- আসন, নতমস্তক লাজে-\nগ্লানি তার মোচন কর' নরসমাজমাঝে।\nস্থান দাও, স্থান দাও, দাও দাও স্থান হে, জাগ্রত ভগবান হে॥\nজনগণপথ তব জয়রথচক্রমুখর আজি,\nস্পন্দিত করি দিগ্\u200cদিগন্ত উঠিল শঙ্খ বাজি।\nদিন আগত ওই, ভারত তবু কই?\nদৈন্যজীর্ণ কক্ষ তার, মলিন শীর্ণ আশা,\nত্রাসরুদ্ধ চিত্ত তার, নাহি নাহি ভাষা।\nকোটিমৌনকণ্ঠপূর্ণ বাণী কর' দান হে, জাগ্রত ভগবান হে॥\nযারা তব শক্তি লভিল নিজ অন্তরমাঝে\nবর্জিল ভয়, অর্জিল জয়, সার্থক হল কাজে।\nদিন আগত ওই, ভারত তবু কই?\nআত্ম- অবিশ্বাস তার নাশ' কঠিন ঘাতে,\nপুঞ্জিত অবসাদভার হান' অশনিপাতে।\nছায়াভয়চকিতমূঢ় করহ পরিত্রাণ হে, জাগ্রত ভগবান হে॥";
        this.String_17 = "রাগ: ইমনকল্যাণ\nতাল: তেওরা\nস্বরলিপিকার: দিনেন্দ্রনাথ ঠাকুর\n\n\nমাতৃমন্দির- পুণ্য- অঙ্গন কর' মহোজ্জ্বল আজ হে\nবর\tপুত্রসঙ্ঘ বিরাজ' হে।\nশুভ\tশঙ্খ বাজহ বাজ' হে।\nঘন\tতিমিররাত্রির চির প্রতীক্ষা\nপূর্ণ কর', লহ' জ্যোতিদীক্ষা,\nযাত্রীদল সব সাজ' হে।\nশুভ\tশঙ্খ বাজহ বাজ' হে।\nবল\tজয় নরোত্তম, পুরুষসত্তম,\nজয় তপস্বিরাজ হে।\nজয় হে, জয় হে, জয় হে, জয় হে।\nএস'\tবজ্রমহাসনে মাতৃ- আশীর্ভাষণে,\nসকল সাধক এস' হে, ধন্য কর' এ দেশ হে।\nসকল যোগী, সকল ত্যাগী, এস' দুঃসহদুঃখভাগী-\nএস' দুর্জয়শক্তিসম্পদ মুক্তবন্ধ সমাজ হে।\nএস' জ্ঞানী, এস' কর্মী নাশ' ভারতলাজ হে।\nএস' মঙ্গল, এস' গৌরব,\nএস' অক্ষয়পুণ্যসৌরভ,\nএস' তেজঃসূর্য উজ্জ্বল কীর্তি- অম্বর মাঝ হে\nবীরধর্মে পুণ্যকর্মে বিশ্বহৃদয় রাজ' হে।\nশুভ\tশঙ্খ বাজহ বাজ' হে।\nজয়\tজয় নরোত্তম, পুরুষসত্তম,\nজয় তপস্বিরাজ হে।\nজয় হে, জয় হে, জয় হে, জয় হে॥";
        this.String_18 = "রাগ: বেহাগ\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nআগে চল্\u200c, আগে চল্\u200c ভাই!\nপড়ে থাকা পিছে, মরে থাকা মিছে,\nবেঁচে মরে কিবা ফল ভাই!\nআগে চল্\u200c, আগে চল্\u200c ভাই॥\nপ্রতি নিমেষেই যেতেছে সময়,\nদিন ক্ষণ চেয়ে থাকা কিছু নয়-\n'সময় সময়' ক'রে পাঁজি পুঁথি ধ'রে\nসময় কোথা পাবি বল্\u200c ভাই!\nআগে চল্\u200c, আগে চল্\u200c ভাই॥\nপিছায়ে যে আছে তারে ডেকে নাও\nনিয়ে যাও সাথে করে-\nকেহ নাহি আসে, একা চলে যাও\nমহত্ত্বের পথ ধরে।\nপিছু হতে ডাকে মায়ার কাঁদন,\nছিঁড়ে চলে যাও মোহের বাঁধন-\nসাধিতে হইবে প্রাণের সাধন,\nমিছে নয়নের জল ভাই!\nআগে চল্\u200c, আগে চল্\u200c ভাই॥\nচিরদিন আছি ভিখারির বেশে\nজগতের পথপাশে-\nযারা চলে যায় কৃপাচোখে চায়,\nপদধুলা উড়ে আসে।\nধুলিশয্যা ছেড়ে ওঠো ওঠো সবে\nমনিবের সাথে যোগ দিতে হবে-\nতা যদি না পারো চেয়ে দেখো তবে\nওই আছে রসাতল ভাই!\nআগে চল্\u200c, আগে চল্\u200c ভাই॥";
        this.String_19 = "রাগ: হাম্বীর\nতাল: তালফেরতা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nআনন্দধ্বনি জাগাও গগনে।\nকে আছ জাগিয়া পুরবে চাহিয়া,\nবলো 'উঠ উঠ' সঘনে গভীরনিদ্রাগমনে॥\nহেরো তিমিররজনী যায় ওই, হাসে উষা নব জ্যোতির্ময়ী-\nনব আনন্দে, নব জীবনে,\nফুল্ল কুসুমে, মধুর পবনে, বিহগকলকূজনে॥\nহেরো আশার আলোকে জাগে শুকতারা উদয়- অচল- পথে,\nকিরণকিরীটে তরুণ তপন উঠিছে অরুণরথে-\nচলো যাই কাজে মানবসমাজে, চলো বাহিরিয়া জগতের মাঝে-\nথেকো না অলস শয়নে, থেকো না মগন স্বপনে॥\nযায় লাজ ত্রাস, আলস বিলাস কুহক মোহ যায়।\nওই দূর হয় শোক সংশয় দুঃখ স্বপনপ্রায়।\nফেলো জীর্ণ চীর, পরো নব সাজ, আরম্ভ করো জীবনের কাজ-\nসরল সবল আনন্দমনে, অমল অটল জীবনে॥";
        this.String_20 = "রাগ: কীর্তন\nতাল: একতাল\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nবাংলার মাটি, বাংলার জল, বাংলার বায়ু, বাংলার ফল-\nপুণ্য হউক, পুণ্য হউক, পুণ্য হউক হে ভগবান॥\nবাংলার ঘর, বাংলার হাট, বাংলার বন, বাংলার মাঠ-\nপূর্ণ হউক, পূর্ণ হউক, পূর্ণ হউক হে ভগবান॥\nবাঙালির পণ, বাঙালির আশা, বাঙালির কাজ, বাঙালির ভাষা-\nসত্য হউক, সত্য হউক, সত্য হউক হে ভগবান॥\nবাঙালির প্রাণ, বাঙালির মন, বাঙালির ঘরে যত ভাই বোন-\nএক হউক, এক হউক, এক হউক হে ভগবান॥";
        this.String_21 = "রাগ: বিভাস- বাউল\nতাল: একতাল\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nআজি\tবাংলাদেশের হৃদয় হতে কখন আপনি\nতুমি এই\tঅপরূপ রূপে বাহির হলে জননী!\nওগো\tমা, তোমায় দেখে দেখে আঁখি না ফিরে!\nতোমার\tদুয়ার আজি খুলে গেছে সোনার মন্দিরে॥\n\nডান হাতে তোর খড়্গ জ্বলে, বাঁ হাত করে শঙ্কাহরণ,\nদুই নয়নে স্নেহের হাসি, ললাটনেত্র আগুনবরণ।\nওগো\tমা, তোমার কী মুরতি আজি দেখি রে!\nতোমার\tদুয়ার আজি খুলে গেছে সোনার মন্দিরে॥\n\nতোমার\tমুক্তকেশের পুঞ্জ মেঘে লুকায় অশনি,\nতোমার\tআঁচল ঝলে আকাশতলে রৌদ্রবসনী!\nওগো\tমা, তোমায় দেখে দেখে আঁখি না ফিরে!\nতোমার\tদুয়ার আজি খুলে গেছে সোনার মন্দিরে॥\n\nযখন\tঅনাদরে চাই নি মুখে ভেবেছিলেম দুঃখিনী মা\nআছে\tভাঙা ঘরে একলা পড়ে, দুখের বুঝি নাইকো সীমা।\nকোথা সে তোর দরিদ্র বেশ, কোথা সে তোর মলিন হাসি-\nআকাশে আজ ছড়িয়ে গেল ওই চরণের দীপ্তিরাশি!\nওগো\tমা, তোমার কী মুরতি আজি দেখি রে!\nতোমার\tদুয়ার আজি খুলে গেছে সোনার মন্দিরে॥\n\nআজি\tদুখের রাতে সুখের স্রোতে ভাসাও ধরণী-\nতোমার\tঅভয় বাজে হৃদয়মাঝে হৃদয়হরণী!\nওগো\tমা, তোমায় দেখে দেখে আঁখি না ফিরে!";
        this.String_22 = "আমায় বোলো না\nরাগ: কাফি\nতাল: একতাল\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nআমায় বোলো না গাহিতে বোলো না।\nএ কি শুধু হাসি খেলা, প্রমোদের মেলা, শুধু মিছেকথা ছলনা? ।\nএ যে নয়নের জল, হতাশের শ্বাস, কলঙ্কের কথা, দরিদ্রের আশ,\nএ যে বুক- ফাটা দুখে গুমরিছে বুকে গভীর মরমবেদনা।\nএ কি শুধু হাসি খেলা, প্রমোদের মেলা, শুধু মিছেকথা ছলনা? ।\nএসেছি কি হেথা যশের কাঙালি কথা গেঁথে গেঁথে নিতে করতালি-\nমিছে কথা কয়ে, মিছে যশ লয়ে, মিছে কাজে নিশিযাপনা!\nকে জাগিবে আজ, কে করিবে কাজ, কে ঘুচাতে চাহে জননীর লাজ-\nকাতরে কাঁদিবে, মায়ের পায়ে দিবে সকল প্রাণের কামনা?\nএ কি শুধু হাসি খেলা, প্রমোদের মেলা, শুধু মিছেকথা ছলনা? ।";
        this.String_23 = "রাগ: ভৈরবী\nতাল: কাহারবা\nস্বরলিপিকার: সরলা দেবী\n\n\nঅয়ি ভুবনমনোমোহিনী, মা,\nঅয়ি নির্মলসূর্যকরোজ্জ্বল ধরণী জনকজননিজননী॥\nনীলসিন্ধুজলধৌতচরণতল, অনিলবিকম্পিত- শ্যামল- অঞ্চল,\nঅম্বরচুম্বিতভালহিমাচল, শুভ্রতুষারকিরীটিনী॥\nপ্রথম প্রভাত উদয় তব গগনে, প্রথম সামরব তব তপোবনে,\nপ্রথম প্রচারিত তব বনভবনে জ্ঞানধর্ম কত কাব্যকাহিনী।\nচিরকল্যাণময়ী তুমি ধন্য, দেশবিদেশে বিতরিছ অন্ন-\nজাহ্নবীযমুনা বিগলিত করুণা পুণ্যপীষুষস্তন্যবাহিনী॥";
        this.String_24 = "রাগ: ভৈরবী\nতাল: একতাল\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nসার্থক জনম আমার জন্মেছি এই দেশে।\nসার্থক জনম, মা গো, তোমায় ভালোবেসে॥\nজানি নে তোর ধনরতন আছে কি না রানীর মতন,\nশুধু জানি আমার অঙ্গ জুড়ায় তোমার ছায়ায় এসে॥\nকোন্\u200c বনেতে জানি নে ফুল গন্ধে এমন করে আকুল,\nকোন্\u200c গগনে ওঠে রে চাঁদ এমন হাসি হেসে।\nআঁখি মেলে তোমার আলো প্রথম আমার চোখ জুড়ালো,\nওই আলোতেই নয়ন রেখে মুদব নয়ন শেষে॥";
        this.String_25 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nযে তোমায় ছাড়ে ছাড়ুক,\tআমি তোমায় ছাড়ব না মা!\nআমি\tতোমার চরণ-\nমা গো, আমি তোমার চরণ করব শরণ, আর কারো ধার ধারব না মা॥\nকে বলে তোর দরিদ্র ঘর,\tহৃদয় তোর রতনরাশি-\nআমি\tজানি গো তার মূল্য জানি, পরের আদর কাড়ব না মা॥\nমানের আশে দেশবিদেশে যে মরে সে মরুক ঘুরে-\nতোমার ছেঁড়া কাঁথা আছে পাতা, ভুলতে সে যে পারব না মা!\nধনে মানে লোকের টানে\tভুলিয়ে নিতে চায় যে আমায়-\nও মা,\tভয় যে জাগে শিয়র- বাগে, কারো কাছেই হারব না মা॥";
        this.String_26 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nযে তোরে পাগল বলে তারে তুই বলিস নে কিছু॥\nআজকে তোরে কেমন ভেবে অঙ্গে যে তোর ধুলো দেবে\nকাল সে প্রাতে মালা হাতে আসবে রে তোর পিছু- পিছু॥\nআজকে আপন মানের ভরে থাক্\u200c সে বসে গদির 'পরে-\nকালকে প্রেমে আসবে নেমে, করবে সে তার মাথা নিচু॥";
        this.String_27 = "রাগ: বাউল\nতাল: একতাল\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nওরে, তোরা নেই বা কথা বললি,\nদাঁড়িয়ে হাটের মধ্যিখানে নেই জাগালি পল্লী॥\nমরিস মিথ্যে ব'কে ঝ'কে, দেখে কেবল হাসে লোকে,\nনাহয় নিয়ে আপন মনের আগুন মনে মনেই জ্বললি॥\nঅন্তরে তোর আছে কী যে নেই রটালি নিজে নিজে,\nনাহয় বাদ্যগুলো বন্ধ রেখে চুপেচাপেই চললি॥\nকাজ থাকে তো কর্\u200c গে না কাজ, লাজ থাকে তো ঘুচা গে লাজ,\nওরে, কে যে তোরে কী বলেছে নেই বা তাতে টললি॥";
        this.String_28 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nযদি তোর ভাবনা থাকে ফিরে যা- না। তবে তুই ফিরে যা- না।\nযদি তোর ভয় থাকে তো করি মানা॥\nযদি তোর ঘুম জড়িয়ে থাকে গায়ে ভুলবি যে পথ পায়ে পায়ে,\nযদি তোর হাত কাঁপে তো নিবিয়ে আলো সবারে করবি কানা॥\nযদি তোর ছাড়তে কিছু না চাহে মন করিস ভারী বোঝা আপন-\nতবে তুই সইতে কভু পারবি নে রে এ বিষম পথের টানা॥\nযদি তোর আপনা হতে অকারণে সুখ সদা না জাগে মনে\nতবে তুই তর্ক ক'রে সকল কথা করিবি নানাখানা॥";
        this.String_29 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nমা কি তুই\tপরের দ্বারে পাঠাবি তোর ঘরের ছেলে?\nতারা যে\tকরে হেলা, মারে ঢেলা, ভিক্ষাঝুলি দেখতে পেলে॥\nকরেছি\tমাথা নিচু,\tচলেছি যাহার পিছু\nযদি বা\tদেয় সে কিছু অবহেলে-\nতবু কি\tএমনি করে ফিরব ওরে আপন মায়ের প্রসাদ ফেলে? ।\nকিছু মোর নেই ক্ষমতা\tসে যে ঘোর মিথ্যে কথা,\nএখনো\tহয় নি মরণ শক্তিশেলে-\nআমাদের\tআপন শক্তি আপন ভক্তি চরণে তোর দেব মেলে॥\nনেব গো\tমেগে- পেতে যা আছে\tতোর ঘরেতে,\nদে গো তোর আঁচল পেতে চিরকেলে-\nআমাদের\tসেইখেনে মান, সেইখেনে প্রাণ, সেইখেনে দিই হৃদয় ঢেলে॥";
        this.String_30 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nছি ছি, চোখের জলে ভেজাস নে আর মাটি।\nএবার কঠিন হয়ে থাক্\u200c- না ওরে, বক্ষোদুয়ার আঁটি-\nজোরে\tবক্ষোদুয়ার আঁটি॥\nপরানটাকে গলিয়ে ফেলে দিস নে, রে ভাই, পথে ঢেলে\nমিথ্যে অকাজে-\nওরে\tনিয়ে তারে চলবি পারে কতই বাধা কাটি,\nপথের\tকতই বাধা কাটি॥\nদেখলে ও তোর জলের ধারা ঘরে পরে হাসবে যারা\nতারা চার দিকে-\nতাদের\tদ্বারেই গিয়ে কান্না জুড়িস, যায় না কি বুক ফাটি,\nলাজে\tযায় না কি বুক ফাটি? ।\nদিনের বেলা জগৎ- মাঝে সবাই যখন চলছে কাজে আপন গরবে-\nতোরা পথের ধারে ব্যথা নিয়ে করিস ঘাঁটাঘাঁটি-\nকেবল করিস ঘাঁটাঘাঁটি॥";
        this.String_31 = "রাগ: বাউল\nতাল: অজ্ঞাত\n\n\nঘরে মুখ মলিন দেখে গলিস নে- ওরে ভাই,\nবাইরে মুখ আঁধার দেখে টলিস নে- ওরে ভাই॥\nযা তোমার আছে মনে সাধো তাই পরানপণে,\nশুধু তাই দশজনারে বলিস নে- ওরে ভাই॥\nএকই পথ আছে ওরে, চলো সেই রাস্তা ধরে,\nযে আসে তারই পিছে চলিস নে- ওরে ভাই!\nথাক্\u200c- না আপন কাজে, যা খুশি বলুক- না যে,\nতা নিয়ে গায়ের জ্বালায় জ্বলিস নে- ওরে ভাই॥";
        this.String_32 = "রাগ: ইমন\nতাল: কাহারবা\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\n\nএখন আর দেরি নয়, ধর্\u200c গো তোরা হাতে হাতে ধর্\u200c গো।\nআজ\tআপন পথে ফিরতে হবে\tসামনে মিলন- স্বর্গ॥\nওরে\tওই উঠেছে শঙ্খ বেজে, খুলল দুয়ার মন্দিরে যে-\nলগ্ন বয়ে যায় পাছে, ভাই, কোথায় পূজার অর্ঘ্য? ।\nএখন\tযার যা- কিছু আছে ঘরে সাজা পূজার থালার 'পরে,\nআত্মদানের উৎসধারায় মঙ্গলঘট ভর্\u200c গো।\nআজ\tনিতেও হবে, আজ দিতেও হবে, দেরি কেন করিস তবে-\nবাঁচতে যদি হয় বেঁচে নে, মর্\u200cতে হয় তো মর্\u200c গো॥";
        this.String_33 = "রাগ: বেহাগ\nতাল: একতাল\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nবুক বেঁধে তুই দাঁড়া দেখি, বারে বারে হেলিস নে ভাই!\nশুধু তুই\tভেবে ভেবেই হাতের লক্ষ্ণী ঠেলিস নে ভাই॥\nএকটা কিছু করে নে ঠিক,\tভেসে ফেরা মরার অধিক-\nবারেক এ দিক বারেক ও দিক, এ খেলা আর খেলিস নে ভাই॥\nমেলে কিনা মেলে রতন করতে তবু হবে যতন-\nনা যদি হয় মনের মতন চোখের জলটা ফেলিস নে ভাই!\nভাসাতে হয় ভাসা ভেলা, করিস নে আর হেলাফেলা-\nপেরিয়ে যখন যাবে বেলা তখন আঁখি মেলিস নে ভাই॥";
        this.String_34 = "রাগ: ভৈরবী- কালাংড়া\nতাল: একতাল\nস্বরলিপিকার: ইন্দিরা দেবী\n\nআমরা\tপথে পথে যাব সারে সারে,\nতোমার\tনাম গেয়ে ফিরিব দ্বারে দ্বারে॥\nবলব \"জননীকে কে দিবি দান,\nকে দিবি ধন তোরা কে দিবি প্রাণ'-\n\"তোদের\tমা ডেকেছে' কব বারে বারে॥\nতোমার নামে প্রাণের সকল সুর\nআপনি উঠবে বেজে সুধামধুর\nমোদের\tহৃদয়যন্ত্রেরই তারে তারে।\nবেলা গেলে শেষে তোমারই পায়ে\nএনে দেব সবার পূজা কুড়ায়ে\nতোমার\tসন্তানেরই দান ভারে ভারে॥";
        this.String_35 = "রাগ: দেশ\nতাল: চৌতাল\nস্বরলিপিকার: কাঙ্গালীচরণ সেন\n\n\nএ ভারতে রাখো নিত্য, প্রভু, তব শুভ আশীর্বাদ-\nতোমার অভয়, তোমার অজিত অমৃত বাণী,\nতোমার স্থির অমর আশা॥\nঅনির্বাণ ধর্ম আলো সবার ঊর্ধ্বে জ্বালো জ্বালো,\nসঙ্কটে দুর্দিনে হে,\nরাখো তারে অরণ্যে তোমারই পথে॥\nবক্ষে বাঁধি দাও তার বর্ম তব নির্বিদার,\nনিঃশঙ্কে যেন সঞ্চরে নির্ভীক।\nপাপের নিরখি জয় নিষ্ঠা তবুও রয়-\nথাকে তব চরণে অটল বিশ্বাসে॥";
        this.String_36 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: সুরেন্দ্রনাথ বন্দ্যোপাধ্যায়\n\nরইল বলে রাখলে কারে, হুকুম তোমার ফলবে কবে?\nতোমার\tটানাটানি টিঁকবে না ভাই, রবার যেটা সেটাই রবে॥\nযা খুশি তাই করতে পারো\tগায়ের জোরে রাখ মারো;\nযাঁর গায়ে সব ব্যথা বাজে তিনি যা সন সেটাই সবে।\nঅনেক তোমার টাকাকড়ি,\tঅনেক দড়া অনেক দড়ি,\nঅনেক অশ্ব অনেক করী- অনেক তোমার আছে ভবে।\nভাবছ হবে তুমিই যা চাও,\tজগৎটাকে তুমিই নাচাও,\nদেখবে হঠাৎ নয়ন খুলে হয় না যেটা সেটাও হবে।";
        this.String_37 = "রাগ: হাম্বীর\nতাল: কাহারবা\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nজননীর দ্বারে আজি ওই শুন গো শঙ্খ বাজে।\nথেকো না থেকো না, ওরে ভাই, মগন মিথ্যা কাজে॥\nঅর্ঘ্য ভরিয়া আনি ধরো গো পূজার থালি,\nরতনপ্রদীপখানি যতনে আনো গো জ্বালি,\nভরি লয়ে দুই পাণি বহি আনো ফুলডালি,\nমার আহ্বানবাণী রটাও ভুবনমাঝে॥\nআজি প্রসন্ন পবনে নবীন জীবন ছুটিছে।\nআজি প্রফুল্ল কুসুমে নব সুগন্ধ উঠিছে।\nআজি উজ্জ্বল ভালে তোলো উন্নত মাথা,\nনবসঙ্গীততালে গাও গম্ভীর গাথা,\nপরো মাল্য কপালে নবপল্লব- গাঁথা,\nশুভ সুন্দর কালে সাজো সাজো নব সাজে॥";
        this.String_38 = "রাগ: ভূপালী\nতাল: ত্রিতাল\nস্বরলিপিকার: সরলা দেবী\n\nআজি এ ভারত লজ্জিত হে,\nহীনতাপঙ্কে মজ্জিত হে॥\nনাহি পৌরুষ, নাহি বিচারণা,\tকঠিন তপস্যা, সত্যসাধনা-\nঅন্তরে বাহিরে ধর্মে কর্মে সকলই ব্রহ্মবিবর্জিত হে॥\nধিক্\u200cকৃত লাঞ্ছিত পৃথ্বী 'পরে,\tধূলিবিলুন্ঠিত সুপ্তিভরে-\nরুদ্র, তোমার নিদারুণ বজ্রে করো তারে সহসা তর্জিত হে॥\nপর্বতে প্রান্তরে নগরে গ্রামে\tজাগ্রত ভারত ব্রহ্মের নামে,\nপুণ্যে বীর্যে অভয়ে অমৃতে হইবে পলকে সজ্জিত হে॥";
        this.String_39 = "রাগ: খাম্বাজ\nতাল: কাহারবা\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\nচলো যাই, চলো, যাই চলো, যাই-\nচলো পদে পদে সত্যের ছন্দে\nচলো দুর্জয় প্রাণের আনন্দে!\nচলো মুক্তিপথে,\nচলো বিঘ্নবিপদজয়ী মনোরথে\nকরো ছিন্ন, করো ছিন্ন, করো ছিন্ন-\nস্বপ্নকুহক করো ছিন্ন।\nথেকো না জড়িত অবরুদ্ধ\nজড়তার জর্জর বন্ধে।\nবলো জয় বলো, জয় বলো, জয়-\nমুক্তির জয় বলো ভাই॥\nচলো দুর্গমদূরপথযাত্রী চলো দিবারাত্রি,\nকরো জয়যাত্রা,\nচলো বহি নির্ভয় বীর্যের বার্তা,\nবলো জয় বলো, জয় বলো, জয়-\nসত্যের জয় বলো ভাই॥\nদুর করো সংশয়শঙ্কার ভার,\nযাও চলি তিমিরদিগন্তের পার।\nকেন যায় দিন হায় দুশ্চিন্তার দ্বন্দ্বে-\nচলো\tদুর্জয় প্রাণের আনন্দে।\nচলো\tজ্যোতির্লোকে জাগ্রত চোখে-\n\nবলো\tজয় বলো, জয় বলো, জয়-\nবলো\tনির্মল জ্যোতির জয় বলো ভাই॥\nহও মৃত্যুতোরণ উত্তীর্ণ,\nযাক, যাক ভেঙে যাক যাহা জীর্ণ।\nচলো\tঅভয় অমৃতময় লোকে, অজর অশোকে,\nবলো\tজয় বলো, জয় বলো, জয়-\nঅমৃতের জয় বলো ভাই॥";
        this.String_40 = "রাগ: মিশ্র মল্লার\nতাল: কাহারবা\nস্বরলিপিকার: শান্তিদেব ঘোষ\n\n\nশুভ\tকর্মপথে ধর' নির্ভয় গান।\nসব\tদুর্বল সংশয় হোক অবসান।\nচির-\tশক্তির নির্ঝর নিত্য ঝরে\nলহ'\tসে অভিষেক ললাট'পরে।\nতব\tজাগ্রত নির্মল নূতন প্রাণ\nত্যাগব্রতে নিক দীক্ষা,\nবিঘ্ন হতে নিক শিক্ষা-\nনিষ্ঠুর সঙ্কট দিক সম্মান।\nদুঃখই হোক তব বিত্ত মহান।\nচল' যাত্রী, চল' দিনরাত্রি-\nকর' অমৃতলোকপথ অনুসন্ধান।\nজড়তাতামস হও উত্তীর্ণ,\nক্লান্তিজাল কর' দীর্ণ বিদীর্ণ-\nদিন- অন্তে অপরাজিত চিত্তে\nমৃত্যুতরণ তীর্থে কর' স্নান॥";
        this.String_41 = "রাগ: ভৈরবী\nতাল: দাদরা\nস্বরলিপিকার: শৈলজারঞ্জন মজুমদার\n\nওরে, নূতন যুগের ভোরে\nদিস নে সময় কাটিয়ে বৃথা সময় বিচার করে॥\nকী রবে আর কী রবে না, কী হবে আর কী হবে না\nওরে হিসাবি,\nএ সংশয়ের মাঝে কি তোর ভাবনা মিশাবি? ।\nযেমন করে ঝর্না নামে দুর্গম পর্বতে\nনির্ভাবনায় ঝাঁপ দিয়ে পড় অজাজিতের পথে।\nজাগবে ততই শক্তি যতই হানবে তোরে মানা,\nঅজানাকে বশ ক'রে তুই করবি আপন জানা।\nচলায় চলায় বাজবে জয়ের ভেরী-\nপায়ের বেগেই পথ কেটে যায়, করিস নে আর দেরি॥";
        this.String_42 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: অনাদিকুমার দস্তিদার\n\n\nব্যর্থ প্রাণের আবর্জনা পুড়িয়ে ফেলে আগুন জ্বালো।\nএকলা রাতের অন্ধকারে আমি চাই পথের আলো॥\nদুন্দুভিতে হল রে কার আঘাত শুরু,\nবুকের মধ্যে উঠল বেজে গুরুগুরু-\nপালায় ছুটে সুপ্তিরাতের স্বপ্নে- দেখা মন্দ ভালো॥\nনিরুদ্দেশের পথিক আমায় ডাক দিলে কি-\nদেখতে তোমায় না যদি পাই নাই- বা দেখি।\nভিতর থেকে ঘুচিয়ে দিলে চাওয়া পাওয়া,\nভাব্\u200cনাতে মোর লাগিয়ে দিলে ঝড়ের হাওয়া\nবজ্রশিখায় এক পলকে মিলিয়ে দিলে সাদা কালো॥";
        this.String_43 = "রাগ: বেহাগ- খাম্বাজ\nতাল: দাদরা\nরচনাস্থান: গিরিডি থেকে ট্রেনে\nস্বরলিপিকার: ইন্দিরা দেবী\n\n\nওদের বাঁধন যতই শক্ত হবে ততই বাঁধন টুটবে,\nমোদের ততই বাঁধন টুটবে।\nওদের যতই আঁখি রক্ত হবে মোদের আঁখি ফুটবে,\nততই মোদের আঁখি ফুটবে॥\nআজকে যে তোর কাজ করা চাই, স্বপ্ন দেখার সময় তো নাই-\nএখন\tওরা যতই গর্জাবে, ভাই তন্দ্রা ততই ছুটবে,\nমোদের\tতন্দ্রা ততই ছুটবে॥\nওরা\tভাঙতে যতই চাবে জোরে গড়বে ততই দ্বিগুণ করে,\nতোরা\tভরসা না ছাড়িস কভু, জেগে আছেন জগৎ- প্রভু-\nওরা\tধর্ম যতই দলবে ততই ধুলায় ধ্বজা লুটবে,\nওদের\tধুলায় ধ্বজা লুটবে॥";
        this.String_44 = "রাগ: খাম্বাজ\nতাল: দাদরা\nরচনাস্থান: গিরিডি\nস্বরলিপিকার: ইন্দিরা দেবী\n\nবিধির বাঁধন কাটবে তুমি এমন শক্তিমান-\nতুমি কি এমন শক্তিমান!\nআমাদের ভাঙাগড়া তোমার হাতে এমন অভিমান-\nতোমাদের এমনি অভিমান॥\nচিরদিন টানবে পিছে, চিরদিন রাখবে নীচে-\nএত বল নাই রে তোমার, সবে না সেই টান॥\nশাসনে যতই ঘেরো আছে বল দুর্বলেরও,\nহও- না যতই বড়ো আছেন ভগবান।\nআমাদের শক্তি মেরে তোরাও বাঁচবি নে রে,\nবোঝা তোর ভারী হলেই ডুববে তরীখান।";
        this.String_45 = "রাগ: বাউল\nতাল: দাদরা\nস্বরলিপিকার: সরলা দেবী\n\nখ্যাপা তুই আছিস আপন খেয়াল ধরে।\nযে আসে\tতোরই পাশে, সবাই হাসে দেখে তোরে॥\nজগতে\tযে যার আছে আপন কাজে দিবানিশি।\nতারা\tপায় না বুঝে তুই কী খুঁজে ক্ষেপে- বেড়াস জনম ভ'রে॥\nতোর\tনাই অবসর, নাইকো দোসর ভবের মাঝে।\nতোরে\tচিনতে যে চাই, সময় না পাই নানান কাজে।\nওরে, তুই কী শুনাতে এত প্রাতে মরিস ডেকে?\nএ যে\tবিষম জ্বালা ঝালাপালা, দিবি সবায় পাগল করে।\nওরে, তুই কী এনেছিস, কী টেনেছিস ভাবের জালে?\nতার কি\tমূল্য আছে কারো কাছে কোনো কালে? ।\nআমরা\tলাভের কাজে হাটের মাঝে ডাকি তোরে!\nতুই কি\tসৃষ্টিছাড়া, নাইকো সাড়া, রয়েছিস কোন্\u200c নেশায় ঘোরে?\nএ জগৎ\tআপন মতে আপন পথে চলে যাবে-\nবসে তুই\tআর- এক কোণে নিজের মনে নিজের ভাবে॥\nওরে ভাই, ভাবের সাথে ভবের মিলন হবে কবে-\nমিছে তুই তারি লাগি আছিস জাগি না জানি কোন্\u200c আশার জোরে॥";
        this.String_46 = "রাগ: অজ্ঞাত\nতাল: অজ্ঞাত\nরচনাস্থান: শান্তিনিকেতন\n\nসাধন কি মোর আসন নেবে হট্টগোলের কাঁধে?\nখাঁটি জিনিস হয় রে মাটি নেশার পরমাদে॥\nকথায় তো শোধ হয় না দেনা, গায়ের জোরে জোড় মেলে না-\nগোলেমালে ফল কি ফলে জোড়াতাড়ার ছাঁদে? ।\nকে বলো তো বিধাতারে তাড়া দিয়ে ভোলায়?\nসৃষ্টিকরের ধন কি মেলে জাদুকরের ঝোলায়?\nমস্ত- বড়োর লোভে শেষে\tমস্ত ফাঁকি জোটে এসে,\nব্যস্ত- আশা জড়িয়ে পড়ে সর্বনাশার ফাঁদে॥";
